// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'isaiah',
  name: 'Isaías',
  englishName: 'Isaiah',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.', pt: 'A visão de Isaías, filho de Amoz, que ele teve a respeito de Judá e Jerusalém, nos dias de Uzias, Jotão, Acaz, e Ezequias, reis de Judá.' },
      { v: 2, en: 'Hear, heavens, and listen, earth; for Yahweh has spoken: “I have nourished and brought up children, and they have rebelled against me.', pt: 'Ouvi, ó céus, e dá ouvidos, ó terra, porque falou o Senhor: Criei filhos, e os engrandeci, mas eles se rebelaram contra mim.' },
      { v: 3, en: 'The ox knows his owner, and the donkey his master’s crib; but Israel doesn’t know, my people don’t consider.”', pt: 'O boi conhece o seu possuidor, e o jumento a manjedoura do seu dono; mas Israel não tem conhecimento, o meu povo não entende.' },
      { v: 4, en: 'Ah sinful nation, a people loaded with iniquity, offspring of evildoers, children who deal corruptly! They have forsaken Yahweh. They have despised the Holy One of Israel. They are estranged and backward.', pt: 'Ah, nação pecadora, povo carregado de iniqüidade, descendência de malfeitores, filhos que praticam a corrupção! Deixaram o Senhor, desprezaram o Santo de Israel, voltaram para trás.' },
      { v: 5, en: 'Why should you be beaten more, that you revolt more and more? The whole head is sick, and the whole heart faint.', pt: 'Por que seríeis ainda castigados, que persistis na rebeldia? Toda a cabeça está enferma e todo o coração fraco.' },
      { v: 6, en: 'From the sole of the foot even to the head there is no soundness in it: wounds, welts, and open sores. They haven’t been closed, neither bandaged, neither soothed with oil.', pt: 'Desde a planta do pé até a cabeça não há nele coisa sã; há só feridas, contusões e chagas vivas; não foram espremidas, nem atadas, nem amolecidas com óleo.' },
      { v: 7, en: 'Your country is desolate. Your cities are burned with fire. Strangers devour your land in your presence, and it is desolate, as overthrown by strangers.', pt: 'O vosso país está assolado; as vossas cidades abrasadas pelo fogo; a vossa terra os estranhos a devoram em vossa presença, e está devastada, como por uma pilhagem de estrangeiros.' },
      { v: 8, en: 'The daughter of Zion is left like a shelter in a vineyard, like a hut in a field of melons, like a besieged city.', pt: 'E a filha de Sião é deixada como a cabana na vinha, como a choupana no pepinal, como cidade sitiada.' },
      { v: 9, en: 'Unless Yahweh of Armies had left to us a very small remnant, we would have been as Sodom; we would have been like Gomorrah.', pt: 'Se o Senhor dos exércitos não nos deixara alguns sobreviventes, já como Sodoma seríamos, e semelhantes a Gomorra.' },
      { v: 10, en: 'Hear Yahweh’s word, you rulers of Sodom! Listen to the law of our God, you people of Gomorrah!', pt: 'Ouvi a palavra do Senhor, governadores de Sodoma; dai ouvidos à lei do nosso Deus, ó povo de Gomorra.' },
      { v: 11, en: '“What are the multitude of your sacrifices to me?”, says Yahweh. “I have had enough of the burnt offerings of rams, and the fat of fed animals. I don’t delight in the blood of bulls, or of lambs, or of male goats.', pt: 'De que me serve a mim a multidão de vossos sacrifícios? diz o Senhor. Estou farto dos holocaustos de carneiros, e da gordura de animais cevados; e não me agrado do sangue de novilhos, nem de cordeiros, nem de bodes.' },
      { v: 12, en: 'When you come to appear before me, who has required this at your hand, to trample my courts?', pt: 'Quando vindes para comparecerdes perante mim, quem requereu de vós isto, que viésseis pisar os meus átrios?' },
      { v: 13, en: 'Bring no more vain offerings. Incense is an abomination to me; new moons, Sabbaths, and convocations: I can’t stand evil assemblies.', pt: 'Não continueis a trazer ofertas vãs; o incenso é para mim abominação. As luas novas, os sábados, e a convocação de assembléias ... não posso suportar a iniqüidade e o ajuntamento solene!' },
      { v: 14, en: 'My soul hates your New Moons and your appointed feasts. They are a burden to me. I am weary of bearing them.', pt: 'As vossas luas novas, e as vossas festas fixas, a minha alma as aborrece; já me são pesadas; estou cansado de as sofrer.' },
      { v: 15, en: 'When you spread out your hands, I will hide my eyes from you. Yes, when you make many prayers, I will not hear. Your hands are full of blood.', pt: 'Quando estenderdes as vossas mãos, esconderei de vós os meus olhos; e ainda que multipliqueis as vossas orações, não as ouvirei; porque as vossas mãos estão cheias de sangue.' },
      { v: 16, en: 'Wash yourselves, make yourself clean. Put away the evil of your doings from before my eyes. Cease to do evil.', pt: 'Lavai-vos, purificai-vos; tirai de diante dos meus olhos a maldade dos vossos atos; cessai de fazer o mal;' },
      { v: 17, en: 'Learn to do well. Seek justice. Relieve the oppressed. Judge the fatherless. Plead for the widow.”', pt: 'aprendei a fazer o bem; buscai a justiça, acabai com a opressão, fazei justiça ao órfão, defendei a causa da viúva.' },
      { v: 18, en: '“Come now, and let us reason together,” says Yahweh: “Though your sins be as scarlet, they shall be as white as snow. Though they be red like crimson, they shall be as wool.', pt: 'Vinde, pois, e arrazoemos, diz o Senhor: ainda que os vossos pecados são como a escarlata, eles se tornarão brancos como a neve; ainda que são vermelhos como o carmesim, tornar-se-ão como a lã.' },
      { v: 19, en: 'If you are willing and obedient, you shall eat the good of the land;', pt: 'Se quiserdes, e me ouvirdes, comereis o bem desta terra;' },
      { v: 20, en: 'but if you refuse and rebel, you shall be devoured with the sword; for the mouth of Yahweh has spoken it.”', pt: 'mas se recusardes, e fordes rebeldes, sereis devorados à espada; pois a boca do Senhor o disse.' },
      { v: 21, en: 'How the faithful city has become a prostitute! She was full of justice; righteousness lodged in her, but now murderers.', pt: 'Como se fez prostituta a cidade fiel! ela que estava cheia de retidão! A justiça habitava nela, mas agora homicidas.' },
      { v: 22, en: 'Your silver has become dross, your wine mixed with water.', pt: 'A tua prata tornou-se em escória, o teu vinho se misturou com água.' },
      { v: 23, en: 'Your princes are rebellious, and companions of thieves. Everyone loves bribes, and follows after rewards. They don’t judge the fatherless, neither does the cause of the widow come to them.', pt: 'Os teus príncipes são rebeldes, e companheiros de ladrões; cada um deles ama as peitas, e anda atrás de presentes; não fazem justiça ao órfão, e não chega perante eles a causa da viúva.' },
      { v: 24, en: 'Therefore the Lord, Yahweh of Armies, the Mighty One of Israel, says: “Ah, I will get relief from my adversaries, and avenge myself on my enemies;', pt: 'portanto diz o Senhor Deus dos exércitos, o Poderoso de Israel: Ah! livrar-me-ei dos meus adversários, e vingar-me-ei dos meus inimigos.' },
      { v: 25, en: 'and I will turn my hand on you, thoroughly purge away your dross, and will take away all your tin.', pt: 'Voltarei contra ti a minha mão, e purificarei como com potassa a tua escória; e tirar-te-ei toda impureza;' },
      { v: 26, en: 'I will restore your judges as at the first, and your counselors as at the beginning. Afterward you shall be called ‘The city of righteousness, a faithful town.’', pt: 'e te restituirei os teus juízes, como eram dantes, e os teus conselheiros, como no princípio, então serás chamada cidade de justiça, cidade fiel.' },
      { v: 27, en: 'Zion shall be redeemed with justice, and her converts with righteousness.', pt: 'Sião será resgatada pela justiça, e os seus convertidos, pela retidão.' },
      { v: 28, en: 'But the destruction of transgressors and sinners shall be together, and those who forsake Yahweh shall be consumed.', pt: 'Mas os transgressores e os pecadores serão juntamente destruídos; e os que deixarem o Senhor serão consumidos.' },
      { v: 29, en: 'For they shall be ashamed of the oaks which you have desired, and you shall be confounded for the gardens that you have chosen.', pt: 'Porque vos envergonhareis por causa dos terebintos de que vos agradastes, e sereis confundidos por causa dos jardins que escolhestes.' },
      { v: 30, en: 'For you shall be as an oak whose leaf fades, and as a garden that has no water.', pt: 'Pois sereis como um carvalho cujas folhas são murchas, e como um jardim que não tem água.' },
      { v: 31, en: 'The strong will be like tinder, and his work like a spark. They will both burn together, and no one will quench them.”', pt: 'E o forte se tornará em estopa, e a sua obra em faísca; e ambos arderão juntamente, e não haverá quem os apague.' },
    ],
    2: [
      { v: 1, en: 'This is what Isaiah the son of Amoz saw concerning Judah and Jerusalem.', pt: 'A visão que teve Isaías, filho de Amoz, a respeito de Judá e de Jerusalém.' },
      { v: 2, en: 'It shall happen in the latter days, that the mountain of Yahweh’s house shall be established on the top of the mountains, and shall be raised above the hills; and all nations shall flow to it.', pt: 'Acontecerá nos últimos dias que se firmará o monte da casa do Senhor, será estabelecido como o mais alto dos montes e se elevará por cima dos outeiros; e concorrerão a ele todas as nações.' },
      { v: 3, en: 'Many peoples shall go and say, “Come, let’s go up to the mountain of Yahweh, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths.” For out of Zion the law shall go out, and Yahweh’s word from Jerusalem.', pt: 'Irão muitos povos, e dirão: Vinde, e subamos ao monte do Senhor, à casa do Deus de Jacó, para que nos ensine os seus caminhos, e andemos nas suas veredas; porque de Sião sairá a lei, e de Jerusalém a palavra do Senhor.' },
      { v: 4, en: 'He will judge between the nations, and will decide concerning many peoples; and they shall beat their swords into plowshares, and their spears into pruning hooks. Nation shall not lift up sword against nation, neither shall they learn war any more.', pt: 'E ele julgará entre as nações, e repreenderá a muitos povos; e estes converterão as suas espadas em relhas de arado, e as suas lanças em foices; uma nação não levantará espada contra outra nação, nem aprenderão mais a guerra.' },
      { v: 5, en: 'House of Jacob, come, and let us walk in the light of Yahweh.', pt: 'Vinde, ó casa de Jacó, e andemos na luz do Senhor.' },
      { v: 6, en: 'For you have forsaken your people, the house of Jacob, because they are filled from the east, with those who practice divination like the Philistines, and they clasp hands with the children of foreigners.', pt: 'Mas tu rejeitaste o teu povo, a casa de Jacó; porque estão cheios de adivinhadores do Oriente, e de agoureiros, como os filisteus, e fazem alianças com os filhos dos estrangeiros.' },
      { v: 7, en: 'Their land is full of silver and gold, neither is there any end of their treasures. Their land also is full of horses, neither is there any end of their chariots.', pt: 'A sua terra está cheia de prata e ouro, e são sem limite os seus tesouros; a sua terra está cheia de cavalos, e os seus carros não tem fim.' },
      { v: 8, en: 'Their land also is full of idols. They worship the work of their own hands, that which their own fingers have made.', pt: 'Também a sua terra está cheia de ídolos; inclinam-se perante a obra das suas mãos, diante daquilo que os seus dedos fabricaram.' },
      { v: 9, en: 'Man is brought low, and mankind is humbled; therefore don’t forgive them.', pt: 'Assim, pois, o homem é abatido, e o varão é humilhado; não lhes perdoes!' },
      { v: 10, en: 'Enter into the rock, and hide in the dust, from before the terror of Yahweh, and from the glory of his majesty.', pt: 'Entra nas rochas, e esconde-te no pó, de diante da espantosa presença do Senhor e da glória da sua majestade.' },
      { v: 11, en: 'The lofty looks of man will be brought low, the haughtiness of men will be bowed down, and Yahweh alone will be exalted in that day.', pt: 'Os olhos altivos do homem serão abatidos, e a altivez dos varões será humilhada, e só o Senhor será exaltado naquele dia.' },
      { v: 12, en: 'For there will be a day of Yahweh of Armies for all that is proud and haughty, and for all that is lifted up; and it shall be brought low:', pt: 'Pois o Senhor dos exércitos tem um dia contra todo soberbo e altivo, e contra todo o que se exalta, para que seja abatido;' },
      { v: 13, en: 'For all the cedars of Lebanon, that are high and lifted up, for all the oaks of Bashan,', pt: 'contra todos os cedros do Líbano, altos e sublimes; e contra todos os carvalhos de Basã;' },
      { v: 14, en: 'For all the high mountains, for all the hills that are lifted up,', pt: 'contra todos os montes altos, e contra todos os outeiros elevados;' },
      { v: 15, en: 'For every lofty tower, for every fortified wall,', pt: 'contra toda torre alta, e contra todo muro fortificado;' },
      { v: 16, en: 'For all the ships of Tarshish, and for all pleasant imagery.', pt: 'e contra todos os navios de Társis, e contra toda a nau vistosa.' },
      { v: 17, en: 'The loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; and Yahweh alone shall be exalted in that day.', pt: 'E a altivez do homem será humilhada, e o orgulho dos varões se abaterá, e só o Senhor será exaltado naquele dia.' },
      { v: 18, en: 'The idols shall utterly pass away.', pt: 'E os ídolos desaparecerão completamente.' },
      { v: 19, en: 'Men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of Yahweh, and from the glory of his majesty, when he arises to shake the earth mightily.', pt: 'Então os homens se meterão nas cavernas das rochas, e nas covas da terra, por causa da presença espantosa do Senhor, e da glória da sua majestade, quando ele se levantar para assombrar a terra.' },
      { v: 20, en: 'In that day, men shall cast away their idols of silver, and their idols of gold, which have been made for themselves to worship, to the moles and to the bats;', pt: 'Naquele dia o homem lançará às toupeiras e aos morcegos os seus ídolos de prata, e os seus ídolos de ouro, que fizeram para ante eles se prostrarem,' },
      { v: 21, en: 'To go into the caverns of the rocks, and into the clefts of the ragged rocks, from before the terror of Yahweh, and from the glory of his majesty, when he arises to shake the earth mightily.', pt: 'para se meter nas fendas das rochas, e nas cavernas das penhas, por causa da presença espantosa do Senhor e da glória da sua majestade, quando ele se levantar para assombrar a terra.' },
      { v: 22, en: 'Stop trusting in man, whose breath is in his nostrils; for of what account is he?', pt: 'Deixai-vos pois do homem cujo fôlego está no seu nariz; porque em que se deve ele estimar?' },
    ],
    3: [
      { v: 1, en: 'For, behold, the Lord, Yahweh of Armies, takes away from Jerusalem and from Judah supply and support, the whole supply of bread, and the whole supply of water;', pt: 'Porque eis que o Senhor Deus dos exércitos está tirando de Jerusalém e de Judá o bordão e o cajado, isto é, todo o recurso de pão, e todo o recurso de água;' },
      { v: 2, en: 'the mighty man, the man of war, the judge, the prophet, the diviner, the elder,', pt: 'o valente e o soldado, o juiz e o profeta, o adivinho e o ancião;' },
      { v: 3, en: 'the captain of fifty, the honorable man, the counselor, the skilled craftsman, and the clever enchanter.', pt: 'o capitão de cinqüenta e o respeitável, o conselheiro, o artífice hábil e o encantador perito;' },
      { v: 4, en: 'I will give boys to be their princes, and children shall rule over them.', pt: 'e dar-lhes-ei meninos por príncipes, e crianças governarão sobre eles.' },
      { v: 5, en: 'The people will be oppressed, everyone by another, and everyone by his neighbor. The child will behave himself proudly against the old man, and the wicked against the honorable.', pt: 'O povo será oprimido; um será contra o outro, e cada um contra o seu próximo; o menino se atreverá contra o ancião, e o vil contra o nobre.' },
      { v: 6, en: 'Indeed a man shall take hold of his brother in the house of his father, saying, “You have clothing, you be our ruler, and let this ruin be under your hand.”', pt: 'Quando alguém pegar de seu irmão na casa de seu pai, dizendo: Tu tens roupa, tu serás o nosso príncipe, e tomarás sob a tua mão esta ruína.' },
      { v: 7, en: 'In that day he will cry out, saying, “I will not be a healer; for in my house is neither bread nor clothing. You shall not make me ruler of the people.”', pt: 'Naquele dia levantará este a sua voz, dizendo: Não quero ser médico; pois em minha casa não há pão nem roupa; não me haveis de constituir governador sobre o povo.' },
      { v: 8, en: 'For Jerusalem is ruined, and Judah is fallen; because their tongue and their doings are against Yahweh, to provoke the eyes of his glory.', pt: 'Pois Jerusalém tropeçou, e Judá caiu; porque a sua língua e as suas obras são contra o Senhor, para afrontarem a sua gloriosa presença.' },
      { v: 9, en: 'The look of their faces testify against them. They parade their sin like Sodom. They don’t hide it. Woe to their soul! For they have brought disaster upon themselves.', pt: 'O aspecto do semblante dá testemunho contra eles; e, como Sodoma, publicam os seus pecados sem os disfarçar. Ai da sua alma! porque eles fazem mal a si mesmos.' },
      { v: 10, en: 'Tell the righteous “Good!” For they shall eat the fruit of their deeds.', pt: 'Dizei aos justos que bem lhes irá; porque comerão do fruto das suas obras.' },
      { v: 11, en: 'Woe to the wicked! Disaster is upon them; for the deeds of his hands will be paid back to him.', pt: 'Ai do ímpio! mal lhe irá; pois se lhe fará o que as suas mãos fizeram.' },
      { v: 12, en: 'As for my people, children are their oppressors, and women rule over them. My people, those who lead you cause you to err, and destroy the way of your paths.', pt: 'Quanto ao meu povo, crianças são os seus opressores, e mulheres dominam sobre eles. Ah, povo meu! os que te guiam te enganam, e destroem o caminho das tuas veredas.' },
      { v: 13, en: 'Yahweh stands up to contend, and stands to judge the peoples.', pt: 'O Senhor levanta-se para pleitear, e põe-se de pé para julgar os povos.' },
      { v: 14, en: 'Yahweh will enter into judgment with the elders of his people, and their leaders: “It is you who have eaten up the vineyard. The plunder of the poor is in your houses.', pt: 'O Senhor entra em juízo contra os anciãos do seu povo, e contra os seus príncipes; sois vós que consumistes a vinha; o espólio do pobre está em vossas casas.' },
      { v: 15, en: 'What do you mean that you crush my people, and grind the face of the poor?” says the Lord, Yahweh of Armies.', pt: 'Que quereis vós, que esmagais o meu povo e moeis o rosto do pobre? diz o Senhor Deus dos exércitos.' },
      { v: 16, en: 'Moreover Yahweh said, “Because the daughters of Zion are haughty, and walk with outstretched necks and flirting eyes, walking to trip as they go, jingling ornaments on their feet;', pt: 'Diz ainda mais o Senhor: Porquanto as filhas de Sião são altivas, e andam de pescoço emproado, lançando olhares impudentes; e, ao andarem, vão de passos curtos, fazendo tinir os ornamentos dos seus pés;' },
      { v: 17, en: 'therefore the Lord brings sores on the crown of the head of the women of Zion, and Yahweh will make their scalps bald.”', pt: 'o Senhor fará tinhosa a cabeça das filhas de Sião, e o Senhor porá a descoberto a sua nudez.' },
      { v: 18, en: 'In that day the Lord will take away the beauty of their anklets, the headbands, the crescent necklaces,', pt: 'Naquele dia lhes trará o Senhor o ornamento dos pés, e as coifas, e as luetas;' },
      { v: 19, en: 'the earrings, the bracelets, the veils,', pt: 'os pendentes, e os braceletes, e os véus;' },
      { v: 20, en: 'the headdresses, the ankle chains, the sashes, the perfume bottles, the charms,', pt: 'os diademas, as cadeias dos artelhos, os cintos, as caixinhas de perfumes e os amuletos;' },
      { v: 21, en: 'the signet rings, the nose rings,', pt: 'os anéis, e as jóias pendentes do nariz;' },
      { v: 22, en: 'the fine robes, the capes, the cloaks, the purses,', pt: 'os vestidos de festa, e os mantos, e os xales, e os bolsos;' },
      { v: 23, en: 'the hand mirrors, the fine linen garments, the tiaras, and the shawls.', pt: 'os vestidos diáfanos, e as capinhas de linho, e os turbantes, e os véus.' },
      { v: 24, en: 'It shall happen that instead of sweet spices, there shall be rottenness; instead of a belt, a rope; instead of well set hair, baldness; instead of a robe, a wearing of sackcloth; and branding instead of beauty.', pt: 'E será que em lugar de perfume haverá mau cheiro, e por cinto, uma corda; em lugar de encrespadura de cabelos, calvície; e em lugar de veste luxuosa, cinto de cilício; e queimadura em lugar de formosura.' },
      { v: 25, en: 'Your men shall fall by the sword, and your mighty in the war.', pt: 'Teus varões cairão à espada, e teus valentes na guerra.' },
      { v: 26, en: 'Her gates shall lament and mourn; and she shall be desolate and sit on the ground.', pt: 'E as portas da cidade gemerão e se carpirão e, desolada, ela se sentará no pó.' },
    ],
    4: [
      { v: 1, en: 'Seven women shall take hold of one man in that day, saying, “We will eat our own bread, and wear our own clothing: only let us be called by your name. Take away our reproach.”', pt: 'Sete mulheres naquele dia lançarão mão dum só homem, dizendo: Nós comeremos do nosso pão, e nos vestiremos de nossos vestidos; tão somente queremos ser chamadas pelo teu nome; tira o nosso opróbrio.' },
      { v: 2, en: 'In that day, Yahweh’s branch will be beautiful and glorious, and the fruit of the land will be the beauty and glory of the survivors of Israel.', pt: 'Naquele dia o renovo do Senhor será cheio de beleza e de glória, e o fruto da terra excelente e formoso para os que escaparem de Israel.' },
      { v: 3, en: 'It will happen, that he who is left in Zion, and he who remains in Jerusalem, shall be called holy, even everyone who is written among the living in Jerusalem;', pt: 'E será que aquele que ficar em Sião e permanecer em Jerusalém, será chamado santo, isto é, todo aquele que estiver inscrito entre os vivos em Jerusalém;' },
      { v: 4, en: 'when the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from within it, by the spirit of justice, and by the spirit of burning.', pt: 'Quando o Senhor tiver lavado a imundícia das filhas de Sião, e tiver limpado o sangue de Jerusalém do meio dela com o espírito de justiça, e com o espírito de ardor.' },
      { v: 5, en: 'Yahweh will create over the whole habitation of Mount Zion, and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night; for over all the glory will be a canopy.', pt: 'E criará o Senhor sobre toda a extensão do monte Sião, e sobre as assembléias dela, uma nuvem de dia, e uma fumaça, e um resplendor de fogo flamejante de noite; porque sobre toda a glória se estenderá um dossel.' },
      { v: 6, en: 'There will be a pavilion for a shade in the daytime from the heat, and for a refuge and for a shelter from storm and from rain.', pt: 'Também haverá de dia um pavilhão para sombra contra o calor, e para refúgio e esconderijo contra a tempestade e a chuva.' },
    ],
    5: [
      { v: 1, en: 'Let me sing for my well beloved a song of my beloved about his vineyard. My beloved had a vineyard on a very fruitful hill.', pt: 'Ora, seja-me permitido cantar para o meu bem amado uma canção de amor a respeito da sua vinha. O meu amado possuía uma vinha num outeiro fertilíssimo.' },
      { v: 2, en: 'He dug it up, gathered out its stones, planted it with the choicest vine, built a tower in the middle of it, and also cut out a wine press therein. He looked for it to yield grapes, but it yielded wild grapes.', pt: 'E, revolvendo-a com enxada e limpando-a das pedras, plantou- a de excelentes vides, e edificou no meio dela uma torre, e também construiu nela um lagar; e esperava que desse uvas, mas deu uvas bravas.' },
      { v: 3, en: '“Now, inhabitants of Jerusalem and men of Judah, please judge between me and my vineyard.', pt: 'Agora, pois, ó moradores de Jerusalém, e homens de Judá, julgai, vos peço, entre mim e a minha vinha.' },
      { v: 4, en: 'What could have been done more to my vineyard, that I have not done in it? Why, when I looked for it to yield grapes, did it yield wild grapes?', pt: 'Que mais se podia fazer à minha vinha, que eu lhe não tenha feito? e por que, esperando eu que desse uvas, veio a produzir uvas bravas?' },
      { v: 5, en: 'Now I will tell you what I will do to my vineyard. I will take away its hedge, and it will be eaten up. I will break down its wall, and it will be trampled down.', pt: 'Agora, pois, vos farei saber o que eu hei de fazer à minha vinha: tirarei a sua sebe, e será devorada; derrubarei a sua parede, e sera pisada;' },
      { v: 6, en: 'I will lay it a wasteland. It won’t be pruned nor hoed, but it will grow briers and thorns. I will also command the clouds that they rain no rain on it.”', pt: 'e a tornarei em deserto; não será podada nem cavada, mas crescerão nela sarças e espinheiro; e às nuvens darei ordem que não derramem chuva sobre ela.' },
      { v: 7, en: 'For the vineyard of Yahweh of Armies is the house of Israel, and the men of Judah his pleasant plant: and he looked for justice, but, behold, oppression; for righteousness, but, behold, a cry of distress.', pt: 'Pois a vinha do Senhor dos exércitos é a casa de Israel, e os homens de Judá são a planta das suas delícias; e esperou que exercessem juízo, mas eis aqui derramamento de sangue; justiça, e eis aqui clamor.' },
      { v: 8, en: 'Woe to those who join house to house, who lay field to field, until there is no room, and you are made to dwell alone in the middle of the land!', pt: 'Ai dos que ajuntam casa a casa, dos que acrescentam campo a campo, até que não haja mais lugar, de modo que habitem sós no meio da terra!' },
      { v: 9, en: 'In my ears, Yahweh of Armies says: “Surely many houses will be desolate, even great and beautiful, unoccupied.', pt: 'A meus ouvidos disse o Senhor dos exércitos: Em verdade que muitas casas ficarão desertas, e até casas grandes e lindas sem moradores.' },
      { v: 10, en: 'For ten acres of vineyard shall yield one bath, and a homer of seed shall yield an ephah.”', pt: 'E dez jeiras de vinha darão apenas um bato, e um hômer de semente não dará mais do que uma efa.' },
      { v: 11, en: 'Woe to those who rise up early in the morning, that they may follow strong drink; who stay late into the night, until wine inflames them!', pt: 'Ai dos que se levantam cedo para correrem atrás da bebida forte e continuam até a noite, até que o vinho os esquente!' },
      { v: 12, en: 'The harp, lyre, tambourine, and flute, with wine, are at their feasts; but they don’t respect the work of Yahweh, neither have they considered the operation of his hands.', pt: 'Têm harpas e alaúdes, tamboris e pífanos, e vinho nos seus banquetes; porém não olham para a obra do Senhor, nem consideram as obras das mãos dele.' },
      { v: 13, en: 'Therefore my people go into captivity for lack of knowledge. Their honorable men are famished, and their multitudes are parched with thirst.', pt: 'Portanto o meu povo é levado cativo, por falta de entendimento; e os seus nobres estão morrendo de fome, e a sua multidão está seca de sede.' },
      { v: 14, en: 'Therefore Sheol has enlarged its desire, and opened its mouth without measure; and their glory, their multitude, their pomp, and he who rejoices among them, descend into it.', pt: 'Por isso o Seol aumentou o seu apetite, e abriu a sua boca desmesuradamente; e para lá descem a glória deles, a sua multidão, a sua pompa, e os que entre eles se exultam.' },
      { v: 15, en: 'So man is brought low, mankind is humbled, and the eyes of the arrogant ones are humbled;', pt: 'O homem se abate, e o varão se humilha, e os olhos dos altivos se abaixam.' },
      { v: 16, en: 'but Yahweh of Armies is exalted in justice, and God the Holy One is sanctified in righteousness.', pt: 'Mas o Senhor dos exércitos é exaltado pelo juízo, e Deus, o Santo, é santificado em justiça.' },
      { v: 17, en: 'Then the lambs will graze as in their pasture, and strangers will eat the ruins of the rich.', pt: 'Então os cordeiros pastarão como em seus pastos; e nos campos desertos se apascentarão cevados e cabritos.' },
      { v: 18, en: 'Woe to those who draw iniquity with cords of falsehood, and wickedness as with cart rope;', pt: 'Ai dos que puxam a iniqüidade com cordas de falsidade, e o pecado como com tirantes de carros!' },
      { v: 19, en: 'Who say, “Let him make speed, let him hasten his work, that we may see it; and let the counsel of the Holy One of Israel draw near and come, that we may know it!”', pt: 'E dizem: Apresse-se Deus, avie a sua obra, para que a vejamos; e aproxime-se e venha o propósito do Santo de Israel, para que o conheçamos.' },
      { v: 20, en: 'Woe to those who call evil good, and good evil; who put darkness for light, and light for darkness; who put bitter for sweet, and sweet for bitter!', pt: 'Ai dos que ao mal chamam bem, e ao bem mal; que põem as trevas por luz, e a luz por trevas, e o amargo por doce, e o doce por amargo!' },
      { v: 21, en: 'Woe to those who are wise in their own eyes, and prudent in their own sight!', pt: 'Ai dos que são sábios a seus próprios olhos, e astutos em seu próprio conceito!' },
      { v: 22, en: 'Woe to those who are mighty to drink wine, and champions at mixing strong drink;', pt: 'Ai dos que são poderosos para beber vinho, e valentes para misturar bebida forte;' },
      { v: 23, en: 'who acquit the guilty for a bribe, but deny justice for the innocent!', pt: 'dos que justificam o ímpio por peitas, e ao inocente lhe tiram o seu direito!' },
      { v: 24, en: 'Therefore as the tongue of fire devours the stubble, and as the dry grass sinks down in the flame, so their root shall be as rottenness, and their blossom shall go up as dust; because they have rejected the law of Yahweh of Armies, and despised the word of the Holy One of Israel.', pt: 'Pelo que, como a língua de fogo consome o restolho, e a palha se desfaz na chama assim a raiz deles será como podridão, e a sua flor se esvaecerá como pó; porque rejeitaram a lei do Senhor dos exércitos, e desprezaram a palavra do santo de Israel,' },
      { v: 25, en: 'Therefore Yahweh’s anger burns against his people, and he has stretched out his hand against them, and has struck them. The mountains tremble, and their dead bodies are as refuse in the middle of the streets. For all this, his anger is not turned away, but his hand is still stretched out.', pt: 'Por isso se acendeu a ira do Senhor contra o seu povo, e o Senhor estendeu a sua mão contra ele, e o feriu; e as montanhas tremeram, e os seus cadáveres eram como lixo no meio das ruas; com tudo isto não tornou atrás a sua ira, mas ainda está estendida a sua mão.' },
      { v: 26, en: 'He will lift up a banner to the nations from far, and he will whistle for them from the end of the earth. Behold, they will come speedily and swiftly.', pt: 'E ele arvorará um estandarte para as nações de longe, e lhes assobiará desde a extremidade da terra; e eis que virão muito apressadamente.' },
      { v: 27, en: 'No one shall be weary nor stumble among them; no one shall slumber nor sleep; neither shall the belt of their waist be untied, nor the strap of their sandals be broken:', pt: 'Não há entre eles cansado algum nem quem tropece; ninguém cochila nem dorme; não se lhe desata o cinto dos lombos, nem se lhe quebra a correia dos sapatos.' },
      { v: 28, en: 'whose arrows are sharp, and all their bows bent. Their horses’ hoofs will be like flint, and their wheels like a whirlwind.', pt: 'As suas flechas são agudas, e todos os seus arcos retesados; os cascos dos seus cavalos são reputados como pederneira, e as rodas dos seus carros qual redemoinho.' },
      { v: 29, en: 'Their roaring will be like a lioness. They will roar like young lions. Yes, they shall roar, and seize their prey and carry it off, and there will be no one to deliver.', pt: 'O seu rugido é como o do leão; rugem como filhos de leão; sim, rugem e agarram a presa, e a levam, e não há quem a livre.' },
      { v: 30, en: 'They will roar against them in that day like the roaring of the sea. If one looks to the land behold, darkness and distress. The light is darkened in its clouds.', pt: 'E bramarão contra eles naquele dia, como o bramido do mar; e se alguém olhar para a terra, eis que só verá trevas e angústia, e a luz se escurecerá nas nuvens sobre ela.' },
    ],
    6: [
      { v: 1, en: 'In the year that king Uzziah died, I saw the Lord sitting on a throne, high and lifted up; and his train filled the temple.', pt: 'No ano em que morreu o rei Uzias, eu vi o Senhor assentado sobre um alto e sublime trono, e as orlas do seu manto enchiam o templo.' },
      { v: 2, en: 'Above him stood the seraphim. Each one had six wings. With two he covered his face. With two he covered his feet. With two he flew.', pt: 'Ao seu redor havia serafins; cada um tinha seis asas; com duas cobria o rosto, e com duas cobria os pés e com duas voava.' },
      { v: 3, en: 'One called to another, and said, “Holy, holy, holy, is Yahweh of Armies! The whole earth is full of his glory!”', pt: 'E clamavam uns para os outros, dizendo: Santo, santo, santo é o Senhor dos exércitos; a terra toda está cheia da sua glória.' },
      { v: 4, en: 'The foundations of the thresholds shook at the voice of him who called, and the house was filled with smoke.', pt: 'E as bases dos limiares moveram-se à voz do que clamava, e a casa se enchia de fumaça.' },
      { v: 5, en: 'Then I said, “Woe is me! For I am undone, because I am a man of unclean lips, and I dwell among a people of unclean lips: for my eyes have seen the King, Yahweh of Armies!”', pt: 'Então disse eu: Ai de mim! pois estou perdido; porque sou homem de lábios impuros, e habito no meio dum povo de impuros lábios; e os meus olhos viram o rei, o Senhor dos exércitos!' },
      { v: 6, en: 'Then one of the seraphim flew to me, having a live coal in his hand, which he had taken with the tongs from off the altar.', pt: 'Então voou para mim um dos serafins, trazendo na mão uma brasa viva, que tirara do altar com uma tenaz;' },
      { v: 7, en: 'He touched my mouth with it, and said, “Behold, this has touched your lips; and your iniquity is taken away, and your sin forgiven.”', pt: 'e com a brasa tocou-me a boca, e disse: Eis que isto tocou os teus lábios; e a tua iniqüidade foi tirada, e perdoado o teu pecado.' },
      { v: 8, en: 'I heard the Lord’s voice, saying, “Whom shall I send, and who will go for us?” Then I said, “Here I am. Send me!”', pt: 'Depois disto ouvi a voz do Senhor, que dizia: A quem enviarei, e quem irá por nós? Então disse eu: Eis-me aqui, envia-me a mim.' },
      { v: 9, en: 'He said, “Go, and tell this people, ‘You hear indeed, but don’t understand; and you see indeed, but don’t perceive.’', pt: 'Disse, pois, ele: Vai, e dize a este povo: Ouvis, de fato, e não entendeis, e vedes, em verdade, mas não percebeis.' },
      { v: 10, en: 'Make the heart of this people fat. Make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and turn again, and be healed.”', pt: 'Engorda o coração deste povo, e endurece-lhe os ouvidos, e fecha-lhe os olhos; para que ele não veja com os olhos, e ouça com os ouvidos, e entenda com o coração, e se converta, e seja sarado.' },
      { v: 11, en: 'Then I said, “Lord, how long?” He answered, “Until cities are waste without inhabitant, and houses without man, and the land becomes utterly waste,', pt: 'Então disse eu: Até quando, Senhor? E respondeu: Até que sejam assoladas as cidades, e fiquem sem habitantes, e as casas sem moradores, e a terra seja de todo assolada,' },
      { v: 12, en: 'And Yahweh has removed men far away, and the forsaken places are many within the land.', pt: 'e o Senhor tenha removido para longe dela os homens, e sejam muitos os lugares abandonados no meio da terra.' },
      { v: 13, en: 'If there is a tenth left in it, that also will in turn be consumed: as a terebinth, and as an oak, whose stock remains when they are felled; so the holy seed is its stock.”', pt: 'Mas se ainda ficar nela a décima parte, tornará a ser consumida, como o terebinto, e como o carvalho, dos quais, depois de derrubados, ainda fica o toco. A santa semente é o seu toco.' },
    ],
    7: [
      { v: 1, en: 'In the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it, but could not prevail against it.', pt: 'Sucedeu, pois, nos dias de Acaz, filho de Jotão, filho de Uzias, rei de Judá, que Rezim, rei da Síria, e Peca, filho de Remalias, rei de Israel, subiram a Jerusalém, para pelejarem contra ela, mas não a puderam conquistar.' },
      { v: 2, en: 'David’s house was told, “Syria is allied with Ephraim.” His heart trembled, and the heart of his people, as the trees of the forest tremble with the wind.', pt: 'Quando deram aviso à casa de Davi, dizendo: A Síria fez aliança com Efraim; ficou agitado o coração de Acaz, e o coração do seu povo, como se agitam as árvores do bosque à força do vento.' },
      { v: 3, en: 'Then Yahweh said to Isaiah, “Go out now to meet Ahaz, you, and Shearjashub your son, at the end of the conduit of the upper pool, on the highway of the fuller’s field.', pt: 'Então disse o Senhor a Isaías: saí agora, tu e teu filho Sear-Jasube, ao encontro de Acaz, ao fim do aqueduto da piscina superior, na estrada do campo do lavandeiro,' },
      { v: 4, en: 'Tell him, ‘Be careful, and keep calm. Don’t be afraid, neither let your heart be faint because of these two tails of smoking torches, for the fierce anger of Rezin and Syria, and of the son of Remaliah.', pt: 'e dize-lhe: Acautela-te e aquieta-te; não temas, nem te desfaleça o coração por causa destes dois pedaços de tições fumegantes; por causa do ardor da ira de Rezim e da Síria, e do filho de Remalias.' },
      { v: 5, en: 'Because Syria, Ephraim, and the son of Remaliah, have plotted evil against you, saying,', pt: 'Porquanto a Síria maquinou o mal contra ti, com Efraim e com o filho de Remalias, dizendo:' },
      { v: 6, en: '“Let’s go up against Judah, and tear it apart, and let’s divide it among ourselves, and set up a king within it, even the son of Tabeel.”', pt: 'Subamos contra Judá, e amedrontemo-lo, e demos sobre ele, tomando-o para nós, e façamos reinar no meio dele o filho de Tabeel.' },
      { v: 7, en: 'This is what the Lord Yahweh says: “It shall not stand, neither shall it happen.”', pt: 'Assim diz o Senhor Deus: Isto não subsistirá, nem tampouco acontecerá.' },
      { v: 8, en: 'For the head of Syria is Damascus, and the head of Damascus is Rezin; and within sixty-five years Ephraim shall be broken in pieces, so that it shall not be a people;', pt: 'Pois a cabeça da Síria é Damasco, e o cabeça de Damasco é Rezim; e dentro de sessenta e cinco anos Efraim será quebrantado, e deixará de ser povo.' },
      { v: 9, en: 'and the head of Ephraim is Samaria, and the head of Samaria is Remaliah’s son. If you will not believe, surely you shall not be established.’”', pt: 'Entretanto a cabeça de Efraim será Samária, e o cabeça de Samária o filho de Remalias; se não o crerdes, certamente não haveis de permanecer.' },
      { v: 10, en: 'Yahweh spoke again to Ahaz, saying,', pt: 'De novo falou o Senhor com Acaz, dizendo:' },
      { v: 11, en: '“Ask a sign of Yahweh your God; ask it either in the depth, or in the height above.”', pt: 'Pede para ti ao Senhor teu Deus um sinal; pede-o ou em baixo nas profundezas ou em cima nas alturas.' },
      { v: 12, en: 'But Ahaz said, “I will not ask, neither will I tempt Yahweh.”', pt: 'Acaz, porém, respondeu: Não o pedirei nem porei à prova o Senhor.' },
      { v: 13, en: 'He said, “Listen now, house of David. Is it not enough for you to try the patience of men, that you will try the patience of my God also?', pt: 'Então disse Isaías: Ouvi agora, ó casa de Davi: Pouco vos é afadigardes os homens, que ainda afadigareis também ao meu Deus?' },
      { v: 14, en: 'Therefore the Lord himself will give you a sign. Behold, the virgin will conceive, and bear a son, and shall call his name Immanuel.', pt: 'Portanto o Senhor mesmo vos dará um sinal: eis que uma virgem conceberá, e dará à luz um filho, e será o seu nome Emanuel.' },
      { v: 15, en: 'He shall eat butter and honey when he knows to refuse the evil, and choose the good.', pt: 'Manteiga e mel comerá, quando ele souber rejeitar o mal e escolher o bem.' },
      { v: 16, en: 'For before the child knows to refuse the evil, and choose the good, the land whose two kings you abhor shall be forsaken.', pt: 'Pois antes que o menino saiba rejeitar o mal e escolher o bem, será desolada a terra dos dois reis perante os quais tu tremes de medo.' },
      { v: 17, en: 'Yahweh will bring on you, on your people, and on your father’s house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.', pt: 'Mas o Senhor fará vir sobre ti, e sobre o teu povo e sobre a casa de teu pai, dias tais, quais nunca vieram, desde o dia em que Efraim se separou de Judá, isto é, fará vir o rei da Assíria.' },
      { v: 18, en: 'It will happen in that day that Yahweh will whistle for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.', pt: 'Naquele dia assobiará o Senhor às moscas que há no extremo dos rios do Egito, e às abelhas que estão na terra da Assíria.' },
      { v: 19, en: 'They shall come, and shall all rest in the desolate valleys, in the clefts of the rocks, on all thorn hedges, and on all pastures.', pt: 'E elas virão, e pousarão todas nos vales desertos e nas fendas das rochas, e sobre todos os espinheirais, e sobre todos os prados.' },
      { v: 20, en: 'In that day the Lord will shave with a razor that is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet; and it shall also consume the beard.', pt: 'Naquele dia rapará o Senhor com uma navalha alugada, que está além do Rio, isto é, com o rei da Assíria, a cabeça e os cabelos dos pés; e até a barba arrancará.' },
      { v: 21, en: 'It shall happen in that day that a man shall keep alive a young cow, and two sheep;', pt: 'Sucederá naquele dia que um homem criará uma vaca e duas ovelhas;' },
      { v: 22, en: 'and it shall happen, that because of the abundance of milk which they shall give he shall eat butter: for everyone will eat butter and honey that is left within the land.', pt: 'e por causa da abundância do leite que elas hão de dar, comerá manteiga; pois manteiga e mel comerá todo aquele que ficar de resto no meio da terra.' },
      { v: 23, en: 'It will happen in that day that every place where there were a thousand vines at a thousand silver shekels, shall be for briers and thorns.', pt: 'Sucederá também naquele dia que todo lugar, em que antes havia mil vides, do valor de mil siclos de prata, será para sarças e para espinheiros.' },
      { v: 24, en: 'People will go there with arrows and with bow, because all the land will be briers and thorns.', pt: 'Com arco e flechas entrarão ali; porque as sarças e os espinheiros cobrirão toda a terra.' },
      { v: 25, en: 'All the hills that were cultivated with the hoe, you shall not come there for fear of briers and thorns; but it shall be for the sending out of oxen, and for the treading of sheep.”', pt: 'Quanto a todos os outeiros que costumavam cavar com enxadas, para ali não chegarás, por medo das sarças e dos espinheiros; mas servirão de pasto para os bois, e serão pisados pelas ovelhas.' },
    ],
    8: [
      { v: 1, en: 'Yahweh said to me, “Take a large tablet, and write on it with a man’s pen, ‘For Maher Shalal Hash Baz’;', pt: 'Disse-me também o Senhor: Toma uma tábua grande e escreve nela em caracteres legíveis: Maer-Salal-Has-Baz;' },
      { v: 2, en: 'and I will take for myself faithful witnesses to testify: Uriah the priest, and Zechariah the son of Jeberechiah.”', pt: 'tomei pois, comigo fiéis testemunhas, a Urias sacerdote, e a Zacarias, filho de Jeberequias.' },
      { v: 3, en: 'I went to the prophetess, and she conceived, and bore a son. Then Yahweh said to me, “Call his name ‘Maher Shalal Hash Baz.’', pt: 'E fui ter com a profetisa; e ela concebeu, e deu à luz um filho; e o Senhor me disse: Põe-lhe o nome de Maer-Salal-Has-Baz.' },
      { v: 4, en: 'For before the child knows how to say, ‘My father,’ and, ‘My mother,’ the riches of Damascus and the plunder of Samaria will be carried away by the king of Assyria.”', pt: 'Pois antes que o menino saiba dizer meu pai ou minha mãe, se levarão as riquezas de Damasco, e os despojos de Samária, diante do rei da Assíria.' },
      { v: 5, en: 'Yahweh spoke to me yet again, saying,', pt: 'E continuou o Senhor a falar ainda comigo, dizendo:' },
      { v: 6, en: '“Because this people have refused the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah’s son;', pt: 'Porquanto este povo rejeitou as águas de Siloa, que correm brandamente, e se alegrou com Rezim e com o filho de Remalias,' },
      { v: 7, en: 'now therefore, behold, the Lord brings upon them the mighty flood waters of the River: the king of Assyria and all his glory. It will come up over all its channels, and go over all its banks.', pt: 'eis que o Senhor fará vir sobre eles as águas do Rio, fortes e impetuosas, isto é, o rei da Assíria, com toda a sua glória; e subirá sobre todos os seus leitos, e transbordará por todas as suas ribanceiras;' },
      { v: 8, en: 'It will sweep onward into Judah. It will overflow and pass through; it will reach even to the neck; and the stretching out of its wings will fill the width of your land, Immanuel.', pt: 'e passará a Judá, inundando-o, e irá passando por ele e chegará até o pescoço; e a extensão de suas asas encherá a largura da tua terra, ó Emanuel.' },
      { v: 9, en: 'Make an uproar, you peoples, and be broken in pieces! Listen, all you from far countries: dress for battle, and be shattered! Dress for battle, and be shattered!', pt: 'Exasperai-vos, ó povos, e sereis quebrantados; dai ouvidos, todos os que sois de terras longínquas; cingi-vos e sereis feitos em pedaços, cingi-vos e sereis feitos em pedaços;' },
      { v: 10, en: 'Take counsel together, and it will be brought to nothing; speak the word, and it will not stand: for God is with us.”', pt: 'Tomai juntamente conselho, e ele será frustrado; dizei uma palavra, e ela não subsistirá; porque Deus é conosco.' },
      { v: 11, en: 'For Yahweh spoke thus to me with a strong hand, and instructed me not to walk in the way of this people, saying,', pt: 'Pois assim o Senhor me falou, com sua forte mão deitada em mim, e me admoestou a que não andasse pelo caminho deste povo, dizendo:' },
      { v: 12, en: '“Don’t say, ‘A conspiracy!’ concerning all about which this people say, ‘A conspiracy!’ neither fear their threats, nor be terrorized.', pt: 'Não chameis conspiração a tudo quanto este povo chama conspiração; e não temais aquilo que ele teme, nem por isso vos assombreis.' },
      { v: 13, en: 'Yahweh of Armies is who you must respect as holy. He is the one you must fear. He is the one you must dread.', pt: 'Ao Senhor dos exércitos, a ele santificai; e seja ele o vosso temor e seja ele o vosso assombro.' },
      { v: 14, en: 'He will be a sanctuary, but for both houses of Israel, he will be a trap and a snare for the inhabitants of Jerusalem.', pt: 'Então ele vos será por santuário; mas servirá de pedra de tropeço, e de rocha de escândalo, às duas casas de Israel; de armadilha e de laço aos moradores de Jerusalém.' },
      { v: 15, en: 'Many will stumble over it, fall, be broken, be snared, and be captured.”', pt: 'E muitos dentre eles tropeçarão, e cairão, e serão quebrantados, e enlaçados, e presos.' },
      { v: 16, en: 'Wrap up the testimony. Seal the law among my disciples.', pt: 'Ata o testemunho, sela a lei entre os meus discípulos.' },
      { v: 17, en: 'I will wait for Yahweh, who hides his face from the house of Jacob, and I will look for him.', pt: 'Esperarei no Senhor, que esconde o seu rosto da casa de Jacó, e a ele aguardarei.' },
      { v: 18, en: 'Behold, I and the children whom Yahweh has given me are for signs and for wonders in Israel from Yahweh of Armies, who dwells in Mount Zion.', pt: 'Eis-me aqui, com os filhos que me deu o Senhor; são como sinais e portentos em Israel da parte do Senhor dos exércitos, que habita no monte Sião.' },
      { v: 19, en: 'When they tell you, “Consult with those who have familiar spirits and with the wizards, who chirp and who mutter:” shouldn’t a people consult with their God? Should they consult the dead on behalf of the living?', pt: 'Quando vos disserem: Consultai os que têm espíritos familiares e os feiticeiros, que chilreiam e murmuram, respondei: Acaso não consultará um povo a seu Deus? acaso a favor dos vivos consultará os mortos?' },
      { v: 20, en: 'Turn to the law and to the testimony! If they don’t speak according to this word, surely there is no morning for them.', pt: 'A Lei e ao Testemunho! se eles não falarem segundo esta palavra, nunca lhes raiará a alva.' },
      { v: 21, en: 'They will pass through it, very distressed and hungry; and it will happen that when they are hungry, they will worry, and curse by their king and by their God. They will turn their faces upward,', pt: 'E passarão pela terra duramente oprimidos e famintos; e, tendo fome, se agastarão, e amaldiçoarão o seu rei e o seu Deus, olhando para o céu em cima;' },
      { v: 22, en: 'and look to the earth, and see distress, darkness, and the gloom of anguish. They will be driven into thick darkness.', pt: 'e para a terra em baixo, e eis aí angústia e escuridão, tristeza da aflição; e para as trevas serão empurrados.' },
    ],
    9: [
      { v: 1, en: 'But there shall be no more gloom for her who was in anguish. In the former time, he brought into contempt the land of Zebulun and the land of Naphtali; but in the latter time he has made it glorious, by the way of the sea, beyond the Jordan, Galilee of the nations.', pt: 'Mas para a que estava aflita não haverá escuridão. Nos primeiros tempos, ele envileceu a terra de Zebulom, e a terra de Naftali; mas nos últimos tempos fará glorioso o caminho do mar, além do Jordão, a Galiléia dos gentios.' },
      { v: 2, en: 'The people who walked in darkness have seen a great light. Those who lived in the land of the shadow of death, on them the light has shined.', pt: 'O povo que andava em trevas viu uma grande luz; e sobre os que habitavam na terra de profunda escuridão resplandeceu a luz.' },
      { v: 3, en: 'You have multiplied the nation. You have increased their joy. They rejoice before you according to the joy in harvest, as men rejoice when they divide the plunder.', pt: 'Tu multiplicaste este povo, a alegria lhe aumentaste; todos se alegrarão perante ti, como se alegram na ceifa e como exultam quando se repartem os despojos.' },
      { v: 4, en: 'For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, you have broken as in the day of Midian.', pt: 'Porque tu quebraste o jugo da sua carga e o bordão do seu ombro, que é o cetro do seu opressor, como no dia de Midiã.' },
      { v: 5, en: 'For all the armor of the armed man in the noisy battle, and the garments rolled in blood, will be for burning, fuel for the fire.', pt: 'Porque todo calçado daqueles que andavam no tumulto, e toda capa revolvida em sangue serão queimados, servindo de pasto ao fogo.' },
      { v: 6, en: 'For to us a child is born. To us a son is given; and the government will be on his shoulders. His name will be called Wonderful, Counselor, Mighty God, Everlasting Father, Prince of Peace.', pt: 'Porque um menino nos nasceu, um filho se nos deu; e o governo estará sobre os seus ombros; e o seu nome será: Maravilhoso Conselheiro, Deus Forte, Pai Eterno, Príncipe da Paz.' },
      { v: 7, en: 'Of the increase of his government and of peace there shall be no end, on David’s throne, and on his kingdom, to establish it, and to uphold it with justice and with righteousness from that time on, even forever. The zeal of Yahweh of Armies will perform this.', pt: 'Do aumento do seu governo e da paz não haverá fim, sobre o trono de Davi e no seu reino, para o estabelecer e o fortificar em retidão e em justiça, desde agora e para sempre; o zelo do Senhor dos exércitos fará isso.' },
      { v: 8, en: 'The Lord sent a word into Jacob, and it falls on Israel.', pt: 'O Senhor enviou uma palavra a Jacó, e ela caiu em Israel.' },
      { v: 9, en: 'All the people will know, including Ephraim and the inhabitants of Samaria, who say in pride and in arrogance of heart,', pt: 'E todo o povo o saberá, Efraim e os moradores de Samária, os quais em soberba e altivez de coração dizem:' },
      { v: 10, en: '“The bricks have fallen, but we will build with cut stone. The sycamore fig trees have been cut down, but we will put cedars in their place.”', pt: 'Os tijolos caíram, mas com cantaria tornaremos a edificar; cortaram-se os sicômoros, mas por cedros os substituiremos.' },
      { v: 11, en: 'Therefore Yahweh will set up on high against him the adversaries of Rezin, and will stir up his enemies,', pt: 'Pelo que o Senhor suscita contra eles os adversários de Rezim, e instiga os seus inimigos,' },
      { v: 12, en: 'The Syrians in front, and the Philistines behind; and they will devour Israel with open mouth. For all this, his anger is not turned away, but his hand is stretched out still.', pt: 'os sírios do Oriente, e os filisteus do Ocidente; e eles devoram a Israel à boca escancarada. Com tudo isso não se apartou a sua ira, mas ainda está estendida a sua mão.' },
      { v: 13, en: 'Yet the people have not turned to him who struck them, neither have they sought Yahweh of Armies.', pt: 'Todavia o povo não se voltou para quem o feriu, nem buscou ao Senhor dos exércitos.' },
      { v: 14, en: 'Therefore Yahweh will cut off from Israel head and tail, palm branch and reed, in one day.', pt: 'Pelo que o Senhor cortou de Israel a cabeça e a cauda, o ramo e o junco, num mesmo dia.' },
      { v: 15, en: 'The elder and the honorable man is the head, and the prophet who teaches lies is the tail.', pt: 'O ancião e o varão de respeito, esse é a cabeça; e o profeta que ensina mentiras, esse e a cauda.' },
      { v: 16, en: 'For those who lead this people lead them astray; and those who are led by them are destroyed.', pt: 'Porque os que guiam este povo o desencaminham; e os que por eles são guiados são devorados.' },
      { v: 17, en: 'Therefore the Lord will not rejoice over their young men, neither will he have compassion on their fatherless and widows; for everyone is profane and an evildoer, and every mouth speaks folly. For all this his anger is not turned away, but his hand is stretched out still.', pt: 'Pelo que o Senhor não se regozija nos seus jovens, e não se compadece dos seus órfãos e das suas viúvas; porque todos eles são profanos e malfeitores, e toda boca profere doidices. Com tudo isso não se apartou a sua ira, mas ainda está estendida a sua mão.' },
      { v: 18, en: 'For wickedness burns like a fire. It devours the briers and thorns; yes, it kindles in the thickets of the forest, and they roll upward in a column of smoke.', pt: 'Pois a impiedade lavra como um fogo que devora espinhos e abrolhos, e se ateia no emaranhado da floresta; e eles sobem ao alto em espessas nuvens de fumaça.' },
      { v: 19, en: 'Through Yahweh of Armies’ wrath, the land is burned up; and the people are the fuel for the fire. No one spares his brother.', pt: 'Por causa da ira do Senhor dos exércitos a terra se queima, e o povo é como pasto do fogo; ninguém poupa ao seu irmão.' },
      { v: 20, en: 'One will devour on the right hand, and be hungry; and he will eat on the left hand, and they will not be satisfied. Everyone will eat the flesh of his own arm:', pt: 'Se colher da banda direita, ainda terá fome, e se comer da banda esquerda, ainda não se fartará; cada um comerá a carne de seu braço.' },
      { v: 21, en: 'Manasseh, Ephraim; and Ephraim, Manasseh; and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.', pt: 'Manassés será contra Efraim, e Efraim contra Manassés, e ambos eles serão contra Judá. Com tudo isso não se apartou a sua ira, mas ainda está estendida a sua mão.' },
    ],
    10: [
      { v: 1, en: 'Woe to those who decree unrighteous decrees, and to the writers who write oppressive decrees;', pt: 'Ai dos que decretam leis injustas, e dos escrivães que escrevem perversidades;' },
      { v: 2, en: 'to deprive the needy from justice, and to rob the poor among my people of their rights, that widows may be their plunder, and that they may make the fatherless their prey!', pt: 'para privarem da justiça os necessitados, e arrebatarem o direito aos aflitos do meu povo; para despojarem as viúvas e roubarem os órfãos!' },
      { v: 3, en: 'What will you do in the day of visitation, and in the desolation which will come from afar? To whom will you flee for help? Where will you leave your wealth?', pt: 'Mas que fareis vós no dia da visitação, e na desolação, que há de vir de longe? a quem recorrereis para obter socorro, e onde deixareis a vossa riqueza?' },
      { v: 4, en: 'They will only bow down under the prisoners, and will fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.', pt: 'Nada mais resta senão curvar-vos entre os presos, ou cair entre os mortos. Com tudo isso não se apartou a sua ira, mas ainda está estendida a sua mão.' },
      { v: 5, en: 'Alas Assyrian, the rod of my anger, the staff in whose hand is my indignation!', pt: 'Ai da Assíria, a vara da minha ira, porque a minha indignação é como bordão nas suas mãos.' },
      { v: 6, en: 'I will send him against a profane nation, and against the people who anger me will I give him a command to take the plunder and to take the prey, and to tread them down like the mire of the streets.', pt: 'Eu a envio contra uma nação ímpia; e contra o povo do meu furor lhe dou ordem, para tomar o despojo, para arrebatar a presa, e para os pisar aos pés, como a lama das ruas.' },
      { v: 7, en: 'However he doesn’t mean so, neither does his heart think so; but it is in his heart to destroy, and to cut off not a few nations.', pt: 'Todavia ela não entende assim, nem o seu coração assim o imagina; antes no seu coração intenta destruir e desarraigar não poucas nações.' },
      { v: 8, en: 'For he says, “Aren’t all of my princes kings?', pt: 'Pois diz: Não são meus príncipes todos eles reis?' },
      { v: 9, en: 'Isn’t Calno like Carchemish? Isn’t Hamath like Arpad? Isn’t Samaria like Damascus?”', pt: 'Não é Calnó como Carquêmis? não é Hamate como Arpade? e Samária como Damasco?' },
      { v: 10, en: 'As my hand has found the kingdoms of the idols, whose engraved images exceeded those of Jerusalem and of Samaria;', pt: 'Do mesmo modo que a minha mão alcançou os reinos dos ídolos, ainda que as suas imagens esculpidas eram melhores do que as de Jerusalém e de Samária.' },
      { v: 11, en: 'shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?', pt: 'como fiz a Samária e aos seus ídolos, não o farei igualmente a Jerusalém e aos seus ídolos?' },
      { v: 12, en: 'Therefore it will happen that, when the Lord has performed his whole work on Mount Zion and on Jerusalem, I will punish the fruit of the willful proud heart of the king of Assyria, and the insolence of his haughty looks.', pt: 'Por isso acontecerá que, havendo o Senhor acabado toda a sua obra no monte Sião e em Jerusalém, então castigará o rei da Assíria pela arrogância do seu coração e a pomba da altivez dos seus olhos.' },
      { v: 13, en: 'For he has said, “By the strength of my hand I have done it, and by my wisdom; for I have understanding: and I have removed the boundaries of the peoples, and have robbed their treasures. Like a valiant man I have brought down their rulers.', pt: 'Porquanto diz ele: Com a força da minha mão o fiz, e com a minha sabedoria, porque sou entendido; eu removi os limites dos povos, e roubei os seus tesouros, e como valente abati os que se sentavam sobre tronos.' },
      { v: 14, en: 'My hand has found the riches of the peoples like a nest, and like one gathers eggs that are abandoned, I have gathered all the earth. There was no one who moved their wing, or that opened their mouth, or chirped.”', pt: 'E achou a minha mão as riquezas dos povos como a um ninho; e como se ajuntam os ovos abandonados, assim eu ajuntei toda a terra; e não houve quem movesse a asa, ou abrisse a boca, ou chilreasse.' },
      { v: 15, en: 'Should an ax brag against him who chops with it? Should a saw exalt itself above him who saws with it? As if a rod should lift those who lift it up, or as if a staff should lift up someone who is not wood.', pt: 'Porventura gloriar-se-á o machado contra o que corta com ele? ou se engrandecerá a serra contra o que a maneja? como se a vara movesse o que a levanta, ou o bordão levantasse aquele que não é pau!' },
      { v: 16, en: 'Therefore the Lord, Yahweh of Armies, will send among his fat ones leanness; and under his glory a burning will be kindled like the burning of fire.', pt: 'Pelo que o Senhor Deus dos exércitos fará definhar os que entre eles são gordos, e debaixo da sua glória ateará um incêndio, como incêndio de fogo.' },
      { v: 17, en: 'The light of Israel will be for a fire, and his Holy One for a flame; and it will burn and devour his thorns and his briers in one day.', pt: 'A Luz de Israel virá a ser um fogo e o seu Santo uma labareda, que num só dia abrasará e consumirá os seus espinheiros e as suas sarças.' },
      { v: 18, en: 'He will consume the glory of his forest, and of his fruitful field, both soul and body. It will be as when a standard bearer faints.', pt: 'Também consumirá a glória da sua floresta, e do seu campo fértil, desde a alma até o corpo; e será como quando um doente vai definhando.' },
      { v: 19, en: 'The remnant of the trees of his forest shall be few, so that a child could write their number.', pt: 'E o resto das árvores da sua floresta será tão pouco que um menino as poderá contar.' },
      { v: 20, en: 'It will come to pass in that day that the remnant of Israel, and those who have escaped from the house of Jacob will no more again lean on him who struck them, but shall lean on Yahweh, the Holy One of Israel, in truth.', pt: 'E acontecerá naquele dia que o resto de Israel, e os que tiverem escapado da casa de Jacó, nunca mais se estribarão sobre aquele que os feriu; antes se estribarão lealmente sobre o Senhor, o Santo de Israel.' },
      { v: 21, en: 'A remnant will return, even the remnant of Jacob, to the mighty God.', pt: 'Um resto voltará; sim, o resto de Jacó voltará para o Deus forte.' },
      { v: 22, en: 'For though your people, Israel, are like the sand of the sea, only a remnant of them will return. A destruction is determined, overflowing with righteousness.', pt: 'Porque ainda que o teu povo, ó Israel, seja como a areia do mar, só um resto dele voltará. Uma destruição está determinada, trasbordando de justiça.' },
      { v: 23, en: 'For the Lord, Yahweh of Armies, will make a full end, and that determined, throughout all the earth.', pt: 'Pois uma destruição, e essa já determinada, o Senhor Deus dos exércitos executará no meio de toda esta terra.' },
      { v: 24, en: 'Therefore the Lord, Yahweh of Armies, says “My people who dwell in Zion, don’t be afraid of the Assyrian, though he strike you with the rod, and lift up his staff against you, as Egypt did.', pt: 'Pelo que assim diz o Senhor Deus dos exércitos: Ó povo meu, que habitas em Sião, não temas a Assíria, quando te ferir com a vara, e contra ti levantar o seu bordão a maneira dos egípcios;' },
      { v: 25, en: 'For yet a very little while, and the indignation against you will be accomplished, and my anger will be directed to his destruction.”', pt: 'porque daqui a bem pouco se cumprirá a minha indignação, e a minha ira servirá para os consumir.' },
      { v: 26, en: 'Yahweh of Armies will stir up a scourge against him, as in the slaughter of Midian at the rock of Oreb. His rod will be over the sea, and he will lift it up like he did against Egypt.', pt: 'E o Senhor dos exércitos suscitará contra ela um flagelo, como a matança de Midiã junto à rocha de Orebe; e a sua vara se estenderá sobre o mar, e ele a levantará como no Egito.' },
      { v: 27, en: 'It will happen in that day, that his burden will depart from off your shoulder, and his yoke from off your neck, and the yoke shall be destroyed because of the anointing oil.', pt: 'E naquele dia a sua carga será tirada do teu ombro, e o seu jugo do teu pescoço; e o jugo será quebrado por causa da gordura.' },
      { v: 28, en: 'He has come to Aiath. He has passed through Migron. At Michmash he stores his baggage.', pt: 'Os assírios já chegaram a Aiate, passaram por Migrom; em Micmás deixam depositada a sua bagagem;' },
      { v: 29, en: 'They have gone over the pass. They have taken up their lodging at Geba. Ramah trembles. Gibeah of Saul has fled.', pt: 'já atravessaram o desfiladeiro, já se alojam em Geba; Ramá treme, Gibeá de Saul já fugiu.' },
      { v: 30, en: 'Cry aloud with your voice, daughter of Gallim! Listen, Laishah! You poor Anathoth!', pt: 'Clama com alta voz, ó filha de Galim! Ouve, ó Laís! Responde-lhe, ó Anatote!' },
      { v: 31, en: 'Madmenah is a fugitive. The inhabitants of Gebim flee for safety.', pt: 'Já se foi Madmena; os moradores de Gebim procuram refúgio.' },
      { v: 32, en: 'This very day he will halt at Nob. He shakes his hand at the mountain of the daughter of Zion, the hill of Jerusalem.', pt: 'Hoje mesmo parará em Nobe; sacudirá o punho contra o monte da filha de Sião, o outeiro de Jerusalém.' },
      { v: 33, en: 'Behold, the Lord, Yahweh of Armies, will lop the boughs with terror. The tall will be cut down, and the lofty will be brought low.', pt: 'Eis que o Senhor Deus dos exércitos cortará os ramos com violência; e os de alta estatura serão cortados, e os elevados serão abatidos.' },
      { v: 34, en: 'He will cut down the thickets of the forest with iron, and Lebanon will fall by the Mighty One.', pt: 'E cortará com o ferro o emaranhado da floresta, e o Líbano cairá pela mão de um poderoso.' },
    ],
    11: [
      { v: 1, en: 'A shoot will come out of the stock of Jesse, and a branch out of his roots will bear fruit.', pt: 'Então brotará um rebento do toco de Jessé, e das suas raízes um renovo frutificará.' },
      { v: 2, en: 'Yahweh’s Spirit will rest on him: the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of Yahweh.', pt: 'E repousará sobre ele o Espírito do Senhor, o espírito de sabedoria e de entendimento, o espírito de conselho e de fortaleza, o espírito de conhecimento e de temor do Senhor.' },
      { v: 3, en: 'His delight will be in the fear of Yahweh. He will not judge by the sight of his eyes, neither decide by the hearing of his ears;', pt: 'E deleitar-se-á no temor do Senhor; e não julgará segundo a vista dos seus olhos, nem decidirá segundo o ouvir dos seus ouvidos;' },
      { v: 4, en: 'but with righteousness he will judge the poor, and decide with equity for the humble of the earth. He will strike the earth with the rod of his mouth; and with the breath of his lips he will kill the wicked.', pt: 'mas julgará com justiça os pobres, e decidirá com eqüidade em defesa dos mansos da terra; e ferirá a terra com a vara de sua boca, e com o sopro dos seus lábios matará o ímpio.' },
      { v: 5, en: 'Righteousness will be the belt of his waist, and faithfulness the belt of his waist.', pt: 'A justiça será o cinto dos seus lombos, e a fidelidade o cinto dos seus rins.' },
      { v: 6, en: 'The wolf will live with the lamb, and the leopard will lie down with the young goat; The calf, the young lion, and the fattened calf together; and a little child will lead them.', pt: 'Morará o lobo com o cordeiro, e o leopardo com o cabrito se deitará; e o bezerro, e o leão novo e o animal cevado viverão juntos; e um menino pequeno os conduzirá.' },
      { v: 7, en: 'The cow and the bear will graze. Their young ones will lie down together. The lion will eat straw like the ox.', pt: 'A vaca e a ursa pastarão juntas, e as suas crias juntas se deitarão; e o leão comerá palha como o boi.' },
      { v: 8, en: 'The nursing child will play near a cobra’s hole, and the weaned child will put his hand on the viper’s den.', pt: 'A criança de peito brincará sobre a toca da áspide, e a desmamada meterá a sua mão na cova do basilisco.' },
      { v: 9, en: 'They will not hurt nor destroy in all my holy mountain; for the earth will be full of the knowledge of Yahweh, as the waters cover the sea.', pt: 'Não se fará mal nem dano algum em todo o meu santo monte; porque a terra se encherá do conhecimento do Senhor, como as águas cobrem o mar.' },
      { v: 10, en: 'It will happen in that day that the nations will seek the root of Jesse, who stands as a banner of the peoples; and his resting place will be glorious.', pt: 'Naquele dia a raiz de Jessé será posta por estandarte dos povos, à qual recorrerão as nações; gloriosas lhe serão as suas moradas.' },
      { v: 11, en: 'It will happen in that day that the Lord will set his hand again the second time to recover the remnant that is left of his people from Assyria, from Egypt, from Pathros, from Cush, from Elam, from Shinar, from Hamath, and from the islands of the sea.', pt: 'Naquele dia o Senhor tornará a estender a sua mão para adquirir outra vez e resto do seu povo, que for deixado, da Assíria, do Egito, de Patros, da Etiópia, de Elão, de Sinar, de Hamate, e das ilhas de mar.' },
      { v: 12, en: 'He will set up a banner for the nations, and will assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.', pt: 'Levantará um pendão entre as nações e ajuntará os desterrados de Israel, e es dispersos de Judá congregará desde os quatro confins da terra.' },
      { v: 13, en: 'The envy also of Ephraim will depart, and those who persecute Judah will be cut off. Ephraim won’t envy Judah, and Judah won’t persecute Ephraim.', pt: 'Também se esvaecerá a inveja de Efraim, e os vexadores de Judá serão desarraigados; Efraim não invejará a Judá e Judá não vexará a Efraim.' },
      { v: 14, en: 'They will fly down on the shoulders of the Philistines on the west. Together they will plunder the children of the east. They will extend their power over Edom and Moab, and the children of Ammon will obey them.', pt: 'Antes voarão sobre os ombros des filisteus ao Ocidente; juntos despojarão aos filhos do Oriente; em Edom e Moabe porão as suas mãos, e os filhos de Amom lhes obedecerão.' },
      { v: 15, en: 'Yahweh will utterly destroy the tongue of the Egyptian sea; and with his scorching wind he will wave his hand over the River, and will split it into seven streams, and cause men to march over in sandals.', pt: 'E o Senhor destruirá totalmente a língua do mar do Egito; e vibrará a sua mão contra o Rio com o seu vento abrasador, e, ferindo- o, dividi-lo-á em sete correntes, e fará que por ele passem a pé enxuto.' },
      { v: 16, en: 'There will be a highway for the remnant that is left of his people from Assyria, like there was for Israel in the day that he came up out of the land of Egypt.', pt: 'Assim haverá caminho plano para e restante do seu povo, que voltar da Assíria, como houve para Israel no dia em que subiu da terra do Egito.' },
    ],
    12: [
      { v: 1, en: 'In that day you will say, “I will give thanks to you, Yahweh; for though you were angry with me, your anger has turned away and you comfort me.', pt: 'Dirás, pois, naquele dia: Graças te dou, ó Senhor; porque, ainda que te iraste contra mim, a tua ira se retirou, e tu me confortaste.' },
      { v: 2, en: 'Behold, God is my salvation. I will trust, and will not be afraid; for Yah, Yahweh, is my strength and song; and he has become my salvation.”', pt: 'Eis que Deus é a minha salvação; eu confiarei e não temerei porque o Senhor, sim o Senhor é a minha força e o meu cântico; e se tornou a minha salvação.' },
      { v: 3, en: 'Therefore with joy you will draw water out of the wells of salvation.', pt: 'Portanto com alegria tirareis águas das fontes da salvação.' },
      { v: 4, en: 'In that day you will say, “Give thanks to Yahweh! Call on his name. Declare his doings among the peoples. Proclaim that his name is exalted!', pt: 'E direis naquele dia: Dai graças ao Senhor, invocai o seu nome, fazei notórios os seus feitos entre os povos, proclamai quão excelso é o seu nome.' },
      { v: 5, en: 'Sing to Yahweh, for he has done excellent things! Let this be known in all the earth!', pt: 'Cantai ao Senhor; porque fez coisas grandiosas; saiba-se isso em toda a terra.' },
      { v: 6, en: 'Cry aloud and shout, you inhabitant of Zion; for the Holy One of Israel is great among you!”', pt: 'Exulta e canta de gozo, ó habitante de Sião; porque grande é o Santo de Israel no meio de ti.' },
    ],
    13: [
      { v: 1, en: 'The burden of Babylon, which Isaiah the son of Amoz saw.', pt: 'Oráculo acerca de Babilônia, que Isaías, filho de Amoz, recebeu numa visão.' },
      { v: 2, en: 'Set up a banner on the bare mountain! Lift up your voice to them! Wave your hand, that they may go into the gates of the nobles.', pt: 'Alçai uma bandeira sobre o monte escalvado; levantai a voz para eles; acenai-lhes com a mão, para que entrem pelas portas dos príncipes.' },
      { v: 3, en: 'I have commanded my consecrated ones; yes, I have called my mighty men for my anger, even my proudly exulting ones.', pt: 'Eu dei ordens aos meus consagrados; sim, já chamei os meus valentes para executarem a minha ira, os que exultam arrogantemente.' },
      { v: 4, en: 'The noise of a multitude is in the mountains, as of a great people; the noise of an uproar of the kingdoms of the nations gathered together! Yahweh of Armies is mustering the army for the battle.', pt: 'Eis um tumulto sobre os montes, como o de grande multidão! Eis um tumulto de reinos, de nações congregadas! O Senhor dos exércitos passa em revista o exército para a guerra.' },
      { v: 5, en: 'They come from a far country, from the uttermost part of heaven, even Yahweh, and the weapons of his indignation, to destroy the whole land.', pt: 'Vêm duma terra de longe, desde a extremidade do céu, o Senhor e os instrumentos da sua indignação, para destruir toda aquela terra.' },
      { v: 6, en: 'Wail; for the day of Yahweh is at hand! It will come as destruction from the Almighty.', pt: 'Uivai, porque o dia do Senhor está perto; virá do Todo-Poderoso como assolação.' },
      { v: 7, en: 'Therefore all hands will be feeble, and everyone’s heart will melt.', pt: 'Pelo que todas as mãos se debilitarão, e se derreterá o coração de todos os homens.' },
      { v: 8, en: 'They will be dismayed. Pangs and sorrows will seize them. They will be in pain like a woman in labor. They will look in amazement one at another. Their faces will be faces of flame.', pt: 'E ficarão desanimados; e deles se apoderarão dores e ais; e se angustiarão, como a mulher que está de parto; olharão atônitos uns para os outros; os seus rostos serão rostos flamejantes.' },
      { v: 9, en: 'Behold, the day of Yahweh comes, cruel, with wrath and fierce anger; to make the land a desolation, and to destroy its sinners out of it.', pt: 'Eis que o dia do Senhor vem, horrendo, com furor e ira ardente; para pôr a terra em assolação e para destruir do meio dela os seus pecadores.' },
      { v: 10, en: 'For the stars of the sky and its constellations will not give their light. The sun will be darkened in its going out, and the moon will not cause its light to shine.', pt: 'Pois as estrelas do céu e as suas constelações não deixarão brilhar a sua luz; o sol se escurecerá ao nascer, e a lua não fará resplandecer a sua luz.' },
      { v: 11, en: 'I will punish the world for their evil, and the wicked for their iniquity. I will cause the arrogance of the proud to cease, and will humble the haughtiness of the terrible.', pt: 'E visitarei sobre o mundo a sua maldade, e sobre os ímpios a sua iniqüidade; e farei cessar a arrogância dos atrevidos, e abaterei a soberba dos cruéis.' },
      { v: 12, en: 'I will make people more rare than fine gold, even a person than the pure gold of Ophir.', pt: 'Farei que os homens sejam mais raros do que o ouro puro, sim mais raros do que o ouro fino de Ofir.' },
      { v: 13, en: 'Therefore I will make the heavens tremble, and the earth will be shaken out of its place in Yahweh of Armies’ wrath, and in the day of his fierce anger.', pt: 'Pelo que farei estremecer o céu, e a terra se movera do seu lugar, por causa do furor do Senhor dos exércitos, e por causa do dia da sua ardente ira.' },
      { v: 14, en: 'It will happen that like a hunted gazelle, and like sheep that no one gathers, they will each turn to their own people, and will each flee to their own land.', pt: 'E como a corça quando é perseguida, e como a ovelha que ninguém recolhe, assim cada um voltará para o seu povo, e cada um fugirá para a sua terra.' },
      { v: 15, en: 'Everyone who is found will be thrust through. Everyone who is captured will fall by the sword.', pt: 'Todo o que for achado será traspassado; e todo o que for apanhado, cairá à espada.' },
      { v: 16, en: 'Their infants also will be dashed in pieces before their eyes. Their houses will be ransacked, and their wives raped.', pt: 'E suas crianças serão despedaçadas perante os seus olhos; as suas casas serão saqueadas, e as suas mulheres violadas.' },
      { v: 17, en: 'Behold, I will stir up the Medes against them, who will not value silver, and as for gold, they will not delight in it.', pt: 'Eis que suscitarei contra eles os medos, que não farão caso da prata, nem tampouco no ouro terão prazer.' },
      { v: 18, en: 'Their bows will dash the young men in pieces; and they shall have no pity on the fruit of the womb. Their eyes will not spare children.', pt: 'E os seus arcos despedaçarão aos mancebos; e não se compadecerão do fruto do ventre; os seus olhos não pouparão as crianças.' },
      { v: 19, en: 'Babylon, the glory of kingdoms, the beauty of the Chaldeans’ pride, will be like when God overthrew Sodom and Gomorrah.', pt: 'E Babilônia, a glória dos reinos, o esplendor e o orgulho dos caldeus, será como Sodoma e Gomorra, quando Deus as transtornou.' },
      { v: 20, en: 'It will never be inhabited, neither will it be lived in from generation to generation. The Arabian will not pitch a tent there, neither will shepherds make their flocks lie down there.', pt: 'Nunca mais será habitada, nem nela morará alguém de geração em geração; nem o árabe armará ali a sua tenda; nem tampouco os pastores ali farão deitar os seus rebanhos.' },
      { v: 21, en: 'But wild animals of the desert will lie there, and their houses will be full of jackals. Ostriches will dwell there, and wild goats will frolic there.', pt: 'Mas as feras do deserto repousarão ali, e as suas casas se encherão de horríveis animais; e ali habitarão as avestruzes, e os sátiros pularão ali.' },
      { v: 22, en: 'Wolves will cry in their fortresses, and jackals in the pleasant palaces. Her time is near to come, and her days will not be prolonged.', pt: 'As hienas uivarão nos seus castelos, e os chacais nos seus palácios de prazer; bem perto está o seu tempo, e os seus dias não se prolongarão.' },
    ],
    14: [
      { v: 1, en: 'For Yahweh will have compassion on Jacob, and will yet choose Israel, and set them in their own land. The foreigner will join himself with them, and they will unite with the house of Jacob.', pt: 'Pois o Senhor se compadecerá de Jacó, e ainda escolherá a Israel e os porá na sua própria terra; e ajuntar-se-ão com eles os estrangeiros, e se apegarão à casa de Jacó.' },
      { v: 2, en: 'The peoples will take them, and bring them to their place. The house of Israel will possess them in Yahweh’s land for servants and for handmaids. They will take as captives those whose captives they were; and they shall rule over their oppressors.', pt: 'E os povos os receberão, e os levarão aos seus lugares; e a casa de Israel os possuirá por servos e por servas, na terra do Senhor e cativarão aqueles que os cativaram, e dominarão os seus opressores.' },
      { v: 3, en: 'It will happen in the day that Yahweh will give you rest from your sorrow, from your trouble, and from the hard service in which you were made to serve,', pt: 'No dia em que Deus vier a dar-te descanso do teu trabalho, e do teu tremor, e da dura servidão com que te fizeram servir,' },
      { v: 4, en: 'that you will take up this parable against the king of Babylon, and say, “How the oppressor has ceased! The golden city has ceased!”', pt: 'proferirás esta parábola contra o rei de Babilônia, e dirás: Como cessou o opressor! como cessou a tirania!' },
      { v: 5, en: 'Yahweh has broken the staff of the wicked, the scepter of the rulers,', pt: 'Já quebrantou o Senhor o bastão dos ímpios e o cetro dos dominadores;' },
      { v: 6, en: 'who struck the peoples in wrath with a continual stroke, who ruled the nations in anger, with a persecution that no one restrained.', pt: 'cetro que feria os povos com furor, com açoites incessantes, e que em ira dominava as nações com uma perseguição irresistível.' },
      { v: 7, en: 'The whole earth is at rest, and is quiet. They break out in song.', pt: 'Toda a terra descansa, e está sossegada! Rompem em brados de júbilo.' },
      { v: 8, en: 'Yes, the cypress trees rejoice with you, with the cedars of Lebanon, saying, “Since you are humbled, no lumberjack has come up against us.”', pt: 'Até as faias se alegram sobre ti, e os cedros do Líbano, dizendo: Desde que tu caiste ninguém sobe contra nós para nos cortar.' },
      { v: 9, en: 'Sheol from beneath has moved for you to meet you at your coming. It stirs up the departed spirits for you, even all the rulers of the earth. It has raised up from their thrones all the kings of the nations.', pt: 'O Seol desde o profundo se turbou por ti, para sair ao teu encontro na tua vinda; ele despertou por ti os mortos, todos os que eram príncipes da terra, e fez levantar dos seus tronos todos os que eram reis das nações.' },
      { v: 10, en: 'They all will answer and ask you, “Have you also become as weak as we are? Have you become like us?”', pt: 'Estes todos responderão, e te dirão: Tu também estás fraco como nós, e te tornaste semelhante a nós.' },
      { v: 11, en: 'Your pomp is brought down to Sheol, with the sound of your stringed instruments. Maggots are spread out under you, and worms cover you.', pt: 'Está derrubada até o Seol a tua pompa, o som dos teus alaúdes; os bichinhos debaixo de ti se estendem e os bichos te cobrem.' },
      { v: 12, en: 'How you have fallen from heaven, morning star, son of the dawn! How you are cut down to the ground, who laid the nations low!', pt: 'Como caíste do céu, ó estrela da manhã, filha da alva! como foste lançado por terra tu que prostravas as nações!' },
      { v: 13, en: 'You said in your heart, “I will ascend into heaven! I will exalt my throne above the stars of God! I will sit on the mountain of assembly, in the far north!', pt: 'E tu dizias no teu coração: Eu subirei ao céu; acima das estrelas de Deus exaltarei o meu trono; e no monte da congregação me assentarei, nas extremidades do norte;' },
      { v: 14, en: 'I will ascend above the heights of the clouds! I will make myself like the Most High!”', pt: 'subirei acima das alturas das nuvens, e serei semelhante ao Altíssimo.' },
      { v: 15, en: 'Yet you shall be brought down to Sheol, to the depths of the pit.', pt: 'Contudo levado serás ao Seol, ao mais profundo do abismo.' },
      { v: 16, en: 'Those who see you will stare at you. They will ponder you, saying, “Is this the man who made the earth to tremble, who shook kingdoms;', pt: 'Os que te virem te contemplarão, considerar-te-ão, e dirão: É este o varão que fazia estremecer a terra, e que fazia tremer os reinos?' },
      { v: 17, en: 'who made the world like a wilderness, and overthrew its cities; who didn’t release his prisoners to their home?”', pt: 'Que punha o mundo como um deserto, e assolava as suas cidades? que a seus cativos não deixava ir soltos para suas casas?' },
      { v: 18, en: 'All the kings of the nations, sleep in glory, everyone in his own house.', pt: 'Todos os reis das nações, todos eles, dormem com glória, cada um no seu túmulo.' },
      { v: 19, en: 'But you are cast away from your tomb like an abominable branch, clothed with the slain, who are thrust through with the sword, who go down to the stones of the pit; like a dead body trodden under foot.', pt: 'Mas tu és lançado da tua sepultura, como um renovo abominável, coberto de mortos atravessados a espada, como os que descem às pedras da cova, como cadáver pisado aos pés.' },
      { v: 20, en: 'You will not join them in burial, because you have destroyed your land. You have killed your people. The offspring of evildoers will not be named forever.', pt: 'Com eles não te reunirás na sepultura; porque destruíste a tua terra e mataste o teu povo. Que a descendência dos malignos não seja nomeada para sempre!' },
      { v: 21, en: 'Prepare for slaughter of his children because of the iniquity of their fathers, that they not rise up and possess the earth, and fill the surface of the world with cities.', pt: 'Preparai a matança para os filhos por causa da maldade de seus pais, para que não se levantem, e possuam a terra, e encham o mundo de cidades.' },
      { v: 22, en: '“I will rise up against them,” says Yahweh of Armies, “and cut off from Babylon name and remnant, and son and son’s son,” says Yahweh.', pt: 'Levantar-me-ei contra eles, diz o Senhor dos exércitos, e exterminarei de Babilônia o nome, e os sobreviventes, o filho, e o neto, diz o Senhor.' },
      { v: 23, en: '“I will also make it a possession for the porcupine, and pools of water. I will sweep it with the broom of destruction,” says Yahweh of Armies.', pt: 'E reduzi-la-ei a uma possessão do ouriço, e a lagoas de águas; e varrê-la-ei com a vassoura da destruição, diz o Senhor dos exércitos.' },
      { v: 24, en: 'Yahweh of Armies has sworn, saying, “Surely, as I have thought, so shall it happen; and as I have purposed, so shall it stand:', pt: 'O Senhor dos exércitos jurou, dizendo: Como pensei, assim sucederá, e como determinei, assim se efetuará.' },
      { v: 25, en: 'that I will break the Assyrian in my land, and tread him under foot on my mountains. Then his yoke will leave them, and his burden leave their shoulders.', pt: 'Quebrantarei o assírio na minha terra e nas minhas montanhas o pisarei; então o seu jugo se apartará deles e a sua carga se desviará dos seus ombros.' },
      { v: 26, en: 'This is the plan that is determined for the whole earth. This is the hand that is stretched out over all the nations.', pt: 'Este é o conselho que foi determinado sobre toda a terra; e esta é a mão que está estendida sobre todas as nações.' },
      { v: 27, en: 'For Yahweh of Armies has planned, and who can stop it? His hand is stretched out, and who can turn it back?”', pt: 'Pois o Senhor dos exércitos o determinou, e quem o invalidará? A sua mão estendida está, e quem a fará voltar atrás?' },
      { v: 28, en: 'This burden was in the year that king Ahaz died.', pt: 'No ano em que morreu o rei Acaz, veio este oráculo.' },
      { v: 29, en: 'Don’t rejoice, O Philistia, all of you, because the rod that struck you is broken; for out of the serpent’s root an adder will emerge, and his fruit will be a fiery flying serpent.', pt: 'Não te alegres, ó Filístia toda, por ser quebrada a vara que te feria; porque da raiz da cobra sairá um basilisco, e o seu fruto será uma serpente voadora.' },
      { v: 30, en: 'The firstborn of the poor will eat, and the needy will lie down in safety; and I will kill your root with famine, and your remnant will be killed.', pt: 'E os primogênitos dos pobres serão apascentados, e os necessitados se deitarão seguros; mas farei morrer de fome a tua raiz, e será destruído o teu restante.' },
      { v: 31, en: 'Howl, gate! Cry, city! You are melted away, Philistia, all of you; for smoke comes out of the north, and there is no straggler in his ranks.', pt: 'Uiva, ó porta; grita, ó cidade; tu, ó Filístia, estás toda derretida; porque do norte vem fumaça; e não há vacilante nas suas fileiras.' },
      { v: 32, en: 'What will they answer the messengers of the nation? That Yahweh has founded Zion, and in her the afflicted of his people will take refuge.', pt: 'Que se responderá pois aos mensageiros do povo? Que o Senhor fundou a Sião, e que nela acharão refúgio os aflitos do seu povo.' },
    ],
    15: [
      { v: 1, en: 'The burden of Moab. For in a night, Ar of Moab is laid waste, and brought to nothing. For in a night Kir of Moab is laid waste, and brought to nothing.', pt: 'Oráculo acerca de Moabe. Porque Ar foi destruída numa noite, Moabe está desfeita; porque Quir foi destruída numa noite, Moabe está desfeita.' },
      { v: 2, en: 'They have gone up to Bayith, and to Dibon, to the high places, to weep. Moab wails over Nebo and over Medeba. Baldness is on all of their heads. Every beard is cut off.', pt: 'Subiu a filha de Dibom aos altos para chorar; por Nebo e por Medeba pranteia Moabe; em todas as cabeças há calva, e toda barba é rapada.' },
      { v: 3, en: 'In their streets, they clothe themselves in sackcloth. In their streets and on their housetops, everyone wails, weeping abundantly.', pt: 'Nas suas ruas cingem-se de saco; nos seus terraços e nas suas praças todos andam pranteando, e choram abundantemente.' },
      { v: 4, en: 'Heshbon cries out with Elealeh. Their voice is heard even to Jahaz. Therefore the armed men of Moab cry aloud. Their souls tremble within them.', pt: 'Assim Hesbom como Eleale andam gritando; até Jaaz se ouve a sua voz; por isso os armados de Moabe clamam; estremece-lhes a alma.' },
      { v: 5, en: 'My heart cries out for Moab! Her nobles flee to Zoar, to Eglath Shelishiyah; for they go up by the ascent of Luhith with weeping; for on the way to Horonaim, they raise up a cry of destruction.', pt: 'O meu coração clama por causa de Moabe; fogem os seus nobres para Zoar, qual uma novilha de três anos; pois vão chorando pela encosta de Luíte; no caminho de Horonaim levantam um grito de destruição.' },
      { v: 6, en: 'For the waters of Nimrim will be desolate; for the grass has withered away, the tender grass fails, there is no green thing.', pt: 'As águas de Ninrim são desoladas; secou-se a relva, definhou a erva verde, e não há verdura alguma.' },
      { v: 7, en: 'Therefore they will carry away the abundance they have gotten, and that which they have stored up, over the brook of the willows.', pt: 'Pelo que a abundância que ajuntaram, e o que guardaram, para além do ribeiro dos salgueiros o levam.' },
      { v: 8, en: 'For the cry has gone around the borders of Moab; its wailing to Eglaim, and its wailing to Beer Elim.', pt: 'Pois o pranto já rodeou os limites de Moabe; até Eglaim chegou o seu clamor, e ainda até Beer-Elim o seu rugido.' },
      { v: 9, en: 'For the waters of Dimon are full of blood; for I will bring yet more on Dimon, a lion on those of Moab who escape, and on the remnant of the land.', pt: 'Pois as águas de Dimom estão cheias de sangue; pelo que ainda acrescentarei mais a Dimom, um leão contra aqueles que escaparem de Moabe, e contra o restante que ficou na terra.' },
    ],
    16: [
      { v: 1, en: 'Send the lambs for the ruler of the land from Selah to the wilderness, to the mountain of the daughter of Zion.', pt: 'Enviaram cordeiros ao governador da terra, desde Sela, pelo deserto, até o monte da filha de Sião.' },
      { v: 2, en: 'For it will be that as wandering birds, as a scattered nest, so will the daughters of Moab be at the fords of the Arnon.', pt: 'Pois como pássaros que vagueiam, como ninhada dispersa, assim são as filhas de Moabe junto aos vaus do Arnom.' },
      { v: 3, en: 'Give counsel! Execute justice! Make your shade like the night in the middle of the noonday! Hide the outcasts! Don’t betray the fugitive!', pt: 'Dá conselhos, executa juízo; põe a tua sombra como a noite ao pino do meio-dia; esconde os desterrados, e não traias o fugitivo.' },
      { v: 4, en: 'Let my outcasts dwell with you! As for Moab, be a hiding place for him from the face of the destroyer. For the extortionist is brought to nothing. Destruction ceases. The oppressors are consumed out of the land.', pt: 'Habitem entre vós os desterrados de Moabe; serve-lhes de refúgio perante a face do destruidor. Quando o homem violento tiver fim, e a destruição tiver cessado, havendo os opressores desaparecido de sobre a terra,' },
      { v: 5, en: 'A throne will be established in loving kindness. One will sit on it in truth, in the tent of David, judging, seeking justice, and swift to do righteousness.', pt: 'então um trono será estabelecido em benignidade, e sobre ele no tabernáculo de Davi se assentará em verdade um que julgue, e que procure a justiça e se apresse a praticar a retidão.' },
      { v: 6, en: 'We have heard of the pride of Moab, that he is very proud; even of his arrogance, his pride, and his wrath. His boastings are nothing.', pt: 'Ouvimos da soberba de Moabe, a soberbíssima; da sua arrogância, da sua soberba, e da sua insolência; de nada valem as suas jactâncias.' },
      { v: 7, en: 'Therefore Moab will wail for Moab. Everyone will wail. You will mourn for the raisin cakes of Kir Hareseth, utterly stricken.', pt: 'portanto Moabe pranteará; prantearão todos por Moabe; pelos bolos de passas de Quir-Haresete suspirareis, inteiramente desanimados.' },
      { v: 8, en: 'For the fields of Heshbon languish with the vine of Sibmah. The lords of the nations have broken down its choice branches, which reached even to Jazer, which wandered into the wilderness. Its shoots were spread abroad. They passed over the sea.', pt: 'porque os campos de Hesbom enfraqueceram, e a vinha de Sibma; os senhores des nações derrubaram os seus ramos, que chegaram a Jazer e penetraram no deserto; os seus rebentos se estenderam e passaram além do mar.' },
      { v: 9, en: 'Therefore I will weep with the weeping of Jazer for the vine of Sibmah. I will water you with my tears, Heshbon, and Elealeh: for on your summer fruits and on your harvest the battle shout has fallen.', pt: 'Pelo que prantearei, com o pranto de Jazer, a vinha de Sibma; regar-te-ei com as minhas lágrimas, ó Hesbom e Eleale; porque sobre os teus frutos de verão e sobre a tua sega caiu o grito da batalha.' },
      { v: 10, en: 'Gladness is taken away, and joy out of the fruitful field; and in the vineyards there will be no singing, neither joyful noise. Nobody will tread out wine in the presses. I have made the shouting stop.', pt: 'A alegria e o regozijo são tirados do fértil campo, e nas vinhas não se canta, nem há júbilo algum; já não se pisam as uvas nos lagares. Eu fiz cessar os gritos da vindima.' },
      { v: 11, en: 'Therefore my heart sounds like a harp for Moab, and my inward parts for Kir Heres.', pt: 'Pelo que minha alma lamenta por Moabe como harpa, e o meu íntimo por Quir-Heres.' },
      { v: 12, en: 'It will happen that when Moab presents himself, when he wearies himself on the high place, and comes to his sanctuary to pray, that he will not prevail.', pt: 'E será que, quando Moabe se apresentar, quando se cansar nos altos, e entrar no seu santuário a orar, nada alcançará.' },
      { v: 13, en: 'This is the word that Yahweh spoke concerning Moab in time past.', pt: 'Essa é a palavra que o Senhor falou no passado acerca de Moabe.' },
      { v: 14, en: 'But now Yahweh has spoken, saying, “Within three years, as a worker bound by contract would count them, the glory of Moab shall be brought into contempt, with all his great multitude; and the remnant will be very small and feeble.”', pt: 'Mas agora diz o Senhor: Dentro de três anos, tais como os anos do jornaleiro, será envilecida a glória de Moabe, juntamente com toda a sua grande multidão; e os que lhe restarem serão poucos e débeis.' },
    ],
    17: [
      { v: 1, en: 'The burden of Damascus. “Behold, Damascus is taken away from being a city, and it will be a ruinous heap.', pt: 'Oráculo acerca de Damasco. Eis que Damasco será tirada, para não mais ser cidade, e se tornará um montão de ruínas.' },
      { v: 2, en: 'The cities of Aroer are forsaken. They will be for flocks, which shall lie down, and no one shall make them afraid.', pt: 'As cidades de Aroer serão abandonadas; hão de ser para os rebanhos, que se deitarão sem haver quem os espante.' },
      { v: 3, en: 'The fortress shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria. They will be as the glory of the children of Israel,” says Yahweh of Armies.', pt: 'E a fortaleza de Efraim cessará, como também o reino de Damasco e o resto da Síria; serão como a glória dos filhos de Israel, diz o Senhor dos exércitos.' },
      { v: 4, en: '“It will happen in that day that the glory of Jacob will be made thin, and the fatness of his flesh will become lean.', pt: 'E será diminuída naquele dia a glória de Jacó, e a gordura da sua carne desaparecerá.' },
      { v: 5, en: 'It will be like when the harvester gathers the wheat, and his arm reaps the grain. Yes, it will be like when one gleans grain in the valley of Rephaim.', pt: 'E será como o segador que colhe o trigo, e que com o seu braço sega as espigas; sim, será como quando alguém colhe espigas no vale de Refaim.' },
      { v: 6, en: 'Yet gleanings will be left there, like the shaking of an olive tree, two or three olives in the top of the uppermost bough, four or five in the outermost branches of a fruitful tree,” says Yahweh, the God of Israel.', pt: 'Mas ainda ficarão nele alguns rabiscos, como no sacudir da oliveira: duas ou três azeitonas na mais alta ponta dos ramos, e quatro ou cinco nos ramos mais exteriores de uma árvore frutífera, diz o Senhor Deus de Israel.' },
      { v: 7, en: 'In that day, people will look to their Maker, and their eyes will have respect for the Holy One of Israel.', pt: 'Naquele dia atentará o homem para o seu Criador, e os seus olhos olharão para o Santo de Israel.' },
      { v: 8, en: 'They will not look to the altars, the work of their hands; neither shall they respect that which their fingers have made, either the Asherah poles, or the incense altars.', pt: 'E não atentará para os altares, obra das suas mãos; nem olhará para o que fizeram seus dedos, para os aserins e para os altares do incenso.' },
      { v: 9, en: 'In that day, their strong cities will be like the forsaken places in the woods and on the mountain top, which were forsaken from before the children of Israel; and it will be a desolation.', pt: 'Naquele dia as suas cidades fortificadas serão como os lugares abandonados no bosque ou sobre o cume das montanhas, os quais foram abandonados ante os filhos de Israel; e haverá assolação.' },
      { v: 10, en: 'For you have forgotten the God of your salvation, and have not remembered the rock of your strength. Therefore you plant pleasant plants, and set out foreign seedlings.', pt: 'Porquanto te esqueceste do Deus da tua salvação, e não te lembraste da rocha da tua fortaleza; por isso, ainda que faças plantações deleitosas e ponhas nelas sarmentos de uma vide estranha,' },
      { v: 11, en: 'In the day of your planting, you hedge it in. In the morning, you make your seed blossom, but the harvest flees away in the day of grief and of desperate sorrow.', pt: 'e as faças crescer no dia em que as plantares, e florescer na manhã desse dia, a colheita voará no dia da tribulação e das dores insofríveis.' },
      { v: 12, en: 'Ah, the uproar of many peoples, who roar like the roaring of the seas; and the rushing of nations, that rush like the rushing of mighty waters!', pt: 'Ai do bramido de muitos povos que bramam como o bramido dos mares; e do rugido das nações que rugem como o rugido de impetuosas águas.' },
      { v: 13, en: 'The nations will rush like the rushing of many waters: but he will rebuke them, and they will flee far off, and will be chased like the chaff of the mountains before the wind, and like the whirling dust before the storm.', pt: 'Rugem as nações, como rugem as muitas águas; mas Deus as repreenderá, e elas fugirão para longe; e serão afugentadas como a pragana dos montes diante do vento e como a poeira num redemoinho diante do tufão.' },
      { v: 14, en: 'At evening, behold, terror! Before the morning, they are no more. This is the portion of those who plunder us, and the lot of those who rob us.', pt: 'Ao anoitecer, eis o terror! e antes que amanheça eles já não existem. Esse é o quinhão daqueles que nos despojam, e a sorte daqueles que nos saqueiam.' },
    ],
    18: [
      { v: 1, en: 'Ah, the land of the rustling of wings, which is beyond the rivers of Ethiopia;', pt: 'Ai da terra do roçar das asas, que está além dos rios da Etiópia;' },
      { v: 2, en: 'that sends ambassadors by the sea, even in vessels of papyrus on the waters, saying, “Go, you swift messengers, to a nation tall and smooth, to a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide!”', pt: 'que envia embaixadores por mar em navios de junco sobre as águas, dizendo: Ide, mensageiros velozes, a um povo de alta estatura e de tez luzidia, a um povo terrível desde o seu princípio, a uma nação forte e vitoriosa, cuja terra os rios dividem!' },
      { v: 3, en: 'All you inhabitants of the world, and you dwellers on the earth, when a banner is lifted up on the mountains, look! When the trumpet is blown, listen!', pt: 'Vede, todos vós, habitantes do mundo, e vós os moradores da terra, quando se arvorar a bandeira nos montes; e ouvi, quando se tocar a trombeta.' },
      { v: 4, en: 'For Yahweh said to me, “I will be still, and I will see in my dwelling place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.”', pt: 'Pois assim me disse o Senhor: estarei quieto, olhando desde a minha morada, como o ardor do sol resplandecente, como a nuvem do orvalho no calor da sega.' },
      { v: 5, en: 'For before the harvest, when the blossom is over, and the flower becomes a ripening grape, he will cut off the sprigs with pruning hooks, and he will cut down and take away the spreading branches.', pt: 'Pois antes da sega, quando acaba a flor e o gomo se torna uva prestes a amadurecer, ele cortará com foices os sarmentos e tirará os ramos, e os lançará fora.' },
      { v: 6, en: 'They will be left together for the ravenous birds of the mountains, and for the animals of the earth. The ravenous birds will summer on them, and all the animals of the earth will winter on them.', pt: 'Serão deixados juntos para as aves dos montes e os animais da terra; e sobre eles veranearão as aves de rapina, e todos os animais da terra invernarão sobre eles.' },
      { v: 7, en: 'In that time, a present will be brought to Yahweh of Armies from a people tall and smooth, even from a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide, to the place of the name of Yahweh of Armies, Mount Zion.', pt: 'Naquele tempo será levado um presente ao Senhor dos exércitos da parte dum povo alto e de tez luzidia, e dum povo terrível desde o seu princípio, uma nação forte e vitoriosa, cuja terra os rios dividem; um presente, sim, será levado ao lugar do nome do Senhor dos exércitos, ao monte Sião.' },
    ],
    19: [
      { v: 1, en: 'The burden of Egypt. “Behold, Yahweh rides on a swift cloud, and comes to Egypt. The idols of Egypt will tremble at his presence; and the heart of Egypt will melt within it.', pt: 'Profecia acerca do Egito. Eis que o Senhor vem cavalgando numa nuvem ligeira, e entra no Egito; e os ídolos do Egito estremecerão diante dele, e o coração dos egípcios se derreterá dentro de si.' },
      { v: 2, en: 'I will stir up the Egyptians against the Egyptians, and they will fight everyone against his brother, and everyone against his neighbor; city against city, and kingdom against kingdom.', pt: 'Incitarei egípcios contra egípcios; e cada um pelejará contra o seu irmão, e cada um contra o seu próximo, cidade contra cidade, reino contra reino.' },
      { v: 3, en: 'The spirit of Egypt will fail within it. I will destroy its counsel. They will seek the idols, the charmers, those who have familiar spirits, and the wizards.', pt: 'E o espírito dos egípcios se esvaecerá dentro deles; eu destruirei o seu conselho; e eles consultarão os seus ídolos, e encantadores, e necromantes e feiticeiros.' },
      { v: 4, en: 'I will give over the Egyptians into the hand of a cruel lord. A fierce king will rule over them,” says the Lord, Yahweh of Armies.', pt: 'Pelo que entregarei os egípcios nas mãos de um senhor duro; e um rei rigoroso os dominará, diz o Senhor Deus dos exércitos.' },
      { v: 5, en: 'The waters will fail from the sea, and the river will be wasted and become dry.', pt: 'e as águas do Nilo minguarão, e o rio se esgotará e secará.' },
      { v: 6, en: 'The rivers will become foul. The streams of Egypt will be diminished and dried up. The reeds and flags will wither away.', pt: 'Também os rios exalarão um fedor; diminuirão e secarão os canais do Egito; as canas e os juncos murcharão.' },
      { v: 7, en: 'The meadows by the Nile, by the brink of the Nile, and all the sown fields of the Nile, will become dry, be driven away, and be no more.', pt: 'Os prados junto ao Nilo, ao longo das suas margens, sim, tudo o que foi semeado junto dele secará, será arrancado, e deixará de existir.' },
      { v: 8, en: 'The fishermen will lament, and all those who fish in the Nile will mourn, and those who spread nets on the waters will languish.', pt: 'E os pescadores gemerão, e lamentarão todos os que lançam anzol ao Nilo, e desfalecerão os que estendem rede sobre as águas.' },
      { v: 9, en: 'Moreover those who work in combed flax, and those who weave white cloth, will be confounded.', pt: 'Envergonhar-se-ão os que trabalham em linho fino, e os que tecem pano branco.' },
      { v: 10, en: 'The pillars will be broken in pieces. All those who work for hire will be grieved in soul.', pt: 'E os que são as colunas do Egito serão esmagados, e todos os que trabalham, por salário serão entristecidos.' },
      { v: 11, en: 'The princes of Zoan are utterly foolish. The counsel of the wisest counselors of Pharaoh has become stupid. How do you say to Pharaoh, “I am the son of the wise, the son of ancient kings?”', pt: 'Na verdade estultos são os príncipes de Zoã; o conselho dos mais sábios conselheiros de Faraó se embruteceu. Como pois a Faraó direis: Sou filho de sábios, filho de reis antigos?' },
      { v: 12, en: 'Where then are your wise men? Let them tell you now; and let them know what Yahweh of Armies has purposed concerning Egypt.', pt: 'Onde estão agora os teus sábios? anunciem-te agora, e te façam saber o que o Senhor dos exércitos determinou contra o Egito.' },
      { v: 13, en: 'The princes of Zoan have become fools. The princes of Memphis are deceived. They have caused Egypt to go astray, who are the cornerstone of her tribes.', pt: 'Estultos tornaram-se os príncipes de Zoã, enganados estão os príncipes de Mênfis; fizeram errar o Egito, os que são a pedra de esquina das suas tribos.' },
      { v: 14, en: 'Yahweh has mixed a spirit of perverseness in the middle of her; and they have caused Egypt to go astray in all of its works, like a drunken man staggers in his vomit.', pt: 'O Senhor derramou no meio deles um espírito de confusão; e eles fizeram errar o Egito em todas as suas obras, como o bêbedo vai cambaleando no seu vômito.' },
      { v: 15, en: 'Neither shall there be any work for Egypt, which head or tail, palm branch or rush, may do.', pt: 'E não haverá para o Egito coisa alguma que possa fazer cabeça ou cauda, ramo ou junco.' },
      { v: 16, en: 'In that day the Egyptians will be like women. They will tremble and fear because of the shaking of Yahweh of Armies’s hand, which he shakes over them.', pt: 'Naquele dia os egípcios serão como mulheres, e tremerão e temerão por vibrar o Senhor dos exércitos a sua mão contra eles.' },
      { v: 17, en: 'The land of Judah will become a terror to Egypt. Everyone to whom mention is made of it will be afraid, because of the plans of Yahweh of Armies, which he determines against it.', pt: 'E a terra de Judá será um espanto para o Egito; todo aquele a quem isso se anunciar se assombrará, por causa do propósito que o Senhor dos exércitos determinou contra eles.' },
      { v: 18, en: 'In that day, there will be five cities in the land of Egypt that speak the language of Canaan, and swear to Yahweh of Armies. One will be called “The city of destruction.”', pt: 'Naquele dia haverá cinco cidades na terra do Egito que falem a língua de Canaã e façam juramento ao Senhor dos exércitos. Uma destas se chamará Cidade de destruição.' },
      { v: 19, en: 'In that day, there will be an altar to Yahweh in the middle of the land of Egypt, and a pillar to Yahweh at its border.', pt: 'Naquele dia haverá um altar dedicado ao Senhor no meio da terra do Egito, e uma coluna se erigirá ao Senhor, na sua fronteira.' },
      { v: 20, en: 'It will be for a sign and for a witness to Yahweh of Armies in the land of Egypt; for they will cry to Yahweh because of oppressors, and he will send them a savior and a defender, and he will deliver them.', pt: 'E servirá isso de sinal e de testemunho ao Senhor dos exércitos na terra do Egito; quando clamarem ao Senhor por causa dos opressores, ele lhes enviará um salvador, que os defenderá e os livrará.' },
      { v: 21, en: 'Yahweh will be known to Egypt, and the Egyptians will know Yahweh in that day. Yes, they will worship with sacrifice and offering, and will vow a vow to Yahweh, and will perform it.', pt: 'E o Senhor se dará a conhecer ao Egito e os egípcios conhecerão ao Senhor naquele dia, e o adorarão com sacrifícios e ofertas, e farão votos ao Senhor, e os cumprirão.' },
      { v: 22, en: 'Yahweh will strike Egypt, striking and healing. They will return to Yahweh, and he will be entreated by them, and will heal them.', pt: 'E ferirá o Senhor aos egípcios; feri-los-á, mas também os curará; e eles se voltarão para o Senhor, que ouvirá as súplicas deles e os curará.' },
      { v: 23, en: 'In that day there will be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and the Egyptians will worship with the Assyrians.', pt: 'Naquele dia haverá estrada do Egito até a Assíria, e os assírios virão ao Egito, e os egípcios irão à Assíria; e os egípcios adorarão com os assírios.' },
      { v: 24, en: 'In that day, Israel will be the third with Egypt and with Assyria, a blessing within the earth;', pt: 'Naquele dia Israel será o terceiro com os egipcios e os assirios, uma benção no meio da terra;' },
      { v: 25, en: 'because Yahweh of Armies has blessed them, saying, “Blessed be Egypt my people, Assyria the work of my hands, and Israel my inheritance.”', pt: 'porquanto o Senhor dos exércitos os tem abençoado, dizendo: Bem-aventurado seja o Egito, meu povo, e a Assíria, obra de minhas mãos, e Israel, minha herança.' },
    ],
    20: [
      { v: 1, en: 'In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;', pt: 'No ano em que Tartã, enviado por Sargão, rei da Assíria, veio a Asdode, e guerreou contra Asdode, e a tomou;' },
      { v: 2, en: 'at that time Yahweh spoke by Isaiah the son of Amoz, saying, “Go, and loosen the sackcloth from off your waist, and take your shoes from off your feet.” He did so, walking naked and barefoot.', pt: 'falou o Senhor, naquele tempo, por intermédio de Isaías, filho de Amoz, dizendo: Vai, solta o cilício de teus lombos, e descalça os sapatos dos teus pés. E ele assim o fez, andando nu e descalço.' },
      { v: 3, en: 'Yahweh said, “As my servant Isaiah has walked naked and barefoot three years for a sign and a wonder concerning Egypt and concerning Ethiopia,', pt: 'Então disse o Senhor: Assim como o meu servo Isaías andou três anos nu e descalço, por sinal e portento contra o Egito e contra a Etiópia,' },
      { v: 4, en: 'so the king of Assyria will lead away the captives of Egypt and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.', pt: 'assim o rei da Assíria levará em cativeiro os presos do Egito, e os exilados da Etiópia, tanto moços como velhos, nus e descalços, e com as nádegas descobertas, para vergonha do Egito.' },
      { v: 5, en: 'They will be dismayed and confounded, because of Ethiopia their expectation, and of Egypt their glory.', pt: 'E assombrar-se-ão, e envergonhar-se-ão por causa da Etiopia, sua esperança, e do Egito, sua glória.' },
      { v: 6, en: 'The inhabitants of this coast land will say in that day, ‘Behold, this is our expectation, where we fled for help to be delivered from the king of Assyria. And we, how will we escape?’”', pt: 'Então os moradores desta região litorânea dirão naquele dia: Vede que tal é a nossa esperança, aquilo que buscamos por socorro, para nos livrarmos do rei da Assíria! Como pois escaparemos nós?' },
    ],
    21: [
      { v: 1, en: 'The burden of the wilderness of the sea. As whirlwinds in the South sweep through, it comes from the wilderness, from an awesome land.', pt: 'Oráculo acerca do deserto do mar. Como os tufões de vento do sul, que tudo assolam, aí vem do deserto, duma terra horrível.' },
      { v: 2, en: 'A grievous vision is declared to me. The treacherous man deals treacherously, and the destroyer destroys. Go up, Elam; attack! I have stopped all of Media’s sighing.', pt: 'Dura visão me foi manifesta: o pérfido trata perfidamente, e o destruidor anda destruindo. Sobe, ó Elão, sitia, ó Média; já fiz cessar todo o seu gemido.' },
      { v: 3, en: 'Therefore my thighs are filled with anguish. Pains have taken hold on me, like the pains of a woman in labor. I am in so much pain that I can’t hear. I so am dismayed that I can’t see.', pt: 'Pelo que os meus lombos estão cheios de angústia; dores apoderaram-se de mim como as dores de mulher na hora do parto; estou tão atribulado que não posso ouvir, e tão desfalecido que não posso ver.' },
      { v: 4, en: 'My heart flutters. Horror has frightened me. The twilight that I desired has been turned into trembling for me.', pt: 'O meu coração se agita, o horror apavora-me; o crepúsculo, que desejava, tem-se-me tornado em tremores.' },
      { v: 5, en: 'They prepare the table. They set the watch. They eat. They drink. Rise up, you princes, oil the shield!', pt: 'Eles põem a mesa, estendem os tapetes, comem, bebem. Levantai-vos, príncipes, e ungi o escudo.' },
      { v: 6, en: 'For the Lord said to me, “Go, set a watchman. Let him declare what he sees.', pt: 'Porque assim me disse o Senhor: Vai, põe uma sentinela; e ela que diga o que vir.' },
      { v: 7, en: 'When he sees a troop, horsemen in pairs, a troop of donkeys, a troop of camels, he shall listen diligently with great attentiveness.”', pt: 'Quando vir uma tropa de cavaleiros de dois a dois, uma tropa de jumentos, ou uma tropa de camelos, escute a sentinela atentamente com grande cuidado.' },
      { v: 8, en: 'He cried like a lion: “Lord, I stand continually on the watchtower in the daytime, and every night I stay at my post.', pt: 'Então clamou aquele que viu: Senhor, sobre a torre de vigia estou em pé continuamente de dia, e de guarda me ponho todas as noites.' },
      { v: 9, en: 'Behold, here comes a troop of men, horsemen in pairs.” He answered, “Fallen, fallen is Babylon; and all the engraved images of her gods are broken to the ground.', pt: 'E eis aqui agora vem uma tropa de homens, cavaleiros de dois a dois. Então ele respondeu e disse: Caiu, caiu Babilônia; e todas as imagens esculpidas de seus deuses são despedaçadas até o chão.' },
      { v: 10, en: 'You are my threshing, and the grain of my floor!” That which I have heard from Yahweh of Armies, the God of Israel, I have declared to you.', pt: 'Ah, malhada minha, e trigo da minha eira! o que ouvi do Senhor dos exércitos, Deus de Israel, isso vos tenho anunciado.' },
      { v: 11, en: 'The burden of Dumah. One calls to me out of Seir, “Watchman, what of the night? Watchman, what of the night?”', pt: 'Oráculo acerca de Dumá. Alguém clama a mim de Seir: Guarda, que horas são da noite? guarda, que horas são da noite?' },
      { v: 12, en: 'The watchman said, “The morning comes, and also the night. If you will inquire, inquire. Come back again.”', pt: 'Respondeu o guarda: Vem a manhã, e também a noite; se quereis perguntar, perguntai; voltai, vinde.' },
      { v: 13, en: 'The burden on Arabia. In the forest in Arabia you will lodge, you caravans of Dedanites.', pt: 'Oráculo contra a Arábia. Nos bosques da Arábia passareis a noite, ó caravanas de dedanitas.' },
      { v: 14, en: 'They brought water to him who was thirsty. The inhabitants of the land of Tema met the fugitives with their bread.', pt: 'Saí com água ao encontro dos sedentos; ó moradores da terra de Tema, saí com pão ao encontro dos fugitivos.' },
      { v: 15, en: 'For they fled away from the swords, from the drawn sword, from the bent bow, and from the heat of battle.', pt: 'pois fogem diante das espadas, diante da espada desembainhada, e diante do arco armado, e diante da pressão da guerra.' },
      { v: 16, en: 'For the Lord said to me, “Within a year, as a worker bound by contract would count it, all the glory of Kedar will fail,', pt: 'porque assim me disse o Senhor: Dentro de um ano, tal como os anos de jornaleiro, toda a glória de Quedar esvaecerá.' },
      { v: 17, en: 'and the residue of the number of the archers, the mighty men of the children of Kedar, will be few; for Yahweh, the God of Israel, has spoken it.”', pt: 'e os restantes do número dos flecheiros, os valentes dos filhos de Quedar, serão diminuídos; porque assim o disse o Senhor, Deus de Israel.' },
    ],
    22: [
      { v: 1, en: 'The burden of the valley of vision. What ails you now, that you have all gone up to the housetops?', pt: 'Oráculo acerca do vale da visão. Que tens agora, pois que com todos os teus subiste aos telhados?' },
      { v: 2, en: 'You that are full of shouting, a tumultuous city, a joyous town; your slain are not slain with the sword, neither are they dead in battle.', pt: 'e tu que estás cheia de clamor, cidade turbulenta, cidade alegre; os teus mortos não são mortos à espada, nem mortos em guerra.' },
      { v: 3, en: 'All your rulers fled away together. They were bound by the archers. All who were found by you were bound together. They fled far away.', pt: 'Todos os teus homens principais juntamente fugiram, sem o arco foram presos; todos os que em ti se acharam, foram presos juntamente, embora tivessem fugido para longe.' },
      { v: 4, en: 'Therefore I said, “Look away from me. I will weep bitterly. Don’t labor to comfort me for the destruction of the daughter of my people.', pt: 'Portanto digo: Desviai de mim a vista, e chorarei amargamente; não vos canseis mais em consolar-me pela destruição da filha do meu povo.' },
      { v: 5, en: 'For it is a day of confusion, and of treading down, and of perplexity, from the Lord, Yahweh of Armies, in the valley of vision; a breaking down of the walls, and a crying to the mountains.”', pt: 'Porque dia de destroço, de atropelamento, e de confusão é este da parte do Senhor Deus dos exércitos, no vale da visão; um derrubar de muros, e um clamor até as montanhas.' },
      { v: 6, en: 'Elam carried his quiver, with chariots of men and horsemen; and Kir uncovered the shield.', pt: 'Elão tomou a aljava, juntamente com carros e cavaleiros, e Quir descobriu os escudos.' },
      { v: 7, en: 'Your choicest valleys were full of chariots, and the horsemen set themselves in array at the gate.', pt: 'Os teus mais formosos vales ficaram cheios de carros, e os cavaleiros postaram-se contra as portas.' },
      { v: 8, en: 'He took away the covering of Judah; and you looked in that day to the armor in the house of the forest.', pt: 'Tirou-se a cobertura de Judá; e naquele dia olhaste para as armas da casa do bosque.' },
      { v: 9, en: 'You saw the breaches of David’s city, that they were many; and you gathered together the waters of the lower pool.', pt: 'E vistes que as brechas da cidade de Davi eram muitas; e ajuntastes as águas da piscina de baixo;' },
      { v: 10, en: 'You counted the houses of Jerusalem, and you broke down the houses to fortify the wall.', pt: 'e contastes as casas de Jerusalém, e derrubastes as casas, para fortalecer os muros;' },
      { v: 11, en: 'You also made a reservoir between the two walls for the water of the old pool. But you didn’t look to him who had done this, neither did you have respect for him who purposed it long ago.', pt: 'fizestes também um reservatório entre os dois muros para as águas da piscina velha; mas não olhastes para aquele que o tinha feito, nem considerastes o que o formou desde a antiguidade.' },
      { v: 12, en: 'In that day, the Lord, Yahweh of Armies, called to weeping, and to mourning, and to baldness, and to dressing in sackcloth:', pt: 'O Senhor Deus dos exércitos vos convidou naquele dia para chorar e prantear, para rapar a cabeça e cingir o cilício;' },
      { v: 13, en: 'and behold, joy and gladness, killing cattle and killing sheep, eating meat and drinking wine: “Let us eat and drink, for tomorrow we will die.”', pt: 'mas eis aqui gozo e alegria; matam-se bois, degolam-se ovelhas, come-se carne, bebe-se vinho, e se diz: Comamos e bebamos, porque amanhã morreremos.' },
      { v: 14, en: 'Yahweh of Armies revealed himself in my ears, “Surely this iniquity will not be forgiven you until you die,” says the Lord, Yahweh of Armies.', pt: 'Mas o Senhor dos exércitos revelou-se aos meus ouvidos, dizendo: Certamente esta maldade não se vos perdoará até que morrais, diz o Senhor Deus dos exércitos.' },
      { v: 15, en: 'Thus says the Lord, Yahweh of Armies, “Go, get yourself to this treasurer, even to Shebna, who is over the house, and say,', pt: 'Assim diz o Senhor Deus dos exércitos: Anda, vai ter com esse administrador, Sebna, o mordomo, e pergunta-lhe:' },
      { v: 16, en: '‘What are you doing here? Who has you here, that you have dug out a tomb here?’ Cutting himself out a tomb on high, chiseling a habitation for himself in the rock!”', pt: 'Que fazes aqui? ou que parente tens tu aqui, para que cavasses aqui uma sepultura? Cavando em lugar alto a tua sepultura, cinzelando na rocha morada para ti mesmo!' },
      { v: 17, en: 'Behold, Yahweh will overcome you and hurl you away violently. Yes, he will grasp you firmly.', pt: 'Eis que o Senhor te arrojará violentamente, ó homem forte, e seguramente te prenderá.' },
      { v: 18, en: 'He will surely wind you around and around, and throw you like a ball into a large country. There you will die, and there the chariots of your glory will be, you shame of your lord’s house.', pt: 'Certamente te enrolará como uma bola, e te lançará para um país espaçoso. Ali morrerás, e ali irão os teus magníficos carros, ó tu, opróbrio da casa do teu senhor.' },
      { v: 19, en: 'I will thrust you from your office. You will be pulled down from your station.', pt: 'E demitir-te-ei do teu posto; e da tua categoria serás derrubado.' },
      { v: 20, en: 'It will happen in that day that I will call my servant Eliakim the son of Hilkiah,', pt: 'Naquele dia chamarei a meu servo Eliaquim, filho de Hilquias,' },
      { v: 21, en: 'and I will clothe him with your robe, and strengthen him with your belt. I will commit your government into his hand; and he will be a father to the inhabitants of Jerusalem, and to the house of Judah.', pt: 'e vesti-lo-ei da tua túnica, e cingi-lo-ei com o teu cinto, e entregarei nas suas mãos o teu governo; e ele será como pai para os moradores de Jerusalém, e para a casa de Judá.' },
      { v: 22, en: 'I will lay the key of David’s house on his shoulder. He will open, and no one will shut. He will shut, and no one will open.', pt: 'Porei a chave da casa de Davi sobre o seu ombro; ele abrirá, e ninguém fechará; fechará, e ninguém abrirá.' },
      { v: 23, en: 'I will fasten him like a nail in a sure place. He will be for a throne of glory to his father’s house.', pt: 'E fixá-lo-ei como a um prego num lugar firme; e será como um trono de honra para a casa de seu pai.' },
      { v: 24, en: 'They will hang on him all the glory of his father’s house, the offspring and the issue, every small vessel, from the cups even to all the pitchers.', pt: 'Nele, pois, pendurarão toda a glória da casa de seu pai, a prole e a progênie, todos os vasos menores, desde as taças até os jarros.' },
      { v: 25, en: '“In that day,” says Yahweh of Armies, “the nail that was fastened in a sure place will give way. It will be cut down, and fall. The burden that was on it will be cut off, for Yahweh has spoken it.”', pt: 'Naquele dia, diz o Senhor dos exércitos, cederá o prego fincado em lugar firme; será cortado, e cairá; e a carga que nele estava se desprenderá, porque o Senhor o disse.' },
    ],
    23: [
      { v: 1, en: 'The burden of Tyre. Howl, you ships of Tarshish! For it is laid waste, so that there is no house, no entering in. From the land of Kittim it is revealed to them.', pt: 'Oráculo acerca de Tiro. Uivai, navios de Társis, porque ela está desolada, a ponto de não haver nela casa nem abrigo; desde a terra de Quitim lhes foi isso revelado.' },
      { v: 2, en: 'Be still, you inhabitants of the coast, you whom the merchants of Sidon, that pass over the sea, have replenished.', pt: 'Calai-vos, moradores do litoral, vós a quem encheram os mercadores de Sidom, navegando pelo mar.' },
      { v: 3, en: 'On great waters, the seed of the Shihor, the harvest of the Nile, was her revenue. She was the market of nations.', pt: 'Por sobre grandes águas foi-lhe trazida a sua provisão, a semente de Sior, a ceifa do Nilo; e ela se tornou a feira das nações.' },
      { v: 4, en: 'Be ashamed, Sidon; for the sea has spoken, the stronghold of the sea, saying, “I have not travailed, nor given birth, neither have I nourished young men, nor brought up virgins.”', pt: 'Envergonha-te, ó Sidom; porque o mar falou, a fortaleza do mar disse: Eu não tive dores de parto, nem dei à luz, nem ainda criei mancebos, nem eduquei donzelas.' },
      { v: 5, en: 'When the report comes to Egypt, they will be in anguish at the report of Tyre.', pt: 'Quando a notícia chegar ao Egito, assim haverá dores quando se ouvirem as notícias de Tiro.' },
      { v: 6, en: 'Pass over to Tarshish! Wail, you inhabitants of the coast!', pt: 'Passai a Társis; uivai, moradores do litoral.' },
      { v: 7, en: 'Is this your joyous city, whose antiquity is of ancient days, whose feet carried her far away to travel?', pt: 'É esta, porventura, a vossa cidade alegre, cuja origem é dos dias antigos, cujos pés a levavam para longe a peregrinar?' },
      { v: 8, en: 'Who has planned this against Tyre, the giver of crowns, whose merchants are princes, whose traders are the honorable of the earth?', pt: 'Quem formou este desígnio contra Tiro, distribuidora de coroas, cujos mercadores eram príncipes e cujos negociantes eram os mais nobres da terra?' },
      { v: 9, en: 'Yahweh of Armies has planned it, to stain the pride of all glory, to bring into contempt all the honorable of the earth.', pt: 'O Senhor dos exércitos formou este desígnio para denegrir a soberba de toda a glória, e para reduzir à ignomínia os ilustres da terra.' },
      { v: 10, en: 'Pass through your land like the Nile, daughter of Tarshish. There is no restraint any more.', pt: 'Inunda como o Nilo a tua terra, ó filha de Társis; já não há mais o que te refreie.' },
      { v: 11, en: 'He has stretched out his hand over the sea. He has shaken the kingdoms. Yahweh has ordered the destruction of Canaan’s strongholds.', pt: 'Ele estendeu a sua mão sobre o mar, e abalou os reinos; o Senhor deu mandado contra Canaã, para destruir as suas fortalezas.' },
      { v: 12, en: 'He said, “You shall rejoice no more, you oppressed virgin daughter of Sidon. Arise, pass over to Kittim. Even there you will have no rest.”', pt: 'E disse: Não continuarás mais a te regozijar, ó oprimida donzela, filha de Sidom; levanta-te, passa a Chipre, e ainda ali não terás descanso.' },
      { v: 13, en: 'Behold, the land of the Chaldeans. This people was not. The Assyrians founded it for those who dwell in the wilderness. They set up their towers. They overthrew its palaces. They made it a ruin.', pt: 'Eis a terra dos caldeus! este é o povo, não foi a Assíria. Destinou a Tiro para as feras do deserto; levantaram as suas torres de sítio; derrubaram os palácios dela; a ruínas a reduziu.' },
      { v: 14, en: 'Howl, you ships of Tarshish, for your stronghold is laid waste!', pt: 'Uivai, navios de Társis; porque está desolada a vossa fortaleza.' },
      { v: 15, en: 'It will come to pass in that day that Tyre will be forgotten seventy years, according to the days of one king. After the end of seventy years it will be to Tyre like in the song of the prostitute.', pt: 'Naquele dia Tiro será posta em esquecimento por setenta anos, conforme os dias dum rei; mas depois de findos os setenta anos, sucederá a Tiro como se diz na canção da prostituta.' },
      { v: 16, en: 'Take a harp; go about the city, you prostitute that has been forgotten. Make sweet melody. Sing many songs, that you may be remembered.', pt: 'Toma a harpa, rodeia a cidade, ó prostituta, entregue ao esquecimento; toca bem, canta muitos cânticos, para que haja memória de ti.' },
      { v: 17, en: 'It will happen after the end of seventy years that Yahweh will visit Tyre, and she shall return to her wages, and will play the prostitute with all the kingdoms of the world on the surface of the earth.', pt: 'No fim de setenta anos o Senhor visitará a Tiro, e ela tornará à sua ganância de prostituta, e fornicará com todos os reinos que há sobre a face da terra.' },
      { v: 18, en: 'Her merchandise and her wages will be holiness to Yahweh. It will not be treasured nor laid up; for her merchandise will be for those who dwell before Yahweh, to eat sufficiently, and for durable clothing.', pt: 'E será consagrado ao Senhor o seu comércio e a sua ganância de prostituta; não se entesourará, nem se guardará; mas o seu comércio será para os que habitam perante o Senhor, para que comam suficientemente; e tenham vestimenta esplêndida.' },
    ],
    24: [
      { v: 1, en: 'Behold, Yahweh makes the earth empty, makes it waste, turns it upside down, and scatters its inhabitants.', pt: 'Eis que o Senhor esvazia a terra e a desola, transtorna a sua superfície e dispersa os seus moradores.' },
      { v: 2, en: 'It will be as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the creditor, so with the debtor; as with the taker of interest, so with the giver of interest.', pt: 'E o que suceder ao povo, sucederá ao sacerdote; ao servo, como ao seu senhor; à serva, como à sua senhora; ao comprador, como ao vendedor; ao que empresta, como ao que toma emprestado; ao que recebe usura, como ao que paga usura.' },
      { v: 3, en: 'The earth will be utterly emptied and utterly laid waste; for Yahweh has spoken this word.', pt: 'De todo se esvaziará a terra, e de todo será saqueada, porque o Senhor pronunciou esta palavra.' },
      { v: 4, en: 'The earth mourns and fades away. The world languishes and fades away. The lofty people of the earth languish.', pt: 'A terra pranteia e se murcha; o mundo enfraquece e se murcha; enfraquecem os mais altos do povo da terra.' },
      { v: 5, en: 'The earth also is polluted under its inhabitants, because they have transgressed the laws, violated the statutes, and broken the everlasting covenant.', pt: 'Na verdade a terra está contaminada debaixo dos seus habitantes; porquanto transgridem as leis, mudam os estatutos, e quebram o pacto eterno.' },
      { v: 6, en: 'Therefore the curse has devoured the earth, and those who dwell therein are found guilty. Therefore the inhabitants of the earth are burned, and few men left.', pt: 'Por isso a maldição devora a terra, e os que habitam nela sofrem por serem culpados; por isso são queimados os seus habitantes, e poucos homens restam.' },
      { v: 7, en: 'The new wine mourns. The vine languishes. All the merry-hearted sigh.', pt: 'Pranteia o mosto, enfraquece a vide, e suspiram todos os que eram alegres de coração.' },
      { v: 8, en: 'The mirth of tambourines ceases. The sound of those who rejoice ends. The joy of the harp ceases.', pt: 'Cessa o folguedo dos tamboris, acaba a algazarra dos jubilantes, cessa a alegria da harpa.' },
      { v: 9, en: 'They will not drink wine with a song. Strong drink will be bitter to those who drink it.', pt: 'Já não bebem vinho ao som das canções; a bebida forte é amarga para os que a bebem.' },
      { v: 10, en: 'The confused city is broken down. Every house is shut up, that no man may come in.', pt: 'Demolida está a cidade desordeira; todas as casas estão fechadas, de modo que ninguém pode entrar.' },
      { v: 11, en: 'There is a crying in the streets because of the wine. All joy is darkened. The mirth of the land is gone.', pt: 'Há lastimoso clamor nas ruas por falta do vinho; toda a alegria se escureceu, já se foi o prazer da terra.' },
      { v: 12, en: 'The city is left in desolation, and the gate is struck with destruction.', pt: 'Na cidade só resta a desolação, e a porta está reduzida a ruínas.' },
      { v: 13, en: 'For it will be so within the earth among the peoples, as the shaking of an olive tree, as the gleanings when the vintage is done.', pt: 'Pois será no meio da terra, entre os povos, como a sacudidura da oliveira, e como os rabiscos, quando está acabada a vindima.' },
      { v: 14, en: 'These shall lift up their voice. They will shout for the majesty of Yahweh. They cry aloud from the sea.', pt: 'Estes alçarão a sua voz, bradando de alegria; por causa da majestade do Senhor clamarão desde o mar.' },
      { v: 15, en: 'Therefore glorify Yahweh in the east, even the name of Yahweh, the God of Israel, in the islands of the sea!', pt: 'Por isso glorificai ao Senhor no Oriente, e na região litorânea do mar ao nome do Senhor Deus de Israel.' },
      { v: 16, en: 'From the uttermost part of the earth have we heard songs. Glory to the righteous! But I said, “I pine away! I pine away! woe is me!” The treacherous have dealt treacherously. Yes, the treacherous have dealt very treacherously.', pt: 'Dos confins da terra ouvimos cantar: Glória ao Justo. Mas eu digo: Emagreço, emagreço, ai de mim! os pérfidos tratam perfidamente; sim, os pérfidos tratam muito perfidamente.' },
      { v: 17, en: 'Fear, the pit, and the snare, are on you who inhabitant the earth.', pt: 'O pavor, e a cova, e o laço vêm sobre ti, ó morador da terra.' },
      { v: 18, en: 'It will happen that he who flees from the noise of the fear will fall into the pit; and he who comes up out of the middle of the pit will be taken in the snare; for the windows on high are opened, and the foundations of the earth tremble.', pt: 'Aquele que fugir da voz do pavor cairá na cova, e o que subir da cova o laço o prenderá; porque as janelas do alto se abriram, e os fundamentos da terra tremem.' },
      { v: 19, en: 'The earth is utterly broken. The earth is torn apart. The earth is shaken violently.', pt: 'A terra está de todo quebrantada, a terra está de todo fendida, a terra está de todo abalada.' },
      { v: 20, en: 'The earth will stagger like a drunken man, and will sway back and forth like a hammock. Its disobedience will be heavy on it, and it will fall and not rise again.', pt: 'A terra cambaleia como o ébrio, e balanceia como a rede de dormir; e a sua transgressão se torna pesada sobre ela, e ela cai, e nunca mais se levantará.' },
      { v: 21, en: 'It shall happen in that day that Yahweh will punish the army of the high ones on high, and the kings of the earth on the earth.', pt: 'Naquele dia o Senhor castigará os exércitos do alto nas alturas, e os reis da terra sobre a terra.' },
      { v: 22, en: 'They shall be gathered together, as prisoners are gathered in the pit, and shall be shut up in the prison; and after many days shall they be visited.', pt: 'E serão ajuntados como presos numa cova, e serão encerrados num cárcere; e serão punidos depois de muitos dias.' },
      { v: 23, en: 'Then the moon shall be confounded, and the sun ashamed; for Yahweh of Armies will reign on Mount Zion, and in Jerusalem; and before his elders will be glory.', pt: 'Então a lua se confundirá, e o sol se envergonhará, pois o Senhor dos exércitos reinará no monte Sião e em Jerusalém; e perante os seus anciãos manifestará a sua glória.' },
    ],
    25: [
      { v: 1, en: 'Yahweh, you are my God. I will exalt you! I will praise your name, for you have done wonderful things, things planned long ago, in complete faithfulness and truth.', pt: 'ç Senhor, tu és o meu Deus; exaltarte-ei a ti, e louvarei o teu nome; porque fizeste maravilhas, os teus conselhos antigos, em fidelidade e em verdade.' },
      { v: 2, en: 'For you have made a city into a heap, a fortified city into a ruin, a palace of strangers to be no city. It will never be built.', pt: 'Porque da cidade fizeste um montão, e da cidade fortificada uma ruína, e do paço dos estranhos, que não seja mais cidade; e ela jamais se tornará a edificar.' },
      { v: 3, en: 'Therefore a strong people will glorify you. A city of awesome nations will fear you.', pt: 'Pelo que te glorificará um povo poderoso; e a cidade das nações formidáveis te temerá:' },
      { v: 4, en: 'For you have been a stronghold to the poor, a stronghold to the needy in his distress, a refuge from the storm, a shade from the heat, when the blast of the dreaded ones is like a storm against the wall.', pt: 'Porque tens sido a fortaleza do pobre, a fortaleza do necessitado na sua angústia, refúgio contra a tempestade, e sombra contra o calor, pois o assopro dos violentos é como a tempestade contra o muro.' },
      { v: 5, en: 'As the heat in a dry place will you bring down the noise of strangers; as the heat by the shade of a cloud, the song of the dreaded ones will be brought low.', pt: 'Como o calor em lugar seco, tu abaterás o tumulto dos estranhos; como se abranda o calor pela sombra da espessa nuvem, assim acabará o cântico dos violentos.' },
      { v: 6, en: 'In this mountain, Yahweh of Armies will make all peoples a feast of choice meat, a feast of choice wines, of choice meat full of marrow, of well refined choice wines.', pt: 'E o Senhor dos exércitos dará neste monte a todos os povos um banquete de coisas gordurosas, banquete de vinhos puros, de coisas gordurosas feitas de tutanos, e de vinhos puros, bem purificados.' },
      { v: 7, en: 'He will destroy in this mountain the surface of the covering that covers all peoples, and the veil that is spread over all nations.', pt: 'E destruirá neste monte a coberta que cobre todos os povos, e o véu que está posto sobre todas as nações.' },
      { v: 8, en: 'He has swallowed up death forever! The Lord Yahweh will wipe away tears from off all faces. He will take the reproach of his people away from off all the earth, for Yahweh has spoken it.', pt: 'Aniquilará a morte para sempre, e assim enxugará o Senhor Deus as lágrimas de todos os rostos, e tirará de toda a terra o opróbrio do seu povo; porque o Senhor o disse.' },
      { v: 9, en: 'It shall be said in that day, “Behold, this is our God! We have waited for him, and he will save us! This is Yahweh! We have waited for him. We will be glad and rejoice in his salvation!”', pt: 'E naquele dia se dirá: Eis que este é o nosso Deus; por ele temos esperado, para que nos salve. Este é o Senhor; por ele temos esperado; na sua salvação gozaremos e nos alegraremos.' },
      { v: 10, en: 'For in this mountain Yahweh’s hand will rest. Moab will be trodden down in his place, even like straw is trodden down in the water of the dunghill.', pt: 'Porque a mão do Senhor repousará neste monte; e Moabe será trilhado no seu lugar, assim como se trilha a palha na água do monturo.' },
      { v: 11, en: 'He will spread out his hands in the middle of it, like one who swims spreads out hands to swim, but his pride will be humbled together with the craft of his hands.', pt: 'E estenderá as suas mãos no meio disso, assim como as estende o nadador para nadar; mas o Senhor abaterá a sua altivez juntamente com a perícia das suas mãos.' },
      { v: 12, en: 'He has brought the high fortress of your walls down, laid low, and brought to the ground, even to the dust.', pt: 'E abaixará as altas fortalezas dos teus muros; abatê-las-á e derrubá-las-á por terra até o pó.' },
    ],
    26: [
      { v: 1, en: 'In that day, this song will be sung in the land of Judah: “We have a strong city. God appoints salvation for walls and bulwarks.', pt: 'Naquele dia se entoará este cântico na terra de Judá: uma cidade forte temos, a que Deus pôs a salvação por muros e antemuros.' },
      { v: 2, en: 'Open the gates, that the righteous nation may enter: the one which keeps faith.', pt: 'Abri as portas, para que entre nela a nação justa, que observa a verdade.' },
      { v: 3, en: 'You will keep whoever’s mind is steadfast in perfect peace, because he trusts in you.', pt: 'Tu conservarás em paz aquele cuja mente está firme em ti; porque ele confia em ti.' },
      { v: 4, en: 'Trust in Yahweh forever; for in Yah, Yahweh, is an everlasting Rock.', pt: 'Confiai sempre no Senhor; porque o Senhor Deus é uma rocha eterna.' },
      { v: 5, en: 'For he has brought down those who dwell on high, the lofty city. He lays it low. He lays it low even to the ground. He brings it even to the dust.', pt: 'porque ele tem derrubado os que habitam no alto, na cidade elevada; abate-a, abate-a até o chão; e a reduz até o pó.' },
      { v: 6, en: 'The foot shall tread it down; Even the feet of the poor, and the steps of the needy.”', pt: 'Pisam-na os pés, os pés dos pobres, e os passos dos necessitados.' },
      { v: 7, en: 'The way of the just is uprightness. You who are upright make the path of the righteous level.', pt: 'O caminho do justo é plano; tu, que és reto, nivelas a sua vereda.' },
      { v: 8, en: 'Yes, in the way of your judgments, Yahweh, have we waited for you. Your name and your renown are the desire of our soul.', pt: 'No caminho dos teus juízos, Senhor, temos esperado por ti; no teu nome e na tua memória está o desejo da nossa alma.' },
      { v: 9, en: 'With my soul I have desired you in the night. Yes, with my spirit within me will I seek you earnestly; for when your judgments are in the earth, the inhabitants of the world learn righteousness.', pt: 'Minha alma te deseja de noite; sim, o meu espírito, dentro de mim, diligentemente te busca; porque, quando os teus juízos estão na terra, os moradores do mundo aprendem justiça.' },
      { v: 10, en: 'Let favor be shown to the wicked, yet he will not learn righteousness. In the land of uprightness he will deal wrongfully, and will not see Yahweh’s majesty.', pt: 'Ainda que se mostre favor ao ímpio, ele não aprende a justiça; até na terra da retidão ele pratica a iniqüidade, e não atenta para a majestade do Senhor.' },
      { v: 11, en: 'Yahweh, your hand is lifted up, yet they don’t see; but they will see your zeal for the people, and be disappointed. Yes, fire will consume your adversaries.', pt: 'Senhor, a tua mão está levantada, contudo eles não a vêem; vê-la-ão, porém, e confundir-se-ão por causa do zelo que tens do teu povo; e o fogo reservado para os teus adversários os devorará.' },
      { v: 12, en: 'Yahweh, you will ordain peace for us, for you have also done all our work for us.', pt: 'Senhor, tu hás de estabelecer para nós a paz; pois tu fizeste para nós todas as nossas obras.' },
      { v: 13, en: 'Yahweh our God, other lords besides you have had dominion over us, but by you only will we make mention of your name.', pt: 'ç Senhor Deus nosso, outros senhores além de ti têm tido o domínio sobre nós; mas, por ti só, nos lembramos do teu nome.' },
      { v: 14, en: 'The dead shall not live. The departed spirits shall not rise. Therefore you have visited and destroyed them, and caused all memory of them to perish.', pt: 'Os falecidos não tornarão a viver; os mortos não ressuscitarão; por isso os visitaste e destruíste, e fizeste perecer toda a sua memória.' },
      { v: 15, en: 'You have increased the nation, O Yahweh. You have increased the nation! You are glorified! You have enlarged all the borders of the land.', pt: 'Tu, Senhor, aumentaste a nação; aumentaste a nação e te fizeste glorioso; alargaste todos os confins da terra.' },
      { v: 16, en: 'Yahweh, in trouble they have visited you. They poured out a prayer when your chastening was on them.', pt: 'Senhor, na angústia te buscaram; quando lhes sobreveio a tua correção, derramaram-se em oração.' },
      { v: 17, en: 'Just as a woman with child, who draws near the time of her delivery, is in pain and cries out in her pangs; so we have been before you, Yahweh.', pt: 'Como a mulher grávida, quando está próxima a sua hora, tem dores de parto e dá gritos nas suas dores, assim fomos nós diante de ti, ó Senhor!' },
      { v: 18, en: 'We have been with child. We have been in pain. We gave birth, it seems, only to wind. We have not worked any deliverance in the earth; neither have the inhabitants of the world fallen.', pt: 'Concebemos nós, e tivemos dores de parto, mas isso foi como se tivéssemos dado à luz o vento; livramento não trouxemos à terra; nem nasceram moradores do mundo.' },
      { v: 19, en: 'Your dead shall live. My dead bodies shall arise. Awake and sing, you who dwell in the dust; for your dew is like the dew of herbs, and the earth will cast out the departed spirits.', pt: 'Os teus mortos viverão, os seus corpos ressuscitarão; despertai e exultai, vós que habitais no pó; porque o teu orvalho é orvalho de luz, e sobre a terra das sombras fá-lo-ás cair.' },
      { v: 20, en: 'Come, my people, enter into your rooms, and shut your doors behind you. Hide yourself for a little moment, until the indignation is past.', pt: 'Vem, povo meu, entra nas tuas câmaras, e fecha as tuas portas sobre ti; esconde-te só por um momento, até que passe a indignação.' },
      { v: 21, en: 'For, behold, Yahweh comes out of his place to punish the inhabitants of the earth for their iniquity. The earth also will disclose her blood, and will no longer cover her slain.', pt: 'Pois eis que o Senhor está saindo do seu lugar para castigar os moradores da terra por causa da sua iniqüidade; e a terra descobrirá o seu sangue, e não encobrirá mais os seus mortos.' },
    ],
    27: [
      { v: 1, en: 'In that day, Yahweh with his hard and great and strong sword will punish leviathan, the fleeing serpent, and leviathan the twisted serpent; and he will kill the dragon that is in the sea.', pt: 'Naquele dia o Senhor castigará com a sua dura espada, grande e forte, o leviatã, a serpente fugitiva, e o leviatã, a serpente tortuosa; e matará o dragão, que está no mar.' },
      { v: 2, en: 'In that day, sing to her, “A pleasant vineyard!', pt: 'Naquele dia haverá uma vinha deliciosa; cantai a seu respeito.' },
      { v: 3, en: 'I, Yahweh, am its keeper. I will water it every moment. Lest anyone damage it, I will keep it night and day.', pt: 'Eu, o Senhor, a guardo, e a cada momento a regarei; para que ninguém lhe faça dano, de noite e de dia a guardarei.' },
      { v: 4, en: 'Wrath is not in me, but if I should find briers and thorns, I would do battle! I would march on them and I would burn them together.', pt: 'Não há indignação em mim; oxalá que fossem ordenados diante de mim em guerra sarças e espinheiros! eu marcharia contra eles e juntamente os queimaria.' },
      { v: 5, en: 'Or else let him take hold of my strength, that he may make peace with me. Let him make peace with me.”', pt: 'Ou, então, busquem o meu refúgio, e façai, paz comigo; sim, façam paz comigo.' },
      { v: 6, en: 'In days to come, Jacob will take root. Israel will blossom and bud. They will fill the surface of the world with fruit.', pt: 'Dias virão em que Jacó lançará raízes; Israel florescerá e brotará; e eles encherão de fruto a face do mundo.' },
      { v: 7, en: 'Has he struck them as he struck those who struck them? Or are they killed like those who killed them were killed?', pt: 'Porventura feriu-os o Senhor como feriu aos que os feriram? ou matou-os ele assim como matou aos que por eles foram mortos?' },
      { v: 8, en: 'In measure, when you send them away, you contend with them. He has removed them with his rough blast in the day of the east wind.', pt: 'Com medida contendeste com eles, quando os rejeitaste; ele a removeu com o seu vento forte, no tempo do vento leste.' },
      { v: 9, en: 'Therefore by this the iniquity of Jacob will be forgiven, and this is all the fruit of taking away his sin: that he makes all the stones of the altar as chalk stones that are beaten in pieces, so that the Asherah poles and the incense altars shall rise no more.', pt: 'Por isso se expiará a iniqüidade de Jacó; e este será todo o fruto da remoção do seu pecado: ele fará todas as pedras do altar como pedras de cal feitas em pedaços, de modo que os aserins e as imagens do sol não poderão ser mais levantados.' },
      { v: 10, en: 'For the fortified city is solitary, a habitation deserted and forsaken, like the wilderness. The calf will feed there, and there he will lie down, and consume its branches.', pt: 'porque a cidade fortificada está solitária, uma habitação rejeitada e abandonada como um deserto; ali pastarão os bezerros, ali também se deitarão e devorarão os seus ramos.' },
      { v: 11, en: 'When its boughs are withered, they will be broken off. The women will come and set them on fire, for they are a people of no understanding. Therefore he who made them will not have compassion on them, and he who formed them will show them no favor.', pt: 'Quando os seus ramos se secam, são quebrados; vêm as mulheres e lhes ateiam fogo; porque este povo não é povo de entendimento; por isso aquele que o fez não se compadecerá dele, e aquele que o formou não lhe mostrará nenhum favor.' },
      { v: 12, en: 'It will happen in that day, that Yahweh will thresh from the flowing stream of the Euphrates to the brook of Egypt; and you will be gathered one by one, children of Israel.', pt: 'Naquele dia o Senhor padejará o seu trigo desde as correntes do Rio, até o ribeiro do Egito; e vós, ó filhos de Israel, sereis colhidos um a um.' },
      { v: 13, en: 'It will happen in that day that a great trumpet will be blown; and those who were ready to perish in the land of Assyria, and those who were outcasts in the land of Egypt, shall come; and they will worship Yahweh in the holy mountain at Jerusalem.', pt: 'E naquele dia se tocará uma grande trombeta; e os que andavam perdidos pela terra da Assíria, e os que foram desterrados para a terra do Egito tornarão a vir; e adorarão ao Senhor no monte santo em Jerusalém.' },
    ],
    28: [
      { v: 1, en: 'Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fertile valley of those who are overcome with wine!', pt: 'Ai da vaidosa coroa dos bêbedos de Efraim, e da flor murchada do seu glorioso ornamento, que está sobre a cabeça do fértil vale dos vencidos do vinho.' },
      { v: 2, en: 'Behold, the Lord has a mighty and strong one. Like a storm of hail, a destroying storm, and like a storm of mighty waters overflowing, he will cast them down to the earth with his hand.', pt: 'Eis que o Senhor tem um valente e poderoso; como tempestade de saraiva, tormenta destruidora, como tempestade de impetuosas águas que transbordam, ele a derrubará violentamente por terra.' },
      { v: 3, en: 'The crown of pride of the drunkards of Ephraim will be trodden under foot.', pt: 'A vaidosa coroa dos bêbedos de Efraim será pisada aos pés;' },
      { v: 4, en: 'The fading flower of his glorious beauty, which is on the head of the fertile valley, shall be like the first-ripe fig before the summer; which someone picks and eats as soon as he sees it.', pt: 'e a flor murchada do seu glorioso ornamento, que está sobre a cabeça do fértil vale, será como figo que amadurece antes do verão, que, vendo-o alguém, e mal tomando-o na mão, o engole.' },
      { v: 5, en: 'In that day, Yahweh of Armies will become a crown of glory, and a diadem of beauty, to the residue of his people;', pt: 'Naquele dia o Senhor dos exércitos será por coroa de glória e diadema de formosura para o restante de seu povo;' },
      { v: 6, en: 'and a spirit of justice to him who sits in judgment, and strength to those who turn back the battle at the gate.', pt: 'e por espírito de juízo para o que se assenta a julgar, e por fortaleza para os que fazem recuar a peleja até a porta.' },
      { v: 7, en: 'They also reel with wine, and stagger with strong drink. The priest and the prophet reel with strong drink. They are swallowed up by wine. They stagger with strong drink. They err in vision. They stumble in judgment.', pt: 'Mas também estes cambaleiam por causa do vinho, e com a bebida forte se desencaminham; até o sacerdote e o profeta cambaleiam por causa da bebida forte, estão tontos do vinho, desencaminham-se por causa da bebida forte; erram na visão, e tropeçam no juizo.' },
      { v: 8, en: 'For all tables are completely full of filthy vomit and filthiness.', pt: 'Pois todas as suas mesas estão cheias de vômitos e de sujidade, e não há lugar que esteja limpo.' },
      { v: 9, en: 'Whom will he teach knowledge? To whom will he explain the message? Those who are weaned from the milk, and drawn from the breasts?', pt: 'Ora, a quem ensinará ele o conhecimento? e a quem fará entender a mensagem? aos desmamados, e aos arrancados dos seios?' },
      { v: 10, en: 'For it is precept on precept, precept on precept; line on line, line on line; here a little, there a little.', pt: 'Pois é preceito sobre preceito, preceito sobre preceito; regra sobre regra, regra sobre regra; um pouco aqui, um pouco ali.' },
      { v: 11, en: 'But he will speak to this nation with stammering lips and in another language;', pt: 'Na verdade por lábios estranhos e por outra língua falará a este povo;' },
      { v: 12, en: 'to whom he said, “This is the resting place. Give rest to weary”; and “This is the refreshing”; yet they would not hear.', pt: 'ao qual disse: Este é o descanso, dai descanso ao cansado; e este é o refrigério; mas não quiseram ouvir.' },
      { v: 13, en: 'Therefore Yahweh’s word will be to them precept on precept, precept on precept; line on line, line on line; here a little, there a little; that they may go, fall backward, be broken, be snared, and be taken.', pt: 'Assim pois a palavra do Senhor lhes será preceito sobre preceito, preceito sobre preceito; regra sobre regra, regra sobre regra; um pouco aqui, um pouco ali; para que vão, e caiam para trás, e fiquem quebrantados, enlaçados, e presos.' },
      { v: 14, en: 'Therefore hear Yahweh’s word, you scoffers, that rule this people in Jerusalem:', pt: 'Ouvi, pois, a palavra do Senhor, homens escarnecedores, que dominais este povo que está em Jerusalém.' },
      { v: 15, en: '“Because you have said, ‘We have made a covenant with death, and with Sheol are we in agreement. When the overflowing scourge passes through, it won’t come to us; for we have made lies our refuge, and we have hidden ourselves under falsehood.’”', pt: 'Porquanto dizeis: Fizemos pacto com a morte, e com o Seol fizemos aliança; quando passar o flagelo trasbordante, não chegará a nós; porque fizemos da mentira o nosso refúgio, e debaixo da falsidade nos escondemos.' },
      { v: 16, en: 'Therefore thus says the Lord Yahweh, “Behold, I lay in Zion for a foundation a stone, a tried stone, a precious cornerstone of a sure foundation. He who believes shall not act hastily.', pt: 'Portanto assim diz o Senhor Deus: Eis que ponho em Sião como alicerce uma pedra, uma pedra provada, pedra preciosa de esquina, de firme fundamento; aquele que crer não se apressará.' },
      { v: 17, en: 'I will make justice the measuring line, and righteousness the plumb line. The hail will sweep away the refuge of lies, and the waters will overflow the hiding place.', pt: 'E farei o juízo a linha para medir, e a justiça o prumo; e a saraiva varrerá o refúgio da mentira, e as águas inundarão o esconderijo.' },
      { v: 18, en: 'Your covenant with death shall be annulled, and your agreement with Sheol shall not stand. When the overflowing scourge passes through, then you will be trampled down by it.', pt: 'E o vosso pacto com a morte será anulado; e a vossa aliança com o Seol não subsistirá; e, quando passar o flagelo trasbordante, sereis abatidos por ele.' },
      { v: 19, en: 'As often as it passes through, it will seize you; for morning by morning it will pass through, by day and by night; and it will be nothing but terror to understand the message.”', pt: 'Todas as vezes que passar, vos arrebatará; porque de manhã em manhã passará, de dia e de noite; e será motivo de terror o só ouvir tal notícia.' },
      { v: 20, en: 'For the bed is too short to stretch out on, and the blanket is too narrow to wrap oneself in.', pt: 'Pois a cama é tão curta que nela ninguém se pode estender; e o cobertor tão estreito que com ele ninguém se pode cobrir.' },
      { v: 21, en: 'For Yahweh will rise up as on Mount Perazim. He will be angry as in the valley of Gibeon; that he may do his work, his unusual work, and bring to pass his act, his extraordinary act.', pt: 'Porque o Senhor se levantará como no monte Perazim, e se irará como no vale de Gibeão, para realizar a sua obra, a sua estranha obra, e para executar o seu ato, o seu estranho ato.' },
      { v: 22, en: 'Now therefore don’t be scoffers, lest your bonds be made strong; for I have heard a decree of destruction from the Lord, Yahweh of Armies, on the whole earth.', pt: 'Agora, pois, não sejais escarnecedores, para que os vossos grilhões não se façam mais fortes; porque da parte do Senhor Deus dos exércitos ouvi um decreto de destruição completa e decisiva, sobre toda terra.' },
      { v: 23, en: 'Give ear, and hear my voice! Listen, and hear my speech!', pt: 'Inclinai os ouvidos, e ouvi a minha voz; escutai, e ouvi o meu discurso.' },
      { v: 24, en: 'Does he who plows to sow plow continually? Does he keep turning the soil and breaking the clods?', pt: 'Porventura lavra continuamente o lavrador, para semear? ou está sempre abrindo e esterroando a sua terra?' },
      { v: 25, en: 'When he has leveled its surface, doesn’t he plant the dill, and scatter the cumin seed, and put in the wheat in rows, the barley in the appointed place, and the spelt in its place?', pt: 'Não é antes assim: quando já tem nivelado a sua superfície, então espalha a nigela, semeia o cominho, lança o trigo a eito, a cevada no lugar determinado e a espelta na margem?' },
      { v: 26, en: 'For his God instructs him in right judgment, and teaches him.', pt: 'Pois o seu Deus o instrui devidamente e o ensina.' },
      { v: 27, en: 'For the dill are not threshed with a sharp instrument, neither is a cart wheel turned over the cumin; but the dill is beaten out with a stick, and the cumin with a rod.', pt: 'Porque a nigela não se trilha com instrumento de trilhar, nem sobre o cominho passa a roda de carro; mas a nigela é debulhada com uma vara, e o cominho com um pau.' },
      { v: 28, en: 'Bread flour must be ground; so he will not always be threshing it. Although he drives the wheel of his threshing cart over it, his horses don’t grind it.', pt: 'Acaso é esmiuçado o trigo? não; não se trilha continuamente, nem se esmiúça com as rodas do seu carro e os seus cavalos; não se esmiúça.' },
      { v: 29, en: 'This also comes out from Yahweh of Armies, who is wonderful in counsel, and excellent in wisdom.', pt: 'Até isso procede do Senhor dos exércitos, que é maravilhoso em conselho e grande em obra.' },
    ],
    29: [
      { v: 1, en: 'Woe to Ariel! Ariel, the city where David encamped! Add year to year; let the feasts come around;', pt: 'Ah! Ariel, Ariel, cidade onde Davi acampou! Acrescentai ano a ano; completem as festas o seu ciclo.' },
      { v: 2, en: 'then I will distress Ariel, and there will be mourning and lamentation. She shall be to me as an altar hearth.', pt: 'Então porei Ariel em aperto, e haverá pranto e lamentação; e ela será para mim como Ariel.' },
      { v: 3, en: 'I will encamp against you all around you, and will lay siege against you with posted troops. I will raise siege works against you.', pt: 'Acamparei contra ti em redor, e te sitiarei com baluartes, e levantarei tranqueiras contra ti.' },
      { v: 4, en: 'You will be brought down, and will speak out of the ground. Your speech will mumble out of the dust. Your voice will be as of one who has a familiar spirit, out of the ground, and your speech will whisper out of the dust.', pt: 'Então serás abatida, falarás de debaixo da terra, e a tua fala desde o pó sairá fraca; e será a tua voz debaixo da terra, como a dum necromante, e a tua fala assobiará desde o pó.' },
      { v: 5, en: 'But the multitude of your foes will be like fine dust, and the multitude of the ruthless ones like chaff that blows away. Yes, it will be in an instant, suddenly.', pt: 'E a multidão dos teus inimigos será como o pó miúdo, e a multidão dos terríveis como a pragana que passa; e isso acontecerá num momento, repentinamente.' },
      { v: 6, en: 'She will be visited by Yahweh of Armies with thunder, with earthquake, with great noise, with whirlwind and storm, and with the flame of a devouring fire.', pt: 'Da parte do Senhor dos exércitos será ela visitada com trovões, e com terremotos, e grande ruído, como tufão, e tempestade, e labareda de fogo consumidor.' },
      { v: 7, en: 'The multitude of all the nations that fight against Ariel, even all who fight against her and her stronghold, and who distress her, will be like a dream, a vision of the night.', pt: 'E como o sonho e uma visão de noite será a multidão de todas as nações que hão de pelejar contra Ariel, sim a multidão de todos os que pelejarem contra ela e contra a sua fortaleza e a puserem em aperto.' },
      { v: 8, en: 'It will be like when a hungry man dreams, and behold, he eats; but he awakes, and his hunger isn’t satisfied; or like when a thirsty man dreams, and behold, he drinks; but he awakes, and behold, he is faint, and he is still thirsty. The multitude of all the nations that fight against Mount Zion will be like that.', pt: 'Será também como o faminto que sonha que está a comer, mas, acordando, sente-se vazio; ou como o sedento que sonha que está a beber, mas, acordando, desfalecido se acha, e ainda com sede; assim será a multidão de todas as nações que pelejarem contra o monte Sião.' },
      { v: 9, en: 'Pause and wonder! Blind yourselves and be blind! They are drunken, but not with wine; they stagger, but not with strong drink.', pt: 'Pasmai, e maravilhai-vos; cegai-vos e ficai cegos; bêbedos estão, mas não de vinho, andam cambaleando, mas não de bebida forte.' },
      { v: 10, en: 'For Yahweh has poured out on you a spirit of deep sleep, and has closed your eyes, the prophets; and he has covered your heads, the seers.', pt: 'Porque o Senhor derramou sobre vós um espírito de profundo sono, e fechou os vossos olhos, os profetas; e vendou as vossas cabeças, os videntes.' },
      { v: 11, en: 'All vision has become to you like the words of a book that is sealed, which men deliver to one who is educated, saying, “Read this, please”; and he says, “I can’t, for it is sealed:”', pt: 'Pelo que toda visão vos é como as palavras dum livro selado que se dá ao que sabe ler, dizendo: Ora lê isto; e ele responde: Não posso, porque está selado.' },
      { v: 12, en: 'and the book is delivered to one who is not educated, saying, “Read this, please”; and he says, “I can’t read.”', pt: 'Ou dá-se o livro ao que não sabe ler, dizendo: Ora lê isto; e ele responde: Não sei ler.' },
      { v: 13, en: 'The Lord said, “Because this people draws near with their mouth and honors me with their lips, but they have removed their heart far from me, and their fear of me is a commandment of men which has been taught;', pt: 'Por isso o Senhor disse: Pois que este povo se aproxima de mim, e com a sua boca e com os seus lábios me honra, mas tem afastado para longe de mim o seu coração, e o seu temor para comigo consiste em mandamentos de homens, aprendidos de cor;' },
      { v: 14, en: 'therefore, behold, I will proceed to do a marvelous work among this people, even a marvelous work and a wonder; and the wisdom of their wise men will perish, and the understanding of their prudent men will be hidden.”', pt: 'portanto eis que continuarei a fazer uma obra maravilhosa com este povo, sim uma obra maravilhosa e um assombro; e a sabedoria dos seus sábios perecerá, e o entendimento dos seus entendidos se esconderá.' },
      { v: 15, en: 'Woe to those who deeply hide their counsel from Yahweh, and whose deeds are in the dark, and who say, “Who sees us?” and “Who knows us?”', pt: 'Ai dos que escondem profundamente o seu propósito do Senhor, e fazem as suas obras às escuras, e dizem: Quem nos vê? e quem nos conhece?' },
      { v: 16, en: 'You turn things upside down! Should the potter be thought to be like clay; that the thing made should say about him who made it, “He didn’t make me”; or the thing formed say of him who formed it, “He has no understanding?”', pt: 'Vós tudo perverteis! Acaso o oleiro há de ser reputado como barro, de modo que a obra diga do seu artífice: Ele não me fez; e o vaso formado diga de quem o formou: Ele não tem entendimento?' },
      { v: 17, en: 'Isn’t it yet a very little while, and Lebanon will be turned into a fruitful field, and the fruitful field will be regarded as a forest?', pt: 'Porventura dentro ainda de muito pouco tempo não se converterá o Líbano em campo fértil? e o campo fértil não se reputará por um bosque?' },
      { v: 18, en: 'In that day, the deaf will hear the words of the book, and the eyes of the blind will see out of obscurity and out of darkness.', pt: 'Naquele dia os surdos ouvirão as palavras do livro, e dentre a escuridão e dentre as trevas os olhos dos cegos a verão.' },
      { v: 19, en: 'The humble also will increase their joy in Yahweh, and the poor among men will rejoice in the Holy One of Israel.', pt: 'E os mansos terão cada vez mais gozo no Senhor, e os pobres dentre os homens se alegrarão no santo de Israel.' },
      { v: 20, en: 'For the ruthless is brought to nothing, and the scoffer ceases, and all those who are alert to do evil are cut off—', pt: 'Porque o opressor é reduzido a nada, e não existe mais o escarnecedor, e todos os que se dão à iniqüidade são desarraigados;' },
      { v: 21, en: 'who cause a person to be indicted by a word, and lay a snare for the arbiter in the gate, and who deprive the innocent of justice with false testimony.', pt: 'os que fazem por culpado o homem numa causa, os que armam laços ao que repreende na porta, e os que por um nada desviam o justo.' },
      { v: 22, en: 'Therefore Yahweh, who redeemed Abraham, says concerning the house of Jacob: “Jacob shall no longer be ashamed, neither shall his face grow pale.', pt: 'Portanto o Senhor, que remiu a Abraão, assim diz acerca da casa de Jacó: Jacó não será agora envergonhado, nem agora se descorará a sua face.' },
      { v: 23, en: 'But when he sees his children, the work of my hands, in the middle of him, they will sanctify my name. Yes, they will sanctify the Holy One of Jacob, and will stand in awe of the God of Israel.', pt: 'Mas quando virem seus filhos a obra das minhas mãos no meio deles, santificarão o meu nome; sim santificarão ao Santo de Jacó, e temerão ao Deus de Israel.' },
      { v: 24, en: 'They also who err in spirit will come to understanding, and those who grumble will receive instruction.”', pt: 'E os errados de espírito virão a ter entendimento, e os murmuradores aprenderão instrução.' },
    ],
    30: [
      { v: 1, en: '“Woe to the rebellious children”, says Yahweh, “who take counsel, but not from me; and who make an alliance, but not with my Spirit, that they may add sin to sin,', pt: 'Ai dos filhos rebeldes, diz o Senhor, que tomam conselho, mas não de mim; e que fazem aliança, mas não pelo meu espírito, para acrescentarem pecado a pecado;' },
      { v: 2, en: 'who set out to go down into Egypt, and have not asked my advice; to strengthen themselves in the strength of Pharaoh, and to take refuge in the shadow of Egypt!', pt: 'que se põem a caminho para descer ao Egito, sem pedirem o meu conselho; para se fortificarem com a força de Faraó, e para confiarem na sombra do Egito!' },
      { v: 3, en: 'Therefore the strength of Pharaoh will be your shame, and the refuge in the shadow of Egypt your confusion.', pt: 'Portanto, a força de Faraó se vos tornará em vergonha, e a confiança na sombra do Egito em confusão.' },
      { v: 4, en: 'For their princes are at Zoan, and their ambassadors have come to Hanes.', pt: 'Pois embora os seus oficiais estejam em Zoã, e os seus embaixadores cheguem a Hanes,' },
      { v: 5, en: 'They shall all be ashamed because of a people that can’t profit them, that are not a help nor profit, but a shame, and also a reproach.”', pt: 'eles se envergonharão de um povo que de nada lhes servirá, nem de ajuda, nem de proveito, porém de vergonha como também de opróbrio.' },
      { v: 6, en: 'The burden of the animals of the South. Through the land of trouble and anguish, of the lioness and the lion, the viper and fiery flying serpent, they carry their riches on the shoulders of young donkeys, and their treasures on the humps of camels, to an unprofitable people.', pt: 'Oráculo contra a Besta do Sul. Através da terra de aflição e de angústia, de onde vem a leoa e o leão, o basilisco, a áspide e a serpente voadora, levam às costas de jumentinhos as suas riquezas, e sobre as corcovas de camelos os seus tesouros, a um povo que de nada lhes aproveitará.' },
      { v: 7, en: 'For Egypt helps in vain, and to no purpose; therefore I have called her Rahab who sits still.', pt: 'Pois o Egito os ajuda em vão, e para nenhum fim; pelo que lhe tenho chamado Raabe que não se move.' },
      { v: 8, en: 'Now go, write it before them on a tablet, and inscribe it in a book, that it may be for the time to come forever and ever.', pt: 'Vai pois agora, escreve isso numa tábua perante eles, registra-o num livro; para que fique como testemunho para o tempo vindouro, para sempre.' },
      { v: 9, en: 'For it is a rebellious people, lying children, children who will not hear Yahweh’s law;', pt: 'Pois este é um povo rebelde, filhos mentirosos, filhos que não querem ouvir a lei do Senhor;' },
      { v: 10, en: 'who tell the seers, “Don’t see!” and to the prophets, “Don’t prophesy to us right things. Tell us pleasant things. Prophesy deceits.', pt: 'que dizem aos videntes: Não vejais; e aos profetas: Não profetizeis para nós o que é reto; dizei-nos coisas aprazíveis, e profetizai-nos ilusões;' },
      { v: 11, en: 'Get out of the way. Turn away from the path. Cause the Holy One of Israel to cease from before us.”', pt: 'desviai-vos do caminho, apartai-vos da vereda; fazei que o Santo de Israel deixe de estar perante nós.' },
      { v: 12, en: 'Therefore thus says the Holy One of Israel, “Because you despise this word, and trust in oppression and perverseness, and rely on it;', pt: 'Pelo que assim diz o Santo de Israel: Visto como rejeitais esta palavra, e confiais na opressão e na perversidade, e sobre elas vos estribais,' },
      { v: 13, en: 'therefore this iniquity shall be to you like a breach ready to fall, swelling out in a high wall, whose breaking comes suddenly in an instant.', pt: 'por isso esta maldade vos será como brecha que, prestes a cair, já forma barriga num alto muro, cuja queda virá subitamente, num momento.' },
      { v: 14, en: 'He will break it as a potter’s vessel is broken, breaking it in pieces without sparing, so that there won’t be found among the broken pieces a piece good enough to take fire from the hearth, or to dip up water out of the cistern.”', pt: 'E ele o quebrará como se quebra o vaso do oleiro, despedaçando-o por completo, de modo que não se achará entre os seus pedaços um caco que sirva para tomar fogo da lareira, ou tirar água da poça.' },
      { v: 15, en: 'For thus said the Lord Yahweh, the Holy One of Israel, “You will be saved in returning and rest. Your strength will be in quietness and in confidence.” You refused,', pt: 'Pois assim diz o Senhor Deus, o Santo de Israel: Voltando e descansando, sereis salvos; no sossego e na confiança estará a vossa força. Mas não quisestes;' },
      { v: 16, en: 'but you said, “No, for we will flee on horses”; therefore you will flee; and, “We will ride on the swift”; therefore those who pursue you will be swift.', pt: 'antes dissestes: Não; porém sobre cavalos fugiremos; portanto fugireis; e: Sobre cavalos ligeiros cavalgaremos; portanto hão de ser ligeiros os vossos perseguidores.' },
      { v: 17, en: 'One thousand will flee at the threat of one. At the threat of five, you will flee until you are left like a beacon on the top of a mountain, and like a banner on a hill.', pt: 'Pela ameaça de um só fugirão mil; e pela ameaça de cinco vós fugireis; até que fiqueis como o mastro no cume do monte, e como o estandarte sobre o outeiro.' },
      { v: 18, en: 'Therefore Yahweh will wait, that he may be gracious to you; and therefore he will be exalted, that he may have mercy on you, for Yahweh is a God of justice. Blessed are all those who wait for him.', pt: 'Por isso o Senhor esperará, para ter misericórdia de vós; e por isso se levantará, para se compadecer de vós; porque o Senhor é um Deus de eqüidade; bem-aventurados todos os que por ele esperam.' },
      { v: 19, en: 'For the people will dwell in Zion at Jerusalem. You will weep no more. He will surely be gracious to you at the voice of your cry. When he hears you, he will answer you.', pt: 'Na verdade o povo habitará em Sião, em Jerusalém; não chorarás mais; certamente se compadecerá de ti, à voz do teu clamor; e, ouvindo-a, te responderá.' },
      { v: 20, en: 'Though the Lord may give you the bread of adversity and the water of affliction, yet your teachers won’t be hidden any more, but your eyes will see your teachers;', pt: 'Embora vos dê o Senhor pão de angústia e água de aperto, contudo não se esconderão mais os teus mestres; antes os teus olhos os verão;' },
      { v: 21, en: 'and when you turn to the right hand, and when you turn to the left, your ears will hear a voice behind you, saying, “This is the way. Walk in it.”', pt: 'e os teus ouvidos ouvirão a palavra do que está por detrás de ti, dizendo: Este é o caminho, andai nele; quando vos desviardes para a direita ou para a esquerda.' },
      { v: 22, en: 'You shall defile the overlaying of your engraved images of silver, and the plating of your molten images of gold. You shall cast them away as an unclean thing. You shall tell it, “Go away!”', pt: 'E contaminareis a cobertura de prata das tuas imagens esculpidas, e o revestimento de ouro das tuas imagens fundidas; e as lançarás fora como coisa imunda; e lhes dirás: Fora daqui.' },
      { v: 23, en: 'He will give the rain for your seed, with which you will sow the ground; and bread of the increase of the ground will be rich and plentiful. In that day, your livestock will feed in large pastures.', pt: 'Então ele te dará chuva para a tua semente, com que semeares a terra, e trigo como produto da terra, o qual será pingue e abundante. Naquele dia o teu gado pastará em largos pastos.' },
      { v: 24, en: 'The oxen likewise and the young donkeys that till the ground will eat savory feed, which has been winnowed with the shovel and with the fork.', pt: 'Os bois e os jumentinhos que lavram a terra, comerão forragem com sal, que terá sido padejada com a pá e com o forcado,' },
      { v: 25, en: 'There shall be brooks and streams of water on every lofty mountain and on every high hill in the day of the great slaughter, when the towers fall.', pt: 'Sobre todo monte alto, e todo outeiro elevado haverá ribeiros e correntes de águas, no dia da grande matança, quando caírem as torres.' },
      { v: 26, en: 'Moreover the light of the moon will be like the light of the sun, and the light of the sun will be seven times brighter, like the light of seven days, in the day that Yahweh binds up the fracture of his people, and heals the wound they were struck with.', pt: 'E a luz da lua será como a luz do sol, e a luz do sol sete vezes maior, como a luz de sete dias, no dia em que o Senhor atar a contusão do seu povo, e curar a chaga da sua ferida.' },
      { v: 27, en: 'Behold, Yahweh’s name comes from far away, burning with his anger, and in thick rising smoke. His lips are full of indignation, and his tongue is as a devouring fire.', pt: 'Eis que o nome do Senhor vem de longe ardendo na sua ira, e com densa nuvem de fumaça; os seus lábios estão cheios de indignação, e a sua língua é como um fogo consumidor;' },
      { v: 28, en: 'His breath is as an overflowing stream that reaches even to the neck, to sift the nations with the sieve of destruction; and a bridle that leads to ruin will be in the jaws of the peoples.', pt: 'e a sua respiração é como o ribeiro transbordante, que chega até o pescoço, para peneirar as nações com peneira de destruição; e um freio de fazer errar estará nas queixadas dos povos.' },
      { v: 29, en: 'You will have a song, as in the night when a holy feast is kept; and gladness of heart, as when one goes with a flute to come to Yahweh’s mountain, to Israel’s Rock.', pt: 'um cântico haverá entre vós, como na noite em que se celebra uma festa santa; e alegria de coração, como a daquele que sai ao som da flauta para vir ao monte do Senhor, à Rocha de Israel.' },
      { v: 30, en: 'Yahweh will cause his glorious voice to be heard, and will show the descent of his arm, with the indignation of his anger, and the flame of a devouring fire, with a blast, storm, and hailstones.', pt: 'O Senhor fará ouvir a sua voz majestosa, e mostrará a descida do seu braço, na indignação da sua ira, e a labareda dum fogo consumidor, e tempestade forte, e dilúvio e pedra de saraiva.' },
      { v: 31, en: 'For through Yahweh’s voice the Assyrian will be dismayed. He will strike him with his rod.', pt: 'Com a voz do Senhor será desfeita em pedaços a Assíria, quando ele a ferir com a vara.' },
      { v: 32, en: 'Every stroke of the rod of punishment, which Yahweh will lay on him, will be with the sound of tambourines and harps. He will fight with them in battles, brandishing weapons.', pt: 'E a cada golpe do bordão de castigo, que o Senhor lhe der, haverá tamboris e harpas; e com combates de brandimento combaterá contra eles.' },
      { v: 33, en: 'For his burning place has long been ready. Yes, for the king it is prepared. He has made its pyre deep and large with fire and much wood. Yahweh’s breath, like a stream of sulfur, kindles it.', pt: 'Porque uma fogueira está, de há muito, preparada; sim, está preparada para o rei; fez-se profunda e larga; a sua pira é fogo, e tem muita lenha; o assopro do Senhor como torrente de enxofre a acende.' },
    ],
    31: [
      { v: 1, en: 'Woe to those who go down to Egypt for help, and rely on horses, and trust in chariots because they are many, and in horsemen because they are very strong, but they don’t look to the Holy One of Israel, and they don’t seek Yahweh!', pt: 'Ai dos que descem ao Egito a buscar socorro, e se estribam em cavalos, e têm confiança em carros, por serem muitos, e nos cavaleiros, por serem muito fortes; e não atentam para o Santo de Israel, e não buscam ao Senhor.' },
      { v: 2, en: 'Yet he also is wise, and will bring disaster, and will not call back his words, but will arise against the house of the evildoers, and against the help of those who work iniquity.', pt: 'Todavia também ele é sábio, e fará vir o mal, e não retirará as suas palavras; mas levantar-se-á contra a casa dos malfeitores, e contra a ajuda dos que praticam a iniqüidade.' },
      { v: 3, en: 'Now the Egyptians are men, and not God; and their horses flesh, and not spirit. When Yahweh stretches out his hand, both he who helps shall stumble, and he who is helped shall fall, and they all shall be consumed together.', pt: 'Ora os egípcios são homens, e não Deus; e os seus cavalos carne, e não espírito; e quando o Senhor estender a sua mão, tanto tropeçará quem dá auxílio, como cairá quem recebe auxílio, e todos juntamente serão consumidos.' },
      { v: 4, en: 'For Yahweh says to me, “As the lion and the young lion growling over his prey, if a multitude of shepherds is called together against him, will not be dismayed at their voice, nor abase himself for their noise, so Yahweh of Armies will come down to fight on Mount Zion and on its heights.', pt: 'Pois assim me diz o Senhor: Como o leão e o cachorro do leão rugem sobre a sua presa, e quando se convoca contra eles uma multidão de pastores não se espantam das suas vozes, nem se abstem pelo seu alarido, assim o Senhor dos exércitos descerá, para pelejar sobre o monte Sião, e sobre o seu outeiro.' },
      { v: 5, en: 'As birds hovering, so Yahweh of Armies will protect Jerusalem. He will protect and deliver it. He will pass over and preserve it.”', pt: 'Como aves quando adejam, assim o Senhor dos exércitos protegerá a Jerusalém; ele a protegerá e a livrará, e, passando, a salvará.' },
      { v: 6, en: 'Return to him from whom you have deeply revolted, children of Israel.', pt: 'Voltai-vos, filhos de Israel, para aquele contra quem vos tendes profundamente rebelado.' },
      { v: 7, en: 'For in that day everyone shall cast away his idols of silver and his idols of gold—sin which your own hands have made for you.', pt: 'Pois naquele dia cada um lançará fora os seus ídolos de prata, e os seus ídolos de ouro, que vos fabricaram as vossas mãos para pecardes.' },
      { v: 8, en: '“The Assyrian will fall by the sword, not of man; and the sword, not of mankind, shall devour him. He will flee from the sword, and his young men will become subject to forced labor.', pt: 'E o assírio cairá pela espada, não de varão; e a espada, não de homem, o consumirá; e fugirá perante a espada, e os seus mancebos serão sujeitos a trabalhos forçados.' },
      { v: 9, en: 'His rock will pass away by reason of terror, and his princes will be afraid of the banner,” says Yahweh, whose fire is in Zion, and his furnace in Jerusalem.', pt: 'A sua rocha passará de medo, e os seus oficiais em pânico desertarão da bandeira, diz o Senhor, cujo fogo está em Sião e em Jerusalém sua fornalha.' },
    ],
    32: [
      { v: 1, en: 'Behold, a king shall reign in righteousness, and princes shall rule in justice.', pt: 'Eis que reinará um rei com justiça, e com retidão governarão príncipes.' },
      { v: 2, en: 'A man shall be as a hiding place from the wind, and a covert from the storm, as streams of water in a dry place, as the shade of a large rock in a weary land.', pt: 'um varão servirá de abrigo contra o vento, e um refúgio contra a tempestade, como ribeiros de águas em lugares secos, e como a sombra duma grande penha em terra sedenta.' },
      { v: 3, en: 'The eyes of those who see will not be dim, and the ears of those who hear will listen.', pt: 'Os olhos dos que vêem não se ofuscarão, e os ouvidos dos que ouvem escutarão.' },
      { v: 4, en: 'The heart of the rash will understand knowledge, and the tongue of the stammerers will be ready to speak plainly.', pt: 'O coração dos imprudentes entenderá o conhecimento, e a língua dos gagos estará pronta para falar distintamente.' },
      { v: 5, en: 'The fool will no longer be called noble, nor the scoundrel be highly respected.', pt: 'Ao tolo nunca mais se chamará nobre, e do avarento nunca mais se dirá que é generoso.' },
      { v: 6, en: 'For the fool will speak folly, and his heart will work iniquity, to practice profanity, and to utter error against Yahweh, To make empty the soul of the hungry, and to cause the drink of the thirsty to fail.', pt: 'Pois o tolo fala tolices, e o seu coração trama iniqüidade, para cometer profanação e proferir mentiras contra o Senhor, para deixar com fome o faminto e fazer faltar a bebida ao sedento.' },
      { v: 7, en: 'The ways of the scoundrel are evil. He devises wicked plans to destroy the humble with lying words, even when the needy speaks right.', pt: 'Também as maquinações do fraudulento são más; ele maquina invenções malignas para destruir os mansos com palavras falsas, mesmo quando o pobre fala o que é reto.' },
      { v: 8, en: 'But the noble devises noble things; and he will continue in noble things.', pt: 'Mas o nobre projeta coisas nobres; e nas coisas nobres persistirá.' },
      { v: 9, en: 'Rise up, you women who are at ease! Hear my voice! You careless daughters, give ear to my speech!', pt: 'Levantai-vos, mulheres que estais sossegadas e ouvi a minha voz; e vós, filhas, que estais , tão seguras, inclinai os ouvidos às minhas palavras.' },
      { v: 10, en: 'For days beyond a year you will be troubled, you careless women; for the vintage shall fail. The harvest won’t come.', pt: 'Num ano e dias vireis a ser perturbadas, ó mulheres que tão seguras estais; pois a vindima falhará, e a colheita não virá.' },
      { v: 11, en: 'Tremble, you women who are at ease! Be troubled, you careless ones! Strip yourselves, make yourselves naked, and put sackcloth on your waist.', pt: 'Tremei, mulheres que estais sossegadas, e turbai-vos, vós que estais tão seguras; despi-vos e ponde-vos nuas, e cingi com saco os vossos lombos.' },
      { v: 12, en: 'Beat your breasts for the pleasant fields, for the fruitful vine.', pt: 'Batei nos peitos pelos campos aprazíveis, e pela vinha frutífera;' },
      { v: 13, en: 'Thorns and briers will come up on my people’s land; yes, on all the houses of joy in the joyous city.', pt: 'pela terra do meu povo, que produz espinheiros e sarças, e por todas as casas de alegria, na cidade jubilosa.' },
      { v: 14, en: 'For the palace will be forsaken. The populous city will be deserted. The hill and the watchtower will be for dens forever, a delight for wild donkeys, a pasture of flocks;', pt: 'Porque o palácio será abandonado, a cidade populosa ficará deserta; e o outeiro e a torre da guarda servirão de cavernas para sempre, para alegria dos asnos monteses, e para pasto dos rebanhos;' },
      { v: 15, en: 'Until the Spirit is poured on us from on high, and the wilderness becomes a fruitful field, and the fruitful field is considered a forest.', pt: 'até que se derrame sobre nós o espírito lá do alto, e o deserto se torne em campo fértil, e o campo fértil seja reputado por um bosque.' },
      { v: 16, en: 'Then justice will dwell in the wilderness; and righteousness will remain in the fruitful field.', pt: 'Então o juízo habitará no deserto, e a justiça morará no campo fértil.' },
      { v: 17, en: 'The work of righteousness will be peace; and the effect of righteousness, quietness and confidence forever.', pt: 'E a obra da justiça será paz; e o efeito da justiça será sossego e segurança para sempre.' },
      { v: 18, en: 'My people will live in a peaceful habitation, in safe dwellings, and in quiet resting places.', pt: 'O meu povo habitará em morada de paz, em moradas bem seguras, e em lugares quietos de descanso.' },
      { v: 19, en: 'Though hail flattens the forest, and the city is leveled completely.', pt: 'Mas haverá saraiva quando cair o bosque; e a cidade será inteiramente abatida.' },
      { v: 20, en: 'Blessed are you who sow beside all waters, who send out the feet of the ox and the donkey.', pt: 'Bem-aventurados sois vós os que semeais junto a todas as águas, que deixais livres os pés do boi e do jumento.' },
    ],
    33: [
      { v: 1, en: 'Woe to you who destroy, but you weren’t destroyed; and who betray, but nobody betrayed you! When you have finished destroying, you will be destroyed; and when you have finished betrayal, you will be betrayed.', pt: 'Ai de ti que despojas, e que não foste despojado; e que procedes perfidamente, e que não foste tratado perfidamente! quando acabares de destruir, serás destruído; e, quando acabares de tratar perfidamente, perfidamente te tratarão.' },
      { v: 2, en: 'Yahweh, be gracious to us. We have waited for you. Be our strength every morning, our salvation also in the time of trouble.', pt: 'ç Senhor, tem misericórdia de nós; por ti temos esperado. Sê tu o nosso braço cada manhã, como também a nossa salvação no tempo da tribulação.' },
      { v: 3, en: 'At the noise of the thunder, the peoples have fled. When you lift yourself up, the nations are scattered.', pt: 'Ao ruído do tumulto fogem os povos; à tua exaltação as nações são dispersas.' },
      { v: 4, en: 'Your plunder will be gathered as the caterpillar gathers. Men will leap on it as locusts leap.', pt: 'Então ajuntar-se-á o vosso despojo como ajunta a lagarta; como os gafanhotos saltam, assim sobre ele saltarão os homens.' },
      { v: 5, en: 'Yahweh is exalted, for he dwells on high. He has filled Zion with justice and righteousness.', pt: 'O Senhor é exalçado, pois habita nas alturas; encheu a Sião de retidão e justiça.' },
      { v: 6, en: 'There will be stability in your times, abundance of salvation, wisdom, and knowledge. The fear of Yahweh is your treasure.', pt: 'Será ele a estabilidade dos teus tempos, abundância de salvação, sabedoria, e conhecimento; e o temor do Senhor é o seu tesouro.' },
      { v: 7, en: 'Behold, their valiant ones cry outside; the ambassadors of peace weep bitterly.', pt: 'Eis que os valentes estão clamando de fora; e os embaixadores da paz estão chorando amargamente.' },
      { v: 8, en: 'The highways are desolate. The traveling man ceases. The covenant is broken. He has despised the cities. He doesn’t respect man.', pt: 'As estradas estão desoladas, cessam os que passam pelas veredas; alianças se rompem, testemunhas se desprezam, e não se faz caso dos homens.' },
      { v: 9, en: 'The land mourns and languishes. Lebanon is confounded and withers away. Sharon is like a desert, and Bashan and Carmel are stripped bare.', pt: 'A terra pranteia, desfalece; o Líbano se envergonha e se murcha; Sarom se tornou como um deserto; Basã e Carmelo ficam despidos de folhas.' },
      { v: 10, en: '“Now I will arise,” says Yahweh; “Now I will lift myself up. Now I will be exalted.', pt: 'Agora me levantarei, diz o Senhor; agora me erguerei; agora serei exaltado.' },
      { v: 11, en: 'You will conceive chaff. You will give birth to stubble. Your breath is a fire that will devour you.', pt: 'Concebeis palha, produzis restolho; e o vosso fôlego é um fogo que vos devorará.' },
      { v: 12, en: 'The peoples will be like the burning of lime, like thorns that are cut down and burned in the fire.', pt: 'E os povos serão como as queimas de cal, como espinhos cortados que são queimados no fogo.' },
      { v: 13, en: 'Hear, you who are far off, what I have done; and, you who are near, acknowledge my might.”', pt: 'Ouvi, vós os que estais longe, o que tenho feito; e vós, que estais vizinhos, reconhecei o meu poder.' },
      { v: 14, en: 'The sinners in Zion are afraid. Trembling has seized the godless ones. Who among us can live with the devouring fire? Who among us can live with everlasting burning?', pt: 'Os pecadores de Sião se assombraram; o tremor apoderou-se dos ímpios. Quem dentre nós pode habitar com o fogo consumidor? quem dentre nós pode habitar com as labaredas eternas?' },
      { v: 15, en: 'He who walks righteously, and speaks blamelessly; He who despises the gain of oppressions, who gestures with his hands, refusing to take a bribe, who stops his ears from hearing of blood, and shuts his eyes from looking at evil—', pt: 'Aquele que anda em justiça, e fala com retidão; aquele que rejeita o ganho da opressão; que sacode as mãos para não receber peitas; o que tapa os ouvidos para não ouvir falar do derramamento de sangue, e fecha os olhos para não ver o mal;' },
      { v: 16, en: 'he will dwell on high. His place of defense will be the fortress of rocks. His bread will be supplied. His waters will be sure.', pt: 'este habitará nas alturas; as fortalezas das rochas serão o seu alto refúgio; dar-se-lhe-á o seu pão; as suas águas serão certas.' },
      { v: 17, en: 'Your eyes will see the king in his beauty. They will see a distant land.', pt: 'Os teus olhos verão o rei na sua formosura, e verão a terra que se estende em amplidão.' },
      { v: 18, en: 'Your heart will meditate on the terror. Where is he who counted? Where is he who weighed? Where is he who counted the towers?', pt: 'O teu coração meditará no terror, dizendo: Onde está aquele que serviu de escrivão? onde está o que pesou o tributo? onde está o que contou as torres?' },
      { v: 19, en: 'You will no longer see the fierce people, a people of a deep speech that you can’t comprehend, with a strange language that you can’t understand.', pt: 'Não verás mais aquele povo feroz, povo de fala obscura, que não se pode compreender, e de língua tão estranha que não se pode entender.' },
      { v: 20, en: 'Look at Zion, the city of our appointed festivals. Your eyes will see Jerusalem, a quiet habitation, a tent that won’t be removed. Its stakes will never be plucked up, nor will any of its cords be broken.', pt: 'Olha para Sião, a cidade das nossas festas solenes; os teus olhos verão a Jerusalém, habitação quieta, tenda que não será removida, cujas estacas nunca serão arrancadas, e das suas cordas nenhuma se quebrará.' },
      { v: 21, en: 'But there Yahweh will be with us in majesty, a place of wide rivers and streams, in which no galley with oars will go, neither will any gallant ship pass by there.', pt: 'Mas o Senhor ali estará conosco em majestade, nesse lugar de largos rios e correntes, no qual não entrará barco de remo, nem por ele passará navio grande.' },
      { v: 22, en: 'For Yahweh is our judge. Yahweh is our lawgiver. Yahweh is our king. He will save us.', pt: 'Porque o Senhor é o nosso juiz; o Senhor é nosso legislador; o Senhor é o nosso rei; ele nos salvará.' },
      { v: 23, en: 'Your rigging is untied. They couldn’t strengthen the foot of their mast. They couldn’t spread the sail. Then the prey of a great plunder was divided. The lame took the prey.', pt: 'As tuas cordas ficaram frouxas; elas não puderam ter firme o seu mastro, nem servir para estender a vela; então a presa de abundantes despojos se repartirá; e ate os coxos participarão da presa.' },
      { v: 24, en: 'The inhabitant won’t say, “I am sick.” The people who dwell therein will be forgiven their iniquity.', pt: 'E morador nenhum dirá: Enfermo estou; o povo que nela habitar será perdoado da sua iniqüidade.' },
    ],
    34: [
      { v: 1, en: 'Come near, you nations, to hear! Listen, you peoples. Let the earth and all it contains hear; the world, and everything that comes from it.', pt: 'Chegai-vos, nações, para ouvir, e vós, povos, escutai; ouça a terra, e a sua plenitude, o mundo e tudo quanto ele produz.' },
      { v: 2, en: 'For Yahweh is enraged against all the nations, and angry with all their armies. He has utterly destroyed them. He has given them over for slaughter.', pt: 'Porque a indignação do Senhor está sobre todas as nações, e o seu furor sobre todo o exército delas; ele determinou a sua destruição, entregou-as à matança.' },
      { v: 3, en: 'Their slain will also be cast out, and the stench of their dead bodies will come up; and the mountains will melt in their blood.', pt: 'E os seus mortos serão arrojados, e dos seus cadáveres subirá o mau cheiro; e com o seu sangue os montes se derreterão.' },
      { v: 4, en: 'All of the army of the sky will be dissolved. The sky will be rolled up like a scroll, and all its armies will fade away, as a leaf fades from off a vine or a fig tree.', pt: 'E todo o exército dos céus se dissolverá, e o céu se enrolará como um livro; e todo o seu exército desvanecerá, como desvanece a folha da vide e da figueira.' },
      { v: 5, en: 'For my sword has drunk its fill in the sky. Behold, it will come down on Edom, and on the people of my curse, for judgment.', pt: 'Pois a minha espada se embriagou no céu; eis que sobre Edom descerá, e sobre o povo do meu anátema, para exercer juízo.' },
      { v: 6, en: 'Yahweh’s sword is filled with blood. It is covered with fat, with the blood of lambs and goats, with the fat of the kidneys of rams; for Yahweh has a sacrifice in Bozrah, And a great slaughter in the land of Edom.', pt: 'A espada do Senhor está cheia de sangue, está cheia de gordura, de sangue de cordeiros e de bodes, da gordura dos rins de carneiros; porque o Senhor tem sacrifício em Bozra, e grande matança na terra de Edom.' },
      { v: 7, en: 'The wild oxen will come down with them, and the young bulls with the mighty bulls; and their land will be drunken with blood, and their dust made greasy with fat.', pt: 'E os bois selvagens cairão com eles, e os novilhos com os touros; e a sua terra embriagar-se-á de sangue, e o seu pó se engrossará de gordura.' },
      { v: 8, en: 'For Yahweh has a day of vengeance, a year of recompense for the cause of Zion.', pt: 'Pois o Senhor tem um dia de vingança, um ano de retribuições pela causa de Sião.' },
      { v: 9, en: 'Its streams will be turned into pitch, its dust into sulfur, And its land will become burning pitch.', pt: 'E os ribeiros de Edom transformarse-ão em pez, e o seu solo em enxofre, e a sua terra tornar-se-á em pez ardente.' },
      { v: 10, en: 'It won’t be quenched night nor day. Its smoke will go up forever. From generation to generation, it will lie waste. No one will pass through it forever and ever.', pt: 'Nem de noite nem de dia se apagará; para sempre a sua fumaça subirá; de geração em geração será assolada; pelos séculos dos séculos ninguém passará por ela.' },
      { v: 11, en: 'But the pelican and the porcupine will possess it. The owl and the raven will dwell in it. He will stretch the line of confusion over it, and the plumb line of emptiness.', pt: 'Mas o pelicano e o ouriço a possuirão; a coruja e o corvo nela habitarão; e ele estenderá sobre ela o cordel de confusão e o prumo de vaidade.' },
      { v: 12, en: 'They shall call its nobles to the kingdom, but none shall be there; and all its princes shall be nothing.', pt: 'Eles chamarão ao reino os seus nobres, mas nenhum haverá; e todos os seus príncipes não serão coisa nenhuma.' },
      { v: 13, en: 'Thorns will come up in its palaces, nettles and thistles in its fortresses; and it will be a habitation of jackals, a court for ostriches.', pt: 'E crescerão espinhos nos seus palácios, urtigas e cardos nas suas fortalezas; e será uma habitação de chacais, um sítio para avestruzes.' },
      { v: 14, en: 'The wild animals of the desert will meet with the wolves, and the wild goat will cry to his fellow. Yes, the night creature shall settle there, and shall find herself a place of rest.', pt: 'E as feras do deserto se encontrarão com hienas; e o sátiro clamará ao seu companheiro; e Lilite pousará ali, e achará lugar de repouso para si.' },
      { v: 15, en: 'The arrow snake will make her nest there, and lay, hatch, and gather under her shade. Yes, the kites will be gathered there, every one with her mate.', pt: 'Ali fará a coruja o seu ninho, e porá os seus ovos, e aninhará os seus filhotes, e os recolherá debaixo da sua sombra; também ali se ajuntarão os abutres, cada fêmea com o seu companheiro.' },
      { v: 16, en: 'Search in the book of Yahweh, and read: not one of these will be missing. None will lack her mate. For my mouth has commanded, and his Spirit has gathered them.', pt: 'Buscai no livro do Senhor, e lede: nenhuma destas criaturas faltará, nenhuma será privada do seu companheiro; porque é a boca dele que o ordenou, e é o seu espírito que os ajuntou.' },
      { v: 17, en: 'He has cast the lot for them, and his hand has divided it to them with a measuring line. They shall possess it forever. From generation to generation they will dwell in it.', pt: 'Ele mesmo lançou as sortes por eles, e a sua mão lhes repartiu a terra com o cordel; para sempre a possuirão; de geração em geração habitarão nela.' },
    ],
    35: [
      { v: 1, en: 'The wilderness and the dry land will be glad. The desert will rejoice and blossom like a rose.', pt: 'O deserto e a terra sedenta se regozijarão; e o ermo exultará e florescerá;' },
      { v: 2, en: 'It will blossom abundantly, and rejoice even with joy and singing. Lebanon’s glory will be given to it, the excellence of Carmel and Sharon. They will see Yahweh’s glory, the excellence of our God.', pt: 'como o narciso florescerá abundantemente, e também exultará de júbilo e romperá em cânticos; dar-se-lhe-á a glória do Líbano, a excelência do Carmelo e Sarom; eles verão a glória do Senhor, a majestade do nosso Deus.' },
      { v: 3, en: 'Strengthen the weak hands, and make firm the feeble knees.', pt: 'Fortalecei as mãos fracas, e firmai os joelhos trementes.' },
      { v: 4, en: 'Tell those who have a fearful heart, “Be strong. Don’t be afraid. Behold, your God will come with vengeance, God’s retribution. He will come and save you.', pt: 'Dizei aos turbados de coração: Sede fortes, não temais; eis o vosso Deus! com vingança virá, sim com a recompensa de Deus; ele virá, e vos salvará.' },
      { v: 5, en: 'Then the eyes of the blind will be opened, and the ears of the deaf will be unstopped.', pt: 'Então os olhos dos cegos serão abertos, e os ouvidos dos surdos se desimpedirão.' },
      { v: 6, en: 'Then the lame man will leap like a deer, and the tongue of the mute will sing; for waters will break out in the wilderness, and streams in the desert.', pt: 'Então o coxo saltará como o cervo, e a língua do mudo cantará de alegria; porque águas arrebentarão no deserto e ribeiros no ermo.' },
      { v: 7, en: 'The burning sand will become a pool, and the thirsty ground springs of water. Grass with reeds and rushes will be in the habitation of jackals, where they lay.', pt: 'E a miragem tornar-se-á em lago, e a terra sedenta em mananciais de águas; e nas habitações em que jaziam os chacais haverá erva com canas e juncos.' },
      { v: 8, en: 'A highway will be there, a road, and it will be called The Holy Way. The unclean shall not pass over it, but it will be for those who walk in the Way. Wicked fools will not go there.', pt: 'E ali haverá uma estrada, um caminho que se chamará o caminho santo; o imundo não passará por ele, mas será para os remidos. Os caminhantes, até mesmo os loucos, nele não errarão.' },
      { v: 9, en: 'No lion will be there, nor will any ravenous animal go up on it. They will not be found there; but the redeemed will walk there.', pt: 'Ali não haverá leão, nem animal feroz subirá por ele, nem se achará nele; mas os redimidos andarão por ele.' },
      { v: 10, en: 'The Yahweh’s ransomed ones will return, and come with singing to Zion; and everlasting joy will be on their heads. They will obtain gladness and joy, and sorrow and sighing will flee away.”', pt: 'E os resgatados do Senhor voltarão; e virão a Sião com júbilo, e alegria eterna haverá sobre as suas cabeças; gozo e alegria alcançarão, e deles fugirá a tristeza e o gemido.' },
    ],
    36: [
      { v: 1, en: 'Now in the fourteenth year of king Hezekiah, Sennacherib king of Assyria attacked all of the fortified cities of Judah, and captured them.', pt: 'No ano décimo quarto do rei Ezequias Senaqueribe, rei da Assíria, subiu contra todas as cidades fortificadas de Judá, e as tomou.' },
      { v: 2, en: 'The king of Assyria sent Rabshakeh from Lachish to Jerusalem to king Hezekiah with a large army. He stood by the aqueduct from the upper pool in the fuller’s field highway.', pt: 'Ora, o rei da Assíria enviou Rabsaqué, de Laquis a Jerusalém, ao rei Ezequias, com um grande exército; e ele parou junto ao aqueduto da piscina superior, que está junto ao caminho do campo do lavandeiro.' },
      { v: 3, en: 'Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder came out to him.', pt: 'Então saíram a ter com ele Eliaquim, filho de Hilquias, o mordomo, e Sebna, o escrivão, e Joá, filho de Asafe, o cronista.' },
      { v: 4, en: 'Rabshakeh said to them, “Now tell Hezekiah, ‘Thus says the great king, the king of Assyria, “What confidence is this in which you trust?', pt: 'E Rabsaqué lhes disse: Ora, dizei a Ezequias: Assim diz o grande rei, o rei da Assíria: Que confiança é essa em que te estribas?' },
      { v: 5, en: 'I say that your counsel and strength for the war are only vain words. Now in whom do you trust, that you have rebelled against me?', pt: 'Bem posso eu dizer: Teu conselho e poder para a guerra são apenas vãs palavras. Em quem pois agora confias, visto que contra mim te rebelas?' },
      { v: 6, en: 'Behold, you trust in the staff of this bruised reed, even in Egypt, which if a man leans on it, it will go into his hand and pierce it. So is Pharaoh king of Egypt to all who trust in him.', pt: 'Eis que confias no Egito, aquele bordão de cana quebrada que, se alguém se apoiar nele, lhe entrará pela mão, e a furará; assim é Faraó, rei do Egito, para com todos os que nele confiam.' },
      { v: 7, en: 'But if you tell me, ‘We trust in Yahweh our God,’ isn’t that he whose high places and whose altars Hezekiah has taken away, and has said to Judah and to Jerusalem, ‘You shall worship before this altar?’”', pt: 'Mas se me disseres: No Senhor, nosso Deus, confiamos; porventura não é esse aquele cujos altos e cujos altares Ezequias tirou, e disse a Judá e a Jerusalém: Perante este altar adorareis?' },
      { v: 8, en: 'Now therefore, please make a pledge to my master the king of Assyria, and I will give you two thousand horses, if you are able on your part to set riders on them.', pt: 'Ora, pois, faze uma aposta com o meu senhor, o rei da Assíria; dar-te-ei dois mil cavalos, se tu puderes dar cavaleiros para eles.' },
      { v: 9, en: 'How then can you turn away the face of one captain of the least of my master’s servants, and put your trust on Egypt for chariots and for horsemen?', pt: 'Como então poderás repelir um só príncipe dos menores servos do meu senhor, quando confias no Egito pelos carros e cavaleiros?' },
      { v: 10, en: 'Have I come up now without Yahweh against this land to destroy it? Yahweh said to me, “Go up against this land, and destroy it.”’”', pt: 'Porventura subi eu agora sem o Senhor contra esta terra, para destruí-la? O Senhor mesmo me disse: Sobe contra esta terra, e destrói-a.' },
      { v: 11, en: 'Then Eliakim, Shebna and Joah said to Rabshakeh, “Please speak to your servants in Aramaic, for we understand it; and don’t speak to us in the Jews’ language in the hearing of the people who are on the wall.”', pt: 'Então disseram Eliaquim, Sebna, e Joá, a Rabsaqué: Pedimos- te que fales aos teus servos em aramaico, porque bem o entendemos; e não nos fales em judaico, aos ouvidos do povo que está sobre o muro.' },
      { v: 12, en: 'But Rabshakeh said, “Has my master sent me only to your master and to you, to speak these words, and not to the men who sit on the wall, who will eat their own dung and drink their own urine with you?”', pt: 'Rabsaqué, porém, disse: Porventura mandou-me o meu senhor só ao teu senhor e a ti, para dizer estas palavras e não aos homens que estão assentados sobre o muro, que juntamente convosco hão de comer o próprio excremento e beber a propria urina?' },
      { v: 13, en: 'Then Rabshakeh stood, and called out with a loud voice in the Jews’ language, and said, “Hear the words of the great king, the king of Assyria!', pt: 'Então Rabsaqué se pôs em pé, e clamou em alta voz na língua judaica, e disse: Ouvi as palavras do grande rei, do rei da Assíria.' },
      { v: 14, en: 'Thus says the king, ‘Don’t let Hezekiah deceive you; for he will not be able to deliver you.', pt: 'Assim diz o rei: Não vos engane Ezequias; porque não vos poderá livrar.' },
      { v: 15, en: 'Don’t let Hezekiah make you trust in Yahweh, saying, “Yahweh will surely deliver us. This city won’t be given into the hand of the king of Assyria.”’', pt: 'Nem tampouco Ezequias vos faça confiar no Senhor, dizendo: Infalivelmente nos livrará o Senhor, e esta cidade não será entregue nas mãos do rei da Assíria.' },
      { v: 16, en: 'Don’t listen to Hezekiah, for thus says the king of Assyria, ‘Make your peace with me, and come out to me; and each of you eat from his vine, and each one from his fig tree, and each one of you drink the waters of his own cistern;', pt: 'Não deis ouvidos a Ezequias; porque assim diz o rei da Assíria: Fazei as vossas pazes comigo, e saí a mim; e coma cada um da sua vide, e da sua figueira, e beba cada um da água da sua cisterna;' },
      { v: 17, en: 'until I come and take you away to a land like your own land, a land of grain and new wine, a land of bread and vineyards.', pt: 'até que eu venha, e vos leve para uma terra semelhante à vossa, terra de trigo e de mosto, terra de pão e de vinhas.' },
      { v: 18, en: 'Beware lest Hezekiah persuade you, saying, “Yahweh will deliver us.” Have any of the gods of the nations delivered their lands from the hand of the king of Assyria?', pt: 'Guardai-vos, para que não vos engane Ezequias, dizendo: O Senhor nos livrará. Porventura os deuses das nações livraram cada um a sua terra das mãos do rei da Assíria?' },
      { v: 19, en: 'Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Have they delivered Samaria from my hand?', pt: 'Onde estão os deuses de Hamate e de Arpade? onde estão os deuses de Sefarvaim? porventura livraram eles a Samária da minha mão?' },
      { v: 20, en: 'Who are they among all the gods of these countries that have delivered their country out of my hand, that Yahweh should deliver Jerusalem out of my hand?’”', pt: 'Quais dentre todos os deuses destes países livraram a sua terra das minhas mãos, para que o Senhor possa livrar a Jerusalém das minhas mãos?' },
      { v: 21, en: 'But they remained silent, and said nothing in reply, for the king’s commandment was, “Don’t answer him.”', pt: 'Eles, porém, se calaram e não lhe responderam palavra; porque havia mandado do rei, dizendo: Não lhe respondais.' },
      { v: 22, en: 'Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, came to Hezekiah with their clothes torn, and told him the words of Rabshakeh.', pt: 'Então Eliaquim, filho de Hilquias, o mordomo, e Sebna, o escrivão, e Joá, filho de Asafe, o cronista, vieram a Ezequias, com as vestiduras rasgadas, e lhe referiram as palavras de Rabsaqué.' },
    ],
    37: [
      { v: 1, en: 'When king Hezekiah heard it, he tore his clothes, covered himself with sackcloth, and went into Yahweh’s house.', pt: 'Tendo ouvido isso o rei Ezequias, rasgou as suas vestes, e se cobriu de saco, e entrou na casa do Senhor.' },
      { v: 2, en: 'He sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to Isaiah the prophet, the son of Amoz.', pt: 'Também enviou Eliaquim, o mordomo, Sebna, o escrivão, e os anciãos dos sacerdotes, cobertos de saco, a Isaías, filho de Amoz, o profeta,' },
      { v: 3, en: 'They said to him, “Thus says Hezekiah, ‘Today is a day of trouble, and of rebuke, and of rejection; for the children have come to the birth, and there is no strength to give birth.', pt: 'para lhe dizerem: Assim diz Ezequias: Este dia é dia de angústia e de vitupérios, e de blasfêmias, porque chegados são os filhos ao parto, e força não há para os dar à luz.' },
      { v: 4, en: 'It may be Yahweh your God will hear the words of Rabshakeh, whom the king of Assyria his master has sent to defy the living God, and will rebuke the words which Yahweh your God has heard. Therefore lift up your prayer for the remnant that is left.’”', pt: 'Porventura o Senhor teu Deus terá ouvido as palavras de Rabsaqué, a quem enviou o rei da Assíria, seu amo, para afrontar o Deus vivo, e para o vituperar com as palavras que o Senhor teu Deus tem ouvido; faze oração pelo resto que ficou.' },
      { v: 5, en: 'So the servants of king Hezekiah came to Isaiah.', pt: 'Foram, pois, os servos do rei Ezequias ter com Isaías,' },
      { v: 6, en: 'Isaiah said to them, “Tell your master, ‘Yahweh says, “Don’t be afraid of the words that you have heard, with which the servants of the king of Assyria have blasphemed me.', pt: 'e Isaías lhes disse: Dizei a vosso amo: Assim diz o Senhor: Não temas à vista das palavras que ouviste, com as quais os servos do rei da Assíria me blasfemaram.' },
      { v: 7, en: 'Behold, I will put a spirit in him and he will hear news, and will return to his own land. I will cause him to fall by the sword in his own land.”’”', pt: 'Eis que meterei nele um espírito, e ele ouvirá uma nova, e voltará para a sua terra; e fá-lo-ei cair morto à espada na sua própria terra.' },
      { v: 8, en: 'So Rabshakeh returned, and found the king of Assyria warring against Libnah, for he had heard that he was departed from Lachish.', pt: 'Voltou pois Rabsaqué, e achou o rei da Assíria pelejando contra Libna; porque ouvira que se havia retirado de Laquis.' },
      { v: 9, en: 'He heard news concerning Tirhakah king of Ethiopia, “He has come out to fight against you.” When he heard it, he sent messengers to Hezekiah, saying,', pt: 'Então ouviu ele dizer a respeito de Tiraca, rei da Etiópia: Saiu para te fazer guerra. Assim que ouviu isto, enviou mensageiros a Ezequias, dizendo:' },
      { v: 10, en: '“Thus you shall speak to Hezekiah king of Judah, saying, ‘Don’t let your God in whom you trust deceive you, saying, “Jerusalem won’t be given into the hand of the king of Assyria.”', pt: 'Assim falareis a Ezequias, rei de Judá: Não te engane o teu Deus, em quem confias, dizendo: Jerusalém não será entregue na mão do rei da Assíria.' },
      { v: 11, en: 'Behold, you have heard what the kings of Assyria have done to all lands, by destroying them utterly. Shall you be delivered?', pt: 'Eis que já tens ouvido o que fizeram os reis da Assíria a todas as terras, destruindo-as totalmente; e serás tu livrado?' },
      { v: 12, en: 'Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, Haran, Rezeph, and the children of Eden who were in Telassar?', pt: 'Porventura as livraram os deuses das nações que meus pais destruíram: Gozã, e Harã, e Rezefe, e os filhos de Edem que estavam em Telassar?' },
      { v: 13, en: 'Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?’”', pt: 'Onde está o rei de Hamate, e o rei de Arpade, e o rei da cidade de Sefarvaim, Hena e Iva?' },
      { v: 14, en: 'Hezekiah received the letter from the hand of the messengers and read it. Then Hezekiah went up to Yahweh’s house, and spread it before Yahweh.', pt: 'Recebendo pois Ezequias as cartas das mãos dos mensageiros, e lendo-as, subiu à casa do Senhor; e Ezequias as estendeu perante o Senhor.' },
      { v: 15, en: 'Hezekiah prayed to Yahweh, saying,', pt: 'E orou Ezequias ao Senhor, dizendo:' },
      { v: 16, en: '“Yahweh of Armies, the God of Israel, who is enthroned among the cherubim, you are the God, even you alone, of all the kingdoms of the earth. You have made heaven and earth.', pt: 'O Senhor dos exércitos, Deus de Israel, tu que estás sentado sobre os querubins; tu, só tu, és o Deus de todos os reinos da terra; tu fizeste o céu e a terra.' },
      { v: 17, en: 'Turn your ear, Yahweh, and hear. Open your eyes, Yahweh, and behold. Hear all of the words of Sennacherib, who has sent to defy the living God.', pt: 'Inclina, ó Senhor, o teu ouvido, e ouve; abre, Senhor, os teus olhos, e vê; e ouve todas as palavras de Senaqueribe, as quais ele mandou para afrontar o Deus vivo.' },
      { v: 18, en: 'Truly, Yahweh, the kings of Assyria have destroyed all the countries and their land,', pt: 'Verdade é, Senhor, que os reis da Assíria têm assolado todos os países, e suas terras,' },
      { v: 19, en: 'and have cast their gods into the fire; for they were no gods, but the work of men’s hands, wood and stone; therefore they have destroyed them.', pt: 'e lançado no fogo os seus deuses; porque deuses não eram, mas obra de mãos de homens, madeira e pedra; por isso os destruíram.' },
      { v: 20, en: 'Now therefore, Yahweh our God, save us from his hand, that all the kingdoms of the earth may know that you are Yahweh, even you only.”', pt: 'Agora, pois, ó Senhor nosso Deus, livra-nos da sua mão, para que todos os reinos da terra saibam que só tu és o Senhor.' },
      { v: 21, en: 'Then Isaiah the son of Amoz sent to Hezekiah, saying, “Yahweh, the God of Israel says, ‘Because you have prayed to me against Sennacherib king of Assyria,', pt: 'Então Isaías, filho de Amoz, mandou dizer a Ezequias: Assim diz o Senhor, o Deus de Israel: Portanto me fizeste a tua súplica contra Senaqueribe, rei de Assíria,' },
      { v: 22, en: 'this is the word which Yahweh has spoken concerning him. The virgin daughter of Zion has despised you and ridiculed you. The daughter of Jerusalem has shaken her head at you.', pt: 'esta é a palavra que o Senhor falou a respeito dele: A virgem, a filha de Sião, te despreza, e de ti zomba; a filha de Jerusalém meneia a cabeça por detrás de ti.' },
      { v: 23, en: 'Whom have you defied and blasphemed? Against whom have you exalted your voice and lifted up your eyes on high? Against the Holy One of Israel.', pt: 'A quem afrontaste e de quem blasfemaste? contra quem alçaste a voz e ergueste os teus olhos ao alto? Contra o Santo de Israel.' },
      { v: 24, en: 'By your servants, have you defied the Lord, and have said, “With the multitude of my chariots I have come up to the height of the mountains, to the innermost parts of Lebanon. I will cut down its tall cedars and its choice cypress trees. I will enter into its farthest height, the forest of its fruitful field.', pt: 'Por meio de teus servos afrontaste o Senhor, e disseste: Com a multidão dos meus carros subi eu aos cumes dos montes, aos últimos recessos do Líbano; e cortei os seus altos cedros e as suas faias escolhidas; e entrei no seu cume mais elevado, no bosque do seu campo fértil.' },
      { v: 25, en: 'I have dug and drunk water, and with the sole of my feet I will dry up all the rivers of Egypt.”', pt: 'Eu cavei, e bebi as águas; e com as plantas de meus pés sequei todos os rios do Egito.' },
      { v: 26, en: '“‘Have you not heard how I have done it long ago, and formed it in ancient times? Now I have brought it to pass, that it should be yours to destroy fortified cities, turning them into ruinous heaps.', pt: 'Não ouviste que já há muito tempo eu fiz isso, e que já desde os dias antigos o tinha determinado? Agora porém o executei, para que fosses tu o que reduzisses as cidades fortificadas a montões de ruínas.' },
      { v: 27, en: 'Therefore their inhabitants had little power. They were dismayed and confounded. They were like the grass of the field, and like the green herb, like the grass on the housetops, and like a field before its crop has grown.', pt: 'Por isso os seus moradores, dispondo de pouca força, andaram atemorizados e envergonhados; tornaram-se como a erva do campo, e como a relva verde, e como o feno dos telhados ou dum campo, que se queimaram antes de amadurecer.' },
      { v: 28, en: 'But I know your sitting down, your going out, your coming in, and your raging against me.', pt: 'Mas eu conheço o teu sentar, o teu sair e o teu entrar, e o teu furor contra mim.' },
      { v: 29, en: 'Because of your raging against me, and because your arrogance has come up into my ears, therefore will I put my hook in your nose and my bridle in your lips, and I will turn you back by the way by which you came.', pt: 'Por causa do teu furor contra mim, e porque a tua arrogância subiu até os meus ouvidos, portanto porei o meu anzol no teu nariz e o meu freio na tua boca, e te farei voltar pelo caminho por onde vieste.' },
      { v: 30, en: '“‘This shall be the sign to you. You will eat this year that which grows of itself, and in the second year that which springs from the same; and in the third year sow and reap and plant vineyards, and eat their fruit.', pt: 'E isto te será por sinal: este ano comereis o que espontaneamente nascer, e no segundo ano o que daí proceder; e no terceiro ano semeai e colhei, plantai vinhas, e comei os frutos delas.' },
      { v: 31, en: 'The remnant that is escaped of the house of Judah will again take root downward, and bear fruit upward.', pt: 'Pois o restante da casa de Judá, que sobreviveu, tornará a lançar raízes para baixo, e dará fruto para cima.' },
      { v: 32, en: 'For out of Jerusalem a remnant will go out, and survivors will escape from Mount Zion. The zeal of Yahweh of Armies will perform this.’', pt: 'Porque de Jerusalém sairá o restante, e do monte Sião os que escaparam; o zelo do Senhor dos exércitos fará isso.' },
      { v: 33, en: '“Therefore Yahweh says concerning the king of Assyria, ‘He will not come to this city, nor shoot an arrow there, neither will he come before it with shield, nor cast up a mound against it.', pt: 'Portanto, assim diz o Senhor acerca do rei da Assíria: Não entrará nesta cidade, nem lançará nela flecha alguma; tampouco virá perante ela com escudo, ou levantará contra ela tranqueira.' },
      { v: 34, en: 'By the way that he came, by the same he shall return, and he shall not come to this city,’ says Yahweh.', pt: 'Pelo caminho por onde veio, por esse voltará; mas nesta cidade não entrará, diz o Senhor.' },
      { v: 35, en: '‘For I will defend this city to save it, for my own sake, and for my servant David’s sake.’”', pt: 'Porque eu defenderei esta cidade, para a livrar, por amor de mim e, por amor do meu servo Davi.' },
      { v: 36, en: 'Then Yahweh’s angel went out and struck one hundred and eighty-five thousand men in the camp of the Assyrians. When men arose early in the morning, behold, these were all dead bodies.', pt: 'Então saiu o anjo do Senhor, e feriu no arraial dos assírios a cento e oitenta e cinco mil; e quando se levantaram pela manhã cedo, eis que todos estes eram corpos mortos.' },
      { v: 37, en: 'So Sennacherib king of Assyria departed, went away, returned to Nineveh, and stayed there.', pt: 'Assim Senaqueribe, rei da Assíria, se retirou, e se foi, e voltou, e habitou em Nínive.' },
      { v: 38, en: 'As he was worshiping in the house of Nisroch his god, Adrammelech and Sharezer his sons struck him with the sword; and they escaped into the land of Ararat. Esar Haddon his son reigned in his place.', pt: 'E sucedeu que, enquanto ele adorava na casa de Nisroque, seu deus, Adrameleb, que e Sarezer, seus filhos, o mataram à espada; e escaparam para a terra de Arará. E Ezar-Hadom, seu filho, reinou em seu lugar.' },
    ],
    38: [
      { v: 1, en: 'In those days was Hezekiah sick and near death. Isaiah the prophet, the son of Amoz, came to him, and said to him, “Yahweh says, ‘Set your house in order, for you will die, and not live.’”', pt: 'Naqueles dias Ezequias adoeceu e esteve à morte. E veio ter com ele o profeta Isaías, filho de Amoz, e lhe disse: Assim diz o Senhor: Põe em ordem a tua casa, porque morrerás, e não viverás.' },
      { v: 2, en: 'Then Hezekiah turned his face to the wall and prayed to Yahweh,', pt: 'Então virou Ezequias o seu rosto para a parede, e orou ao Senhor,' },
      { v: 3, en: 'and said, “Remember now, Yahweh, I beg you, how I have walked before you in truth and with a perfect heart, and have done that which is good in your sight.” Hezekiah wept bitterly.', pt: 'e disse: Lembra-te agora, ó Senhor, peço-te, de que modo tenho andado diante de ti em verdade, e com coração perfeito, e tenho feito o que era reto aos teus olhos. E chorou Ezequias amargamente.' },
      { v: 4, en: 'Then Yahweh’s word came to Isaiah, saying,', pt: 'Então veio a palavra do Senhor a Isaías, dizendo:' },
      { v: 5, en: '“Go, and tell Hezekiah, ‘Yahweh, the God of David your father, says, “I have heard your prayer. I have seen your tears. Behold, I will add fifteen years to your life.', pt: 'Vai e dize a Ezequias: Assim diz o Senhor, o Deus de Davi teu pai: Ouvi a tua oração, e vi as tuas lágrimas; eis que acrescentarei aos teus dias quinze anos.' },
      { v: 6, en: 'I will deliver you and this city out of the hand of the king of Assyria, and I will defend this city.', pt: 'Livrar-te-ei das mãos do rei da Assíria, a ti, e a esta cidade; eu defenderei esta cidade.' },
      { v: 7, en: 'This shall be the sign to you from Yahweh, that Yahweh will do this thing that he has spoken.', pt: 'E isto te será da parte do Senhor como sinal de que o Senhor cumprirá esta palavra que falou:' },
      { v: 8, en: 'Behold, I will cause the shadow on the sundial, which has gone down on the sundial of Ahaz with the sun, to return backward ten steps. So the sun returned ten steps on the sundial on which it had gone down.”’”', pt: 'Eis que farei voltar atrás dez graus a sombra no relógio de Acaz, pelos quais já declinou com o sol. Assim recuou o sol dez graus pelos quais já tinha declinado.' },
      { v: 9, en: 'The writing of Hezekiah king of Judah, when he had been sick, and had recovered of his sickness.', pt: 'O escrito de Ezequias, rei de Judá, depois de ter estado doente, e de ter convalescido de sua enfermidade.' },
      { v: 10, en: 'I said, “In the middle of my life I go into the gates of Sheol. I am deprived of the residue of my years.”', pt: 'Eu disse: Na tranqüilidade de meus dias hei de entrar nas portas do Seol; estou privado do resto de meus anos.' },
      { v: 11, en: 'I said, “I won’t see Yah, Yah in the land of the living. I will see man no more with the inhabitants of the world.', pt: 'Eu disse: Já não verei mais ao Senhor na terra dos viventes; jamais verei o homem com os moradores do mundo.' },
      { v: 12, en: 'My dwelling is removed, and is carried away from me like a shepherd’s tent. I have rolled up, like a weaver, my life. He will cut me off from the loom. From day even to night you will make an end of me.', pt: 'A minha habitação já foi arrancada e arrebatada de mim, qual tenda de pastor; enrolei como tecelão a minha vida; ele me corta do tear; do dia para a noite tu darás cabo de mim.' },
      { v: 13, en: 'I waited patiently until morning. He breaks all my bones like a lion. From day even to night you will make an end of me.', pt: 'Clamei por socorro até a madrugada; como um leão, assim ele quebrou todos os meus ossos; do dia para a noite tu darás cabo de mim.' },
      { v: 14, en: 'I chattered like a swallow or a crane. I moaned like a dove. My eyes weaken looking upward. Lord, I am oppressed. Be my security.”', pt: 'Como a andorinha, ou o grou, assim eu chilreava; e gemia como a pomba; os meus olhos se cansavam de olhar para cima; ó Senhor, ando oprimido! fica por meu fiador.' },
      { v: 15, en: 'What will I say? He has both spoken to me, and himself has done it. I will walk carefully all my years because of the anguish of my soul.', pt: 'Que direi? como mo prometeu, assim ele mesmo o cumpriu; assim passarei mansamente por todos os meus anos, por causa da amargura da minha alma.' },
      { v: 16, en: 'Lord, men live by these things; and my spirit finds life in all of them: you restore me, and cause me to live.', pt: 'ç Senhor por estas coisas vivem os homens, e inteiramente nelas está a vida do meu espírito; portanto restabelece-me, e faze-me viver.' },
      { v: 17, en: 'Behold, for peace I had great anguish, but you have in love for my soul delivered it from the pit of corruption; for you have cast all my sins behind your back.', pt: 'Eis que foi para minha paz que eu estive em grande amargura; tu, porém, amando a minha alma, a livraste da cova da corrupção; porque lançaste para trás das tuas costas todos os meus pecados.' },
      { v: 18, en: 'For Sheol can’t praise you. Death can’t celebrate you. Those who go down into the pit can’t hope for your truth.', pt: 'Pois não pode louvar-te o Seol, nem a morte cantar-te os louvores; os que descem para a cova não podem esperar na tua verdade.' },
      { v: 19, en: 'The living, the living, he shall praise you, as I do today. The father shall make known your truth to the children.', pt: 'O vivente, o vivente é que te louva, como eu hoje faço; o pai aos filhos faz notória a tua verdade.' },
      { v: 20, en: 'Yahweh will save me. Therefore we will sing my songs with stringed instruments all the days of our life in Yahweh’s house.', pt: 'O Senhor está prestes a salvar-me; pelo que, tangendo eu meus instrumentos, nós o louvaremos todos os dias de nossa vida na casa do Senhor.' },
      { v: 21, en: 'Now Isaiah had said, “Let them take a cake of figs, and lay it for a poultice on the boil, and he shall recover.”', pt: 'Ora Isaías dissera: Tomem uma pasta de figos, e a ponham como cataplasma sobre a úlcera; e Ezequias sarará.' },
      { v: 22, en: 'Hezekiah also had said, “What is the sign that I will go up to Yahweh’s house?”', pt: 'Também dissera Ezequias: Qual será o sinal de que hei de subir à casa do Senhor?' },
    ],
    39: [
      { v: 1, en: 'At that time, Merodach Baladan the son of Baladan, king of Babylon, sent letters and a present to Hezekiah; for he heard that he had been sick, and had recovered.', pt: 'Naquele tempo enviou Merodaque-Baladã, filho de Baladã, rei de Babilônia, cartas e um presente a Ezequias; porque tinha ouvido dizer que havia estado doente e que já tinha convalescido.' },
      { v: 2, en: 'Hezekiah was pleased with them, and showed them the house of his precious things, the silver, and the gold, the spices, and the precious oil, and all the house of his armor, and all that was found in his treasures. There was nothing in his house, nor in all his dominion, that Hezekiah didn’t show them.', pt: 'E Ezequias se alegrou com eles, e lhes mostrou a casa do seu tesouro, a prata, e o ouro, e as especiarias, e os melhores ungüentos, e toda a sua casa de armas, e tudo quanto se achava nos seus tesouros; coisa nenhuma houve, nem em sua casa, nem em todo o seu domínio, que Ezequias lhes não mostrasse.' },
      { v: 3, en: 'Then Isaiah the prophet came to king Hezekiah, and asked him, “What did these men say? Where did they come from to you?” Hezekiah said, “They have come from a country far from me, even from Babylon.”', pt: 'Então o profeta Isaías veio ao rei Ezequias, e lhe perguntou: Que foi que aqueles homens disseram, e donde vieram ter contigo? Respondeu Ezequias: Duma terra remota vieram ter comigo, de Babilônia.' },
      { v: 4, en: 'Then he asked, “What have they seen in your house?” Hezekiah answered, “They have seen all that is in my house. There is nothing among my treasures that I have not shown them.”', pt: 'Ele ainda perguntou: Que foi que viram em tua casa? Respondeu Ezequias: Viram tudo quanto há em minha casa; coisa nenhuma há nos meus tesouros que eu deixasse de lhes mostrar.' },
      { v: 5, en: 'Then Isaiah said to Hezekiah, “Hear the word of Yahweh of Armies:', pt: 'Então disse Isaías a Ezequias: Ouve a palavra do Senhor dos exércitos:' },
      { v: 6, en: '‘Behold, the days are coming when all that is in your house, and that which your fathers have stored up until today, will be carried to Babylon. Nothing will be left,’ says Yahweh.', pt: 'Eis que virão dias em que tudo quanto houver em tua casa, juntamente com o que entesouraram teus pais até o dia de hoje, será levado para Babilônia; não ficará coisa alguma, disse o Senhor.' },
      { v: 7, en: '‘They will take away your sons who will issue from you, whom you shall father, and they will be eunuchs in the king of Babylon’s palace.’”', pt: 'E dos teus filhos, que de ti procederem, e que tu gerares, alguns serão levados cativos, para que sejam eunucos no palácio do rei de Babilônia.' },
      { v: 8, en: 'Then Hezekiah said to Isaiah, “Yahweh’s word which you have spoken is good.” He said moreover, “For there will be peace and truth in my days.”', pt: 'Então disse Ezequias a Isaías: Tua é a palavra do Senhor que disseste. Disse mais: Porque haverá paz e verdade em meus dias.' },
    ],
    40: [
      { v: 1, en: '“Comfort, comfort my people,” says your God.', pt: 'Consolai, consolai o meu povo, diz o vosso Deus.' },
      { v: 2, en: '“Speak comfortably to Jerusalem; and call out to her that her warfare is accomplished, that her iniquity is pardoned, that she has received of Yahweh’s hand double for all her sins.”', pt: 'Falai benignamente a Jerusalém, e bradai-lhe que já a sua malícia é acabada, que a sua iniqüidade está expiada e que já recebeu em dobro da mão do Senhor, por todos os seus pecados.' },
      { v: 3, en: 'The voice of one who calls out, “Prepare the way of Yahweh in the wilderness! Make a level highway in the desert for our God.', pt: 'Eis a voz do que clama: Preparai no deserto o caminho do Senhor; endireitai no ermo uma estrada para o nosso Deus.' },
      { v: 4, en: 'Every valley shall be exalted, and every mountain and hill shall be made low. The uneven shall be made level, and the rough places a plain.', pt: 'Todo vale será levantado, e será abatido todo monte e todo outeiro; e o terreno acidentado será nivelado, e o que é escabroso, aplanado.' },
      { v: 5, en: 'Yahweh’s glory shall be revealed, and all flesh shall see it together; for the mouth of Yahweh has spoken it.”', pt: 'A glória do Senhor se revelará; e toda a carne juntamente a verá; pois a boca do Senhor o disse.' },
      { v: 6, en: 'The voice of one saying, “Cry!” One said, “What shall I cry?” “All flesh is like grass, and all its glory is like the flower of the field.', pt: 'Uma voz diz: Clama. Respondi eu: Que hei de clamar? Toda a carne é erva, e toda a sua beleza como a flor do campo.' },
      { v: 7, en: 'The grass withers, the flower fades, because Yahweh’s breath blows on it. Surely the people are like grass.', pt: 'Seca-se a erva, e murcha a flor, soprando nelas o hálito do Senhor. Na verdade o povo é erva.' },
      { v: 8, en: 'The grass withers, the flower fades; but the word of our God stands forever.”', pt: 'Seca-se a erva, e murcha a flor; mas a palavra de nosso Deus subsiste eternamente.' },
      { v: 9, en: 'You who tell good news to Zion, go up on a high mountain. You who tell good news to Jerusalem, lift up your voice with strength. Lift it up. Don’t be afraid. Say to the cities of Judah, “Behold, your God!”', pt: 'Tu, anunciador de boas-novas a Sião, sobe a um monte alto. Tu, anunciador de boas-novas a Jerusalém, levanta a tua voz fortemente; levanta-a, não temas, e dize às cidades de Judá: Eis aqui está o vosso Deus.' },
      { v: 10, en: 'Behold, the Lord Yahweh will come as a mighty one, and his arm will rule for him. Behold, his reward is with him, and his recompense before him.', pt: 'Eis que o Senhor Deus virá com poder, e o seu braço dominará por ele; eis que o seu galardão está com ele, e a sua recompensa diante dele.' },
      { v: 11, en: 'He will feed his flock like a shepherd. He will gather the lambs in his arm, and carry them in his bosom. He will gently lead those who have their young.', pt: 'Como pastor ele apascentará o seu rebanho; entre os seus braços recolherá os cordeirinhos, e os levará no seu regaço; as que amamentam, ele as guiará mansamente.' },
      { v: 12, en: 'Who has measured the waters in the hollow of his hand, and marked off the sky with his span, and calculated the dust of the earth in a measuring basket, and weighed the mountains in scales, and the hills in a balance?', pt: 'Quem mediu com o seu punho as águas, e tomou a medida dos céus aos palmos, e recolheu numa medida o pó da terra e pesou os montes com pesos e os outeiros em balanças,' },
      { v: 13, en: 'Who has directed Yahweh’s Spirit, or has taught him as his counselor?', pt: 'Quem guiou o Espírito do Senhor, ou, como seu conselheiro o ensinou?' },
      { v: 14, en: 'Who did he take counsel with, and who instructed him, and taught him in the path of justice, and taught him knowledge, and showed him the way of understanding?', pt: 'Com quem tomou ele conselho, para que lhe desse entendimento, e quem lhe mostrou a vereda do juízo? quem lhe ensinou conhecimento, e lhe mostrou o caminho de entendimento?' },
      { v: 15, en: 'Behold, the nations are like a drop in a bucket, and are regarded as a speck of dust on a balance. Behold, he lifts up the islands like a very little thing.', pt: 'Eis que as nações são consideradas por ele como a gota dum balde, e como o pó miúdo das balanças; eis que ele levanta as ilhas como a uma coisa pequeníssima.' },
      { v: 16, en: 'Lebanon is not sufficient to burn, nor its animals sufficient for a burnt offering.', pt: 'Nem todo o Líbano basta para o fogo, nem os seus animais bastam para um holocausto.' },
      { v: 17, en: 'All the nations are like nothing before him. They are regarded by him as less than nothing, and vanity.', pt: 'Todas as nações são como nada perante ele; são por ele reputadas menos do que nada, e como coisa vã.' },
      { v: 18, en: 'To whom then will you liken God? Or what likeness will you compare to him?', pt: 'A quem, pois, podeis assemelhar a Deus? ou que figura podeis comparar a ele?' },
      { v: 19, en: 'A workman has cast an image, and the goldsmith overlays it with gold, and casts silver chains for it.', pt: 'Quanto ao ídolo, o artífice o funde, e o ourives o cobre de ouro, e forja cadeias de prata para ele.' },
      { v: 20, en: 'He who is too impoverished for such an offering chooses a tree that will not rot. He seeks a skillful workman to set up a carved image for him that will not be moved.', pt: 'O empobrecido, que não pode oferecer tanto, escolhe madeira que não apodrece; procura para si um artífice perito, para gravar uma imagem que não se pode mover.' },
      { v: 21, en: 'Haven’t you known? Haven’t you heard? Haven’t you been told from the beginning? Haven’t you understood from the foundations of the earth?', pt: 'Porventura não sabeis? porventura não ouvis? ou desde o princípio não se vos notificou isso mesmo? ou não tendes entendido desde a fundação da terra?' },
      { v: 22, en: 'It is he who sits above the circle of the earth, and its inhabitants are like grasshoppers; who stretches out the heavens like a curtain, and spreads them out like a tent to dwell in;', pt: 'E ele o que está assentado sobre o círculo da terra, cujos moradores são para ele como gafanhotos; é ele o que estende os céus como cortina, e o desenrola como tenda para nela habitar.' },
      { v: 23, en: 'who brings princes to nothing; who makes the judges of the earth like meaningless.', pt: 'E ele o que reduz a nada os príncipes, e torna em coisa vã os juízes da terra.' },
      { v: 24, en: 'They are planted scarcely. They are sown scarcely. Their stock has scarcely taken root in the ground. He merely blows on them, and they wither, and the whirlwind takes them away as stubble.', pt: 'Na verdade, mal se tem plantado, mal se tem semeado e mal se tem arraigado na terra o seu tronco, quando ele sopra sobre eles, e secam-se, e a tempestade os leva como à pragana.' },
      { v: 25, en: '“To whom then will you liken me? Who is my equal?” says the Holy One.', pt: 'A quem, pois, me comparareis, para que eu lhe seja semelhante? diz o Santo.' },
      { v: 26, en: 'Lift up your eyes on high, and see who has created these, who brings out their army by number. He calls them all by name. by the greatness of his might, and because he is strong in power, Not one is lacking.', pt: 'Levantai ao alto os vossos olhos, e vede: quem criou estas coisas? Foi aquele que faz sair o exército delas segundo o seu número; ele as chama a todas pelos seus nomes; por ser ele grande em força, e forte em poder, nenhuma faltará.' },
      { v: 27, en: 'Why do you say, Jacob, and speak, Israel, “My way is hidden from Yahweh, and the justice due me is disregarded by my God?”', pt: 'Por que dizes, ó Jacó, e falas, ó Israel: O meu caminho está escondido ao Senhor, e o meu juízo passa despercebido ao meu Deus?' },
      { v: 28, en: 'Haven’t you known? Haven’t you heard? The everlasting God, Yahweh, The Creator of the ends of the earth, doesn’t faint. He isn’t weary. His understanding is unsearchable.', pt: 'Não sabes, não ouviste que o eterno Deus, o Senhor, o Criador dos confins da terra, não se cansa nem se fatiga? E inescrutável o seu entendimento.' },
      { v: 29, en: 'He gives power to the weak. He increases the strength of him who has no might.', pt: 'Ele dá força ao cansado, e aumenta as forças ao que não tem nenhum vigor.' },
      { v: 30, en: 'Even the youths faint and get weary, and the young men utterly fall;', pt: 'Os jovens se cansarão e se fatigarão, e os mancebos cairão,' },
      { v: 31, en: 'But those who wait for Yahweh will renew their strength. They will mount up with wings like eagles. They will run, and not be weary. They will walk, and not faint.', pt: 'mas os que esperam no Senhor renovarão as suas forças; subirão com asas como águias; correrão, e não se cansarão; andarão, e não se fatigarão.' },
    ],
    41: [
      { v: 1, en: '“Keep silent before me, islands, and let the peoples renew their strength. Let them come near, then let them speak. Let’s meet together for judgment.', pt: 'Calai-vos diante de mim, ó ilhas; e renovem os povos as forças; cheguem-se, e então falem; cheguemo-nos juntos a juizo.' },
      { v: 2, en: 'Who has raised up one from the east? Who called him to his foot in righteousness? He hands over nations to him, and makes him rule over kings. He gives them like the dust to his sword, like the driven stubble to his bow.', pt: 'Quem suscitou do Oriente aquele cujos passos a vitória acompanha? Quem faz que as nações se lhe submetam e que ele domine sobre reis? Ele os entrega à sua espada como o pó, e ao seu arco como pragana arrebatada pelo vento.' },
      { v: 3, en: 'He pursues them, and passes by safely, Even by a way that he had not gone with his feet.', pt: 'Ele os persegue, e passa adiante em segurança, até por uma vereda em que com os seus pés nunca tinha trilhado.' },
      { v: 4, en: 'Who has worked and done it, calling the generations from the beginning? I, Yahweh, the first, and with the last, I am he.”', pt: 'Quem operou e fez isto, chamando as gerações desde o princípio? Eu, o Senhor, que sou o primeiro, e que com os últimos sou o mesmo.' },
      { v: 5, en: 'The islands have seen, and fear. The ends of the earth tremble. They approach, and come.', pt: 'As ilhas o viram, e temeram; os confins da terra tremeram; aproximaram-se, e vieram.' },
      { v: 6, en: 'Everyone helps his neighbor. They say to their brothers, “Be strong!”', pt: 'um ao outro ajudou, e ao seu companheiro disse: Esforça-te.' },
      { v: 7, en: 'So the carpenter encourages the goldsmith. He who smoothes with the hammer encourages him who strikes the anvil, saying of the soldering, “It is good”; and he fastens it with nails, that it might not totter.', pt: 'Assim o artífice animou ao ourives, e o que alisa com o martelo ao que bate na bigorna, dizendo da coisa soldada: Boa é. Então com pregos a segurou, para que não viesse a mover-se.' },
      { v: 8, en: '“But you, Israel, my servant, Jacob whom I have chosen, the offspring of Abraham my friend,', pt: 'Mas tu, ó Israel, servo meu, tu Jacó, a quem escolhi, descendência de Abraão,' },
      { v: 9, en: 'You whom I have taken hold of from the ends of the earth, and called from its corners, and said to you, ‘You are my servant, I have chosen you and have not cast you away.’', pt: 'tomei desde os confins da terra, e te chamei desde os seus cantos, e te disse: Tu és o meu servo, a ti te escolhi e não te rejeitei;' },
      { v: 10, en: 'Don’t you be afraid, for I am with you. Don’t be dismayed, for I am your God. I will strengthen you. Yes, I will help you. Yes, I will uphold you with the right hand of my righteousness.', pt: 'não temas, porque eu sou contigo; não te assombres, porque eu sou teu Deus; eu te fortaleço, e te ajudo, e te sustento com a destra da minha justiça.' },
      { v: 11, en: 'Behold, all those who are incensed against you will be disappointed and confounded. Those who strive with you will be like nothing, and shall perish.', pt: 'Eis que envergonhados e confundidos serão todos os que se irritam contra ti; tornar-se-ão em nada; e os que contenderem contigo perecerão.' },
      { v: 12, en: 'You will seek them, and won’t find them, even those who contend with you. Those who war against you will be as nothing, as a non-existent thing.', pt: 'Quanto aos que pelejam contigo, buscá-los-ás, mas não os acharás; e os que guerreiam contigo tornar-se-ão em nada e perecerão.' },
      { v: 13, en: 'For I, Yahweh your God, will hold your right hand, saying to you, ‘Don’t be afraid. I will help you.’', pt: 'Porque eu, o Senhor teu Deus, te seguro pela tua mão direita, e te digo: Não temas; eu te ajudarei.' },
      { v: 14, en: 'Don’t be afraid, you worm Jacob, and you men of Israel. I will help you,” says Yahweh, “and your Redeemer is the Holy One of Israel.', pt: 'Não temas, ó bichinho de Jacó, nem vós, povozinho de Israel; eu te ajudo, diz o Senhor, e o teu redentor é o Santo de Israel.' },
      { v: 15, en: 'Behold, I have made you into a new sharp threshing instrument with teeth. You will thresh the mountains, and beat them small, and will make the hills like chaff.', pt: 'Eis que farei de ti um trilho novo, que tem dentes agudos; os montes trilharás e os moerás, e os outeiros tornarás como a pragana.' },
      { v: 16, en: 'You will winnow them, and the wind will carry them away, and the whirlwind will scatter them. You will rejoice in Yahweh. You will glory in the Holy One of Israel.', pt: 'Tu os padejarás e o vento os levará, e o redemoinho os espalhará; e tu te alegrarás no Senhor e te gloriarás no Santo de Israel.' },
      { v: 17, en: 'The poor and needy seek water, and there is none. Their tongue fails for thirst. I, Yahweh, will answer them. I, the God of Israel, will not forsake them.', pt: 'Os pobres e necessitados buscam água, e não há, e a sua língua se seca de sede; mas eu o Senhor os ouvirei, eu o Deus de Israel não os desampararei.' },
      { v: 18, en: 'I will open rivers on the bare heights, and springs in the middle of the valleys. I will make the wilderness a pool of water, and the dry land springs of water.', pt: 'Abrirei rios nos altos desnudados, e fontes no meio dos vales; tornarei o deserto num lago d\'água, e a terra seca em mananciais.' },
      { v: 19, en: 'I will put cedar, acacia, myrtle, and oil trees in the wilderness. I will set cypress trees, pine, and box trees together in the desert;', pt: 'Plantarei no deserto o cedro, a acácia, a murta, e a oliveira; e porei no ermo juntamente a faia, o olmeiro e o buxo;' },
      { v: 20, en: 'that they may see, know, consider, and understand together, that Yahweh’s hand has done this, and the Holy One of Israel has created it.', pt: 'para que todos vejam, e saibam, e considerem, e juntamente entendam que a mão do Senhor fez isso, e o Santo de Israel o criou.' },
      { v: 21, en: 'Produce your cause,” says Yahweh. “Bring out your strong reasons,” says the King of Jacob.', pt: 'Apresentai a vossa demanda, diz o Senhor; trazei as vossas firmes razões, diz o Rei de Jacó.' },
      { v: 22, en: '“Let them announce, and declare to us what shall happen. Declare the former things, what they are, that we may consider them, and know the latter end of them; or show us things to come.', pt: 'Tragam-nas, e assim nos anunciem o que há de acontecer; anunciai-nos as coisas passadas, quais são, para que as consideremos, e saibamos o fim delas; ou mostrai-nos coisas vindouras.' },
      { v: 23, en: 'Declare the things that are to come hereafter, that we may know that you are gods. Yes, do good, or do evil, that we may be dismayed, and see it together.', pt: 'Anunciai-nos as coisas que ainda hão de vir, para que saibamos que sois deuses; fazei bem, ou fazei mal, para que nos assombremos, e fiquemos atemorizados.' },
      { v: 24, en: 'Behold, you are of nothing, and your work is of nothing. He who chooses you is an abomination.', pt: 'Eis que vindes do nada, e a vossa obra do que nada é; abominação é quem vos escolhe.' },
      { v: 25, en: '“I have raised up one from the north, and he has come; from the rising of the sun, one who calls on my name; and he shall come on rulers as on mortar, and as the potter treads clay.', pt: 'Do norte suscitei a um que já é chegado; do nascente do sol a um que invoca o meu nome; e virá sobre os magistrados como sobre o lodo, e como o oleiro pisa o barro.' },
      { v: 26, en: 'Who has declared it from the beginning, that we may know? And before, that we may say, ‘He is right?’ Surely, there is no one who declares. Surely, there is no one who shows. Surely, there is no one who hears your words.', pt: 'Quem anunciou isso desde o princípio, para que o possamos saber? ou dantes, para que digamos: Ele é justo? Mas não há quem anuncie, nem tampouco quem manifeste, nem tampouco quem ouça as vossas palavras.' },
      { v: 27, en: 'I am the first to say to Zion, ‘Behold, look at them;’ and I will give one who brings good news to Jerusalem.', pt: 'Eu sou o que primeiro direi a Sião: Ei-los, ei-los; e a Jerusalém darei um mensageiro que traz boas-novas.' },
      { v: 28, en: 'When I look, there is no man; even among them there is no counselor who, when I ask of them, can answer a word.', pt: 'E quando eu olho, não há ninguém; nem mesmo entre eles há conselheiro que possa responder palavra, quando eu lhes perguntar.' },
      { v: 29, en: 'Behold, all of them, their deeds are vanity and nothing. Their molten images are wind and confusion.', pt: 'Eis que todos são vaidade. As suas obras não são coisa alguma; as suas imagens de fundição são vento e coisa vã.' },
    ],
    42: [
      { v: 1, en: '“Behold, my servant, whom I uphold; my chosen, in whom my soul delights— I have put my Spirit on him. He will bring justice to the nations.', pt: 'Eis aqui o meu servo, a quem sustenho; o meu escolhido, em quem se compraz a minha alma; pus o meu espírito sobre ele. ele trará justiça às nações.' },
      { v: 2, en: 'He will not shout, nor raise his voice, nor cause it to be heard in the street.', pt: 'Não clamará, não se exaltará, nem fará ouvir a sua voz na rua.' },
      { v: 3, en: 'He won’t break a bruised reed. He won’t quench a dimly burning wick. He will faithfully bring justice.', pt: 'A cana trilhada, não a quebrará, nem apagará o pavio que fumega; em verdade trará a justiça;' },
      { v: 4, en: 'He will not fail nor be discouraged, until he has set justice in the earth, and the islands will wait for his law.”', pt: 'não faltará nem será quebrantado, até que ponha na terra a justiça; e as ilhas aguardarão a sua lei.' },
      { v: 5, en: 'Thus says God Yahweh, he who created the heavens and stretched them out, he who spread out the earth and that which comes out of it, he who gives breath to its people and spirit to those who walk in it.', pt: 'Assim diz Deus, o Senhor, que criou os céus e os desenrolou, e estendeu a terra e o que dela procede; que dá a respiração ao povo que nela está, e o espírito aos que andam nela.' },
      { v: 6, en: '“I, Yahweh, have called you in righteousness, and will hold your hand, and will keep you, and make you a covenant for the people, as a light for the nations;', pt: 'Eu o Senhor te chamei em justiça; tomei-te pela mão, e te guardei; e te dei por pacto ao povo, e para luz das nações;' },
      { v: 7, en: 'to open the blind eyes, to bring the prisoners out of the dungeon, and those who sit in darkness out of the prison.', pt: 'para abrir os olhos dos cegos, para tirar da prisão os presos, e do cárcere os que jazem em trevas.' },
      { v: 8, en: '“I am Yahweh. That is my name. I will not give my glory to another, nor my praise to engraved images.', pt: 'Eu sou o Senhor; este é o meu nome; a minha glória, pois, a outrem não a darei, nem o meu louvor às imagens esculpidas.' },
      { v: 9, en: 'Behold, the former things have happened, and I declare new things. I tell you about them before they come up.”', pt: 'Eis que as primeiras coisas já se realizaram, e novas coisas eu vos anuncio; antes que venham à luz, vo-las faço ouvir.' },
      { v: 10, en: 'Sing to Yahweh a new song, and his praise from the end of the earth, you who go down to the sea, and all that is therein, the islands and their inhabitants.', pt: 'Cantai ao Senhor um cântico novo, e o seu louvor desde a extremidade da terra, vós, os que navegais pelo mar, e tudo quanto há nele, vós ilhas, e os vossos habitantes.' },
      { v: 11, en: 'Let the wilderness and its cities raise their voices, with the villages that Kedar inhabits. Let the inhabitants of Sela sing. Let them shout from the top of the mountains!', pt: 'Alcem a voz o deserto e as suas cidades, com as aldeias que Quedar habita; exultem os que habitam nos penhascos, e clamem do cume dos montes.' },
      { v: 12, en: 'Let them give glory to Yahweh, and declare his praise in the islands.', pt: 'Dêem glória ao Senhor, e anunciem nas ilhas o seu louvor.' },
      { v: 13, en: 'Yahweh will go out like a mighty man. He will stir up zeal like a man of war. He will raise a war cry. Yes, he will shout aloud. He will triumph over his enemies.', pt: 'O Senhor sai como um valente, como homem de guerra desperta o zelo; clamará, e fará grande ruído, e mostrar-se-á valente contra os seus inimigos.' },
      { v: 14, en: '“I have been silent a long time. I have been quiet and restrained myself. Now I will cry out like a travailing woman. I will both gasp and pant.', pt: 'Por muito tempo me calei; estive em silêncio, e me contive; mas agora darei gritos como a que está de parto, arfando e arquejando.' },
      { v: 15, en: 'I will destroy mountains and hills, and dry up all their herbs. I will make the rivers islands, and will dry up the pools.', pt: 'Os montes e outeiros tornarei em deserto, e toda a sua erva farei secar; e tornarei os rios em ilhas, e secarei as lagoas.' },
      { v: 16, en: 'I will bring the blind by a way that they don’t know. I will lead them in paths that they don’t know. I will make darkness light before them, and crooked places straight. I will do these things, and I will not forsake them.', pt: 'E guiarei os cegos por um caminho que não conhecem; fá-los- ei caminhar por veredas que não têm conhecido; tornarei as trevas em luz perante eles, e aplanados os caminhos escabrosos. Estas coisas lhes farei; e não os desampararei.' },
      { v: 17, en: '“Those who trust in engraved images, who tell molten images, ‘You are our gods’ will be turned back. They will be utterly disappointed.', pt: 'Tornados para trás e cobertos de vergonha serão os que confiam em imagens esculpidas, que dizem às imagens de fundição: Vós sois nossos deuses.' },
      { v: 18, en: '“Hear, you deaf, and look, you blind, that you may see.', pt: 'Surdos, ouvi; e vós, cegos, olhai, para que possais ver.' },
      { v: 19, en: 'Who is blind, but my servant? Or who is as deaf as my messenger whom I send? Who is as blind as he who is at peace, and as blind as Yahweh’s servant?', pt: 'Quem é cego, senão o meu servo, ou surdo como o meu mensageiro, que envio? e quem é cego como o meu dedicado, e cego como o servo do Senhor?' },
      { v: 20, en: 'You see many things, but don’t observe. His ears are open, but he doesn’t listen.', pt: 'Tu vês muitas coisas, mas não as guardas; ainda que ele tenha os ouvidos abertos, nada ouve.' },
      { v: 21, en: 'It pleased Yahweh, for his righteousness’ sake, to magnify the law, and make it honorable.', pt: 'Foi do agrado do Senhor, por amor da sua justiça, engrandecer a lei e torná-la gloriosa.' },
      { v: 22, en: 'But this is a robbed and plundered people. All of them are snared in holes, and they are hidden in prisons. They have become captives, and no one delivers; and a plunder, and no one says, ‘Restore them!’', pt: 'Mas este é um povo roubado e saqueado; todos estão enlaçados em cavernas, e escondidos nas casas dos cárceres; são postos por presa, e ninguém há que os livre; por despojo, e ninguém diz: Restitui.' },
      { v: 23, en: 'Who is there among you who will give ear to this? Who will listen and hear for the time to come?', pt: 'Quem há entre vós que a isso dará ouvidos? que atenderá e ouvirá doravante?' },
      { v: 24, en: 'Who gave Jacob as plunder, and Israel to the robbers? Didn’t Yahweh, he against whom we have sinned? For they would not walk in his ways, and they disobeyed his law.', pt: 'Quem entregou Jacó por despojo, e Israel aos roubadores? porventura não foi o Senhor, aquele contra quem pecamos, e em cujos caminhos eles não queriam andar, e cuja lei não queriam observar?' },
      { v: 25, en: 'Therefore he poured the fierceness of his anger on him, and the strength of battle; and it set him on fire all around, but he didn’t know; and it burned him, but he didn’t take it to heart.”', pt: 'Pelo que o Senhor derramou sobre Israel a indignação da sua ira, e a violência da guerra; isso lhe ateou fogo ao redor; contudo ele não o percebeu; e o queimou; contudo ele não se compenetrou disso.' },
    ],
    43: [
      { v: 1, en: 'But now Yahweh who created you, Jacob, and he who formed you, Israel says: “Don’t be afraid, for I have redeemed you. I have called you by your name. You are mine.', pt: 'Mas agora, assim diz o Senhor que te criou, ó Jacó, e que te formou, ó Israel: Não temas, porque eu te remi; chamei-te pelo teu nome, tu és meu.' },
      { v: 2, en: 'When you pass through the waters, I will be with you; and through the rivers, they will not overflow you. When you walk through the fire, you will not be burned, and flame will not scorch you.', pt: 'Quando passares pelas águas, eu serei contigo; quando pelos rios, eles não te submergirão; quando passares pelo fogo, não te queimarás, nem a chama arderá em ti.' },
      { v: 3, en: 'For I am Yahweh your God, the Holy One of Israel, your Savior. I have given Egypt as your ransom, Ethiopia and Seba in your place.', pt: 'Porque eu sou o Senhor teu Deus, o Santo de Israel, o teu Salvador; por teu resgate dei o Egito, e em teu lugar a Etiópia e Seba.' },
      { v: 4, en: 'Since you have been precious and honored in my sight, and I have loved you; therefore I will give people in your place, and nations instead of your life.', pt: 'Visto que foste precioso aos meus olhos, e és digno de honra e eu te amo, portanto darei homens por ti, e es povos pela tua vida.' },
      { v: 5, en: 'Don’t be afraid; for I am with you. I will bring your offspring from the east, and gather you from the west.', pt: 'Não temas, pois, porque eu sou contigo; trarei a tua descendência desde o Oriente, e te ajuntarei desde o Ocidente.' },
      { v: 6, en: 'I will tell the north, ‘Give them up!’ and tell the south, ‘Don’t hold them back! Bring my sons from far, and my daughters from the ends of the earth—', pt: 'Direi ao Norte: Dá; e ao Sul: Não retenhas; trazei meus filhos de longe, e minhas filhas das extremidades da terra;' },
      { v: 7, en: 'everyone who is called by my name, and whom I have created for my glory, whom I have formed, yes, whom I have made.’”', pt: 'a todo aquele que é chamado pelo meu nome, e que criei para minha glória, e que formei e fiz.' },
      { v: 8, en: 'Bring out the blind people who have eyes, and the deaf who have ears.', pt: 'Fazei sair o povo que é cego e tem olhos; e os surdos que têm ouvidos.' },
      { v: 9, en: 'Let all the nations be gathered together, and let the peoples be assembled. Who among them can declare this, and show us former things? Let them bring their witnesses, that they may be justified; or let them hear, and say, “That is true.”', pt: 'Todas as nações se congreguem, e os povos se reúnam; quem dentre eles pode anunciar isso, e mostrar-nos coisas já passadas? apresentem as suas testemunhas, para que se justifiquem; e para que se ouça, e se diga: Verdade é.' },
      { v: 10, en: '“You are my witnesses,” says Yahweh, “With my servant whom I have chosen; that you may know and believe me, and understand that I am he. Before me there was no God formed, neither will there be after me.', pt: 'Vós sois as minhas testemunhas, do Senhor, e o meu servo, a quem escolhi; para que o saibais, e me creiais e entendais que eu sou o mesmo; antes de mim Deus nenhum se formou, e depois de mim nenhum haverá.' },
      { v: 11, en: 'I myself am Yahweh; and besides me there is no savior.', pt: 'Eu, eu sou o Senhor, e fora de mim não há salvador.' },
      { v: 12, en: 'I have declared, I have saved, and I have shown; and there was no strange god among you. Therefore you are my witnesses”, says Yahweh, “and I am God.', pt: 'Eu anunciei, e eu salvei, e eu o mostrei; e deus estranho não houve entre vós; portanto vós sois as minhas testemunhas, diz o Senhor.' },
      { v: 13, en: 'Yes, since the day was, I am he; and there is no one who can deliver out of my hand. I will work, and who can hinder it?”', pt: 'Eu sou Deus; também de hoje em diante, eu o sou; e ninguém há que possa fazer escapar das minhas mãos; operando eu, quem impedirá?' },
      { v: 14, en: 'Yahweh, your Redeemer, the Holy One of Israel says: “For your sake, I have sent to Babylon, and I will bring all of them down as fugitives, even the Chaldeans, in the ships of their rejoicing.', pt: 'Assim diz o Senhor, vosso Redentor, o Santo de Israel: Por amor de vós enviarei a Babilônia, e a todos os fugitivos farei embarcar até os caldeus, nos navios com que se vangloriavam.' },
      { v: 15, en: 'I am Yahweh, your Holy One, the Creator of Israel, your King.”', pt: 'Eu sou o Senhor, vosso Santo, o Criador de Israel, vosso Rei.' },
      { v: 16, en: 'Yahweh, who makes a way in the sea, and a path in the mighty waters says:', pt: 'Assim diz o Senhor, o que preparou no mar um caminho, e nas águas impetuosas uma vereda;' },
      { v: 17, en: 'who brings out the chariot and horse, the army and the mighty man (they lie down together, they shall not rise; they are extinct, they are quenched like a wick):', pt: 'o que faz sair o carro e o cavalo, o exército e a força; eles juntamente se deitam, e jamais se levantarão; estão extintos, apagados como uma torcida.' },
      { v: 18, en: '“Don’t remember the former things, and don’t consider the things of old.', pt: 'Não vos lembreis das coisas passadas, nem considereis as antigas.' },
      { v: 19, en: 'Behold, I will do a new thing. It springs out now. Don’t you know it? I will even make a way in the wilderness, and rivers in the desert.', pt: 'Eis que faço uma coisa nova; agora está saindo à luz; porventura não a percebeis? eis que porei um caminho no deserto, e rios no ermo.' },
      { v: 20, en: 'The animals of the field shall honor me, the jackals and the ostriches; because I give water in the wilderness and rivers in the desert, to give drink to my people, my chosen,', pt: 'Os animais do campo me honrarão, os chacais e os avestruzes; porque porei águas no deserto, e rios no ermo, para dar de beber ao meu povo, ao meu escolhido,' },
      { v: 21, en: 'the people which I formed for myself, that they might declare my praise.', pt: 'esse povo que formei para mim, para que publicasse o meu louvor.' },
      { v: 22, en: 'Yet you have not called on me, Jacob; but you have been weary of me, Israel.', pt: 'Contudo tu não me invocaste a mim, ó Jacó; mas te cansaste de mim, ó Israel.' },
      { v: 23, en: 'You have not brought me of your sheep for burnt offerings; neither have you honored me with your sacrifices. I have not burdened you with offerings, nor wearied you with frankincense.', pt: 'Não me trouxeste o gado miúdo dos teus holocaustos, nem me honraste com os teus sacrifícios; não te fiz servir com ofertas, nem te fatiguei com incenso.' },
      { v: 24, en: 'You have bought me no sweet cane with money, nor have you filled me with the fat of your sacrifices; but you have burdened me with your sins. You have wearied me with your iniquities.', pt: 'Não me compraste por dinheiro cana aromática, nem com a gordura dos teus sacrifícios me satisfizeste; mas me deste trabalho com os teus pecados, e me cansaste com as tuas iniqüidades.' },
      { v: 25, en: 'I, even I, am he who blots out your transgressions for my own sake; and I will not remember your sins.', pt: 'Eu, eu mesmo, sou o que apago as tuas transgressões por amor de mim, e dos teus pecados não me lembro.' },
      { v: 26, en: 'Put me in remembrance. Let us plead together. Declare your case, that you may be justified.', pt: 'Procura lembrar-me; entremos juntos em juizo; apresenta as tuas razães, para que te possas justificar!' },
      { v: 27, en: 'Your first father sinned, and your teachers have transgressed against me.', pt: 'Teu primeiro pai pecou, e os teus intérpretes prevaricaram contra mim.' },
      { v: 28, en: 'Therefore I will profane the princes of the sanctuary; and I will make Jacob a curse, and Israel an insult.”', pt: 'Pelo que profanei os príncipes do santuário; e entreguei Jacó ao anátema, e Israel ao opróbrio.' },
    ],
    44: [
      { v: 1, en: 'Yet listen now, Jacob my servant, and Israel, whom I have chosen.', pt: 'Agora, pois, ouve, ó Jacó, servo meu, ó Israel, a quem escolhi.' },
      { v: 2, en: 'This is what Yahweh who made you, and formed you from the womb, who will help you says: “Don’t be afraid, Jacob my servant; and you, Jeshurun, whom I have chosen.', pt: 'Assim diz o Senhor que te criou e te formou desde o ventre, e que te ajudará: Não temas, ó Jacó, servo meu, e tu, Jesurum, a quem escolhi.' },
      { v: 3, en: 'For I will pour water on him who is thirsty, and streams on the dry ground. I will pour my Spirit on your descendants, and my blessing on your offspring:', pt: 'Porque derramarei água sobre o sedento, e correntes sobre a terra seca; derramarei o meu Espírito sobre a tua posteridade, e a minha bênção sobre a tua descendência;' },
      { v: 4, en: 'and they will spring up among the grass, as willows by the watercourses.', pt: 'e brotarão como a erva, como salgueiros junto às correntes de águas.' },
      { v: 5, en: 'One will say, ‘I am Yahweh’s;’ and another will be called by the name of Jacob; and another will write with his hand ‘to Yahweh,’ and honor the name of Israel.”', pt: 'Este dirá: Eu sou do Senhor; e aquele se chamará do nome de Jacó; e aquele outro escreverá na própria mão: Eu sou do Senhor; e por sobrenome tomará o nome de Israel.' },
      { v: 6, en: 'This is what Yahweh, the King of Israel, and his Redeemer, Yahweh of Armies, says: “I am the first, and I am the last; and besides me there is no God.', pt: 'Assim diz o Senhor, Rei de Israel, seu Redentor, o Senhor dos exércitos: Eu sou o primeiro, e eu sou o último, e fora de mim não há Deus.' },
      { v: 7, en: 'Who is like me? Who will call, and will declare it, and set it in order for me, since I established the ancient people? Let them declare the things that are coming, and that will happen.', pt: 'Quem há como eu? Que o proclame e o exponha perante mim! Quem tem anunciado desde os tempos antigos as coisas vindouras? Que nos anuncie as que ainda hão de vir.' },
      { v: 8, en: 'Don’t fear, neither be afraid. Haven’t I declared it to you long ago, and shown it? You are my witnesses. Is there a God besides me? Indeed, there is not. I don’t know any other Rock.”', pt: 'Não vos assombreis, nem temais; porventura não vo-lo declarei há muito tempo, e não vo-lo anunciei? Vós sois as minhas testemunhas! Acaso há outro Deus além de mim? Não, não há Rocha; não conheço nenhuma.' },
      { v: 9, en: 'Everyone who makes a carved image is vain. The things that they delight in will not profit. Their own witnesses don’t see, nor know, that they may be disappointed.', pt: 'Todos os artífices de imagens esculpidas são nada; e as suas coisas mais desejáveis são de nenhum préstimo; e suas próprias testemunhas nada vêem nem entendem, para que eles sejam confundidos.' },
      { v: 10, en: 'Who has fashioned a god, or molds an image that is profitable for nothing?', pt: 'Quem forma um deus, e funde uma imagem de escultura, que é de nenhum préstimo?' },
      { v: 11, en: 'Behold, all his fellows will be disappointed; and the workmen are mere men. Let them all be gathered together. Let them stand up. They will fear. They will be put to shame together.', pt: 'Eis que todos os seus seguidores ficarão confundidos; e os artífices são apenas homens; ajuntem-se todos, e se apresentem; assombrar-se-ão, e serão juntamente confundidos.' },
      { v: 12, en: 'The blacksmith takes an ax, works in the coals, fashions it with hammers, and works it with his strong arm. He is hungry, and his strength fails; he drinks no water, and is faint.', pt: 'O ferreiro faz o machado, e trabalha nas brasas, e o forja com martelos, e o forja com o seu forte braço; ademais ele tem fome, e a sua força falta; não bebe água, e desfalece.' },
      { v: 13, en: 'The carpenter stretches out a line. He marks it out with a pencil. He shapes it with planes. He marks it out with compasses, and shapes it like the figure of a man, with the beauty of a man, to reside in a house.', pt: 'O carpinteiro estende a régua sobre um pau, e com lápis esboça um deus; dá-lhe forma com o cepilho; torna a esboçá-lo com o compasso; finalmente dá-lhe forma à semelhança dum homem, segundo a beleza dum homem, para habitar numa casa.' },
      { v: 14, en: 'He cuts down cedars for himself, and takes the cypress and the oak, and strengthens for himself one among the trees of the forest. He plants a cypress tree, and the rain nourishes it.', pt: 'Um homem corta para si cedros, ou toma um cipreste, ou um carvalho; assim escolhe dentre as árvores do bosque; planta uma faia, e a chuva a faz crescer.' },
      { v: 15, en: 'Then it will be for a man to burn; and he takes some of it, and warms himself. Yes, he burns it, and bakes bread. Yes, he makes a god, and worships it; he makes it a carved image, and falls down to it.', pt: 'Então ela serve ao homem para queimar: da madeira toma uma parte e com isso se aquenta; acende um fogo e assa o pão; também faz um deus e se prostra diante dele; fabrica uma imagem de escultura, e se ajoelha diante dela.' },
      { v: 16, en: 'He burns part of it in the fire. With part of it, he eats meat. He roasts a roast, and is satisfied. Yes, he warms himself, and says, “Aha! I am warm. I have seen the fire.”', pt: 'Ele queima a metade no fogo, e com isso prepara a carne para comer; faz um assado, e dele se farta; também se aquenta, e diz: Ah! já me aquentei, já vi o fogo.' },
      { v: 17, en: 'The rest of it he makes into a god, even his engraved image. He bows down to it and worships, and prays to it, and says, “Deliver me; for you are my god!”', pt: 'Então do resto faz para si um deus, uma imagem de escultura; ajoelha-se diante dela, prostra-se, e lhe dirige a sua súplica dizendo: Livra-me porquanto tu és o meu deus.' },
      { v: 18, en: 'They don’t know, neither do they consider: for he has shut their eyes, that they can’t see; and their hearts, that they can’t understand.', pt: 'Nada sabem, nem entendem; porque se lhe untaram os olhos, para que não vejam, e o coração, para que não entendam.' },
      { v: 19, en: 'No one thinks, neither is there knowledge nor understanding to say, “I have burned part of it in the fire. Yes, I have also baked bread on its coals. I have roasted meat and eaten it. Shall I make the rest of it into an abomination? Shall I bow down to a tree trunk?”', pt: 'E nenhum deles reflete; e não têm conhecimento nem entendimento para dizer: Metade queimei no fogo, e assei pão sobre as suas brasas; fiz um assado e dele comi; e faria eu do resto uma abominação? ajoelhar-me-ei ao que saiu duma árvore?' },
      { v: 20, en: 'He feeds on ashes. A deceived heart has turned him aside; and he can’t deliver his soul, nor say, “Isn’t there a lie in my right hand?”', pt: 'Apascenta-se de cinza. O seu coração enganado o desviou, de maneira que não pode livrar a sua alma, nem dizer: Porventura não há uma mentira na minha mão direita?' },
      { v: 21, en: 'Remember these things, Jacob and Israel; for you are my servant. I have formed you. You are my servant. Israel, you will not be forgotten by me.', pt: 'Lembra-te destas coisas, ó Jacó, sim, tu ó Israel; porque tu és meu servo! Eu te formei, meu servo és tu; ó Israel não te esquecerei de ti.' },
      { v: 22, en: 'I have blotted out, as a thick cloud, your transgressions, and, as a cloud, your sins. Return to me, for I have redeemed you.', pt: 'Apagai as tuas transgressões como a névoa, e os teus pecados como a nuvem; torna-te para mim, porque eu te remi.' },
      { v: 23, en: 'Sing, you heavens, for Yahweh has done it! Shout, you lower parts of the earth! Break out into singing, you mountains, O forest, all of your trees, for Yahweh has redeemed Jacob, and will glorify himself in Israel.', pt: 'Cantai alegres, vós, ó céus, porque o Senhor fez isso; exultai vós, as partes mais baixas da terra; vós, montes, retumbai com júbilo; também vós, bosques, e todas as árvores em vós; porque o Senhor remiu a Jacó, e se glorificará em Israel.' },
      { v: 24, en: 'Yahweh, your Redeemer, and he who formed you from the womb says: “I am Yahweh, who makes all things; who alone stretches out the heavens; who spreads out the earth by myself;', pt: 'Assim diz o Senhor, teu Redentor, e que te formou desde o ventre: Eu sou o Senhor que faço todas as coisas, que sozinho estendi os céus, e espraiei a terra (quem estava comigo?);' },
      { v: 25, en: 'who frustrates the signs of the liars, and makes diviners mad; who turns wise men backward, and makes their knowledge foolish;', pt: 'que desfaço os sinais dos profetas falsos, e torno loucos os adivinhos, que faço voltar para trás os sábios, e converto em loucura a sua ciência;' },
      { v: 26, en: 'who confirms the word of his servant, and performs the counsel of his messengers; who says of Jerusalem, ‘She will be inhabited;’ and of the cities of Judah, ‘They will be built,’ and ‘I will raise up its waste places;’', pt: 'sou eu que confirmo a palavra do meu servo, e cumpro o conselho dos meus mensageiros; que digo de Jerusalém: Ela será habitada; e das cidades de Judá: Elas serão edificadas, e eu levantarei as suas ruínas;' },
      { v: 27, en: 'who says to the deep, ‘Be dry,’ and ‘I will dry up your rivers;’', pt: 'que digo ao abismo: Seca-te, eu secarei os teus rios;' },
      { v: 28, en: 'Who says of Cyrus, ‘He is my shepherd, and shall perform all my pleasure,’ even saying of Jerusalem, ‘She will be built;’ and of the temple, ‘Your foundation will be laid.’”', pt: 'que digo de Ciro: Ele é meu pastor, e cumprira tudo o que me apraz; de modo que ele também diga de Jerusalém: Ela será edificada, e o fundamento do templo será lançado.' },
    ],
    45: [
      { v: 1, en: 'Yahweh says to his anointed, to Cyrus, whose right hand I have held, to subdue nations before him, and strip kings of their armor; to open the doors before him, and the gates shall not be shut:', pt: 'Assim diz o Senhor ao seu ungido, a Ciro, a quem tomo pela mão direita, para abater nações diante de sua face, e descingir os lombos dos reis; para abrir diante dele as portas, e as portas não se fecharão;' },
      { v: 2, en: '“I will go before you, and make the rough places smooth. I will break the doors of brass in pieces, and cut apart the bars of iron.', pt: 'eu irei adiante de ti, e tornarei planos os lugares escabrosos; quebrarei as portas de bronze, e despedaçarei os ferrolhos de ferro.' },
      { v: 3, en: 'I will give you the treasures of darkness, and hidden riches of secret places, that you may know that it is I, Yahweh, who call you by your name, even the God of Israel.', pt: 'Dar-te-ei os tesouros das trevas, e as riquezas encobertas, para que saibas que eu sou o Senhor, o Deus de Israel, que te chamo pelo teu nome.' },
      { v: 4, en: 'For Jacob my servant’s sake, and Israel my chosen, I have called you by your name. I have given you a title, though you have not known me.', pt: 'Por amor de meu servo Jacó, e de Israel, meu escolhido, eu te chamo pelo teu nome; ponho-te o teu sobrenome, ainda que não me conheças.' },
      { v: 5, en: 'I am Yahweh, and there is no one else. Besides me, there is no God. I will strengthen you, though you have not known me;', pt: 'Eu sou o Senhor, e não há outro; fora de mim não há Deus; eu te cinjo, ainda que tu não me conheças.' },
      { v: 6, en: 'that they may know from the rising of the sun, and from the west, that there is no one besides me. I am Yahweh, and there is no one else.', pt: 'Para que se saiba desde o nascente do sol, e desde o poente, que fora de mim não há outro; eu sou o Senhor, e não há outro.' },
      { v: 7, en: 'I form the light, and create darkness. I make peace, and create calamity. I am Yahweh, who does all these things.', pt: 'Eu formo a luz, e crio as trevas; eu faço a paz, e crio o mal; eu sou o Senhor, que faço todas estas coisas.' },
      { v: 8, en: 'Rain, you heavens, from above, and let the skies pour down righteousness. Let the earth open, that it may produce salvation, and let it cause righteousness to spring up with it. I, Yahweh, have created it.', pt: 'Destilai vós, céus, dessas alturas a justiça, e chovam-na as nuvens; abra-se a terra, e produza a salvação e ao mesmo tempo faça nascer a justiça; eu, o Senhor, as criei:' },
      { v: 9, en: 'Woe to him who strives with his Maker— a clay pot among the clay pots of the earth! Shall the clay ask him who fashions it, ‘What are you making?’ or your work, ‘He has no hands?’', pt: 'Ai daquele que contende com o seu Criador! o caco entre outros cacos de barro! Porventura dirá o barro ao que o formou: Que fazes? ou dirá a tua obra: Não tens mãos?' },
      { v: 10, en: 'Woe to him who says to a father, ‘What have you become the father of?’ or to a mother, ‘To what have you given birth?’”', pt: 'Ai daquele que diz ao pai: Que é o que geras? e à mulher: Que dás tu à luz?' },
      { v: 11, en: 'Yahweh, the Holy One of Israel, and his Maker says: “You ask me about the things that are to come, concerning my sons, and you command me concerning the work of my hands!', pt: 'Assim diz o Senhor, o Santo de Israel, aquele que o formou: Perguntai-me as coisas futuras; demandai-me acerca de meus filhos, e acerca da obra das minhas mãos.' },
      { v: 12, en: 'I have made the earth, and created man on it. I, even my hands, have stretched out the heavens; and I have commanded all their army.', pt: 'Eu é que fiz a terra, e nela criei o homem; as minhas mãos estenderam os céus, e a todo o seu exército dei as minhas ordens.' },
      { v: 13, en: 'I have raised him up in righteousness, and I will make straight all his ways. He shall build my city, and he shall let my exiles go free, not for price nor reward,” says Yahweh of Armies.', pt: 'Eu o despertei em justiça, e todos os seus caminhos endireitarei; ele edificará a minha cidade, e libertará os meus cativos, não por preço nem por presentes, diz o Senhor dos exércitos.' },
      { v: 14, en: 'Yahweh says: “The labor of Egypt, and the merchandise of Ethiopia, and the Sabeans, men of stature, shall come over to you, and they shall be yours. They will go after you. They shall come over in chains; and they will bow down to you. They will make supplication to you: ‘Surely God is in you; and there is no one else. There is no other god.', pt: 'Assim diz o Senhor: A riqueza do Egito, e as mercadorias da Etiópia, e os sabeus, homens de alta estatura, passarão para ti, e serão teus; irão atrás de ti; em grilhões virão; e, prostrando-se diante de ti, far-te-ão as suas súplicas, dizendo: Deus está contigo somente; e não há nenhum outro Deus.' },
      { v: 15, en: 'Most certainly you are a God who has hidden yourself, God of Israel, the Savior.’”', pt: 'Verdadeiramente tu és um Deus que te ocultas, ó Deus de Israel, o Salvador.' },
      { v: 16, en: 'They will be disappointed, yes, confounded, all of them. Those who are makers of idols will go into confusion together.', pt: 'Envergonhar-se-ão, e também se confundirão todos; cairão juntos em ignomínia os que fabricam ídolos.' },
      { v: 17, en: 'Israel will be saved by Yahweh with an everlasting salvation. You will not be disappointed nor confounded to ages everlasting.', pt: 'Mas Israel será salvo pelo Senhor, com uma salvação eterna; pelo que não sereis jamais envergonhados nem confundidos em toda a eternidade.' },
      { v: 18, en: 'For Yahweh who created the heavens, the God who formed the earth and made it, who established it and didn’t create it a waste, who formed it to be inhabited says: “I am Yahweh; and there is no other.', pt: 'Porque assim diz o Senhor, que criou os céus, o Deus que formou a terra, que a fez e a estabeleceu, não a criando para ser um caos, mas para ser habitada: Eu sou o Senhor e não há outro.' },
      { v: 19, en: 'I have not spoken in secret, in a place of the land of darkness. I didn’t say to the offspring of Jacob, ‘Seek me in vain.’ I, Yahweh, speak righteousness. I declare things that are right.', pt: 'Não falei em segredo, nalgum lugar tenebroso da terra; não disse à descendência de Jacó: Buscai-me no caos; eu, o Senhor, falo a justiça, e proclamo o que é reto.' },
      { v: 20, en: '“Assemble yourselves and come. Draw near together, you who have escaped from the nations. Those have no knowledge who carry the wood of their engraved image, and pray to a god that can’t save.', pt: 'Congregai-vos, e vinde; chegai-vos juntos, os que escapastes das nações; nada sabem os que conduzem em procissão as suas imagens de escultura, feitas de madeira, e rogam a um deus que não pode salvar.' },
      { v: 21, en: 'Declare and present it. Yes, let them take counsel together. Who has shown this from ancient time? Who has declared it of old? Haven’t I, Yahweh? There is no other God besides me, a just God and a Savior; There is no one besides me.', pt: 'Anunciai e apresentai as razões: tomai conselho todos juntos. Quem mostrou isso desde a antigüidade? quem de há muito o anunciou? Porventura não sou eu, o Senhor? Pois não há outro Deus senão eu; Deus justo e Salvador não há além de mim.' },
      { v: 22, en: '“Look to me, and be saved, all the ends of the earth; for I am God, and there is no other.', pt: 'Olhai para mim, e sereis salvos, vós, todos os confins da terra; porque eu sou Deus, e não há outro.' },
      { v: 23, en: 'I have sworn by myself. The word has gone out of my mouth in righteousness, and will not be revoked, that to me every knee shall bow, every tongue shall take an oath.', pt: 'Por mim mesmo jurei; já saiu da minha boca a palavra de justiça, e não tornará atrás. Diante de mim se dobrará todo joelho, e jurará toda língua.' },
      { v: 24, en: 'They will say of me, ‘There is righteousness and strength only in Yahweh.’” Even to him shall men come; and all those who raged against him shall be disappointed.', pt: 'De mim se dirá: Tão somente no senhor há justiça e força. A ele virão, envergonhados, todos os que se irritarem contra ele.' },
      { v: 25, en: 'All the offspring of Israel will be justified in Yahweh, and will rejoice!', pt: 'Mas no Senhor será justificada e se gloriará toda a descendência de Israel.' },
    ],
    46: [
      { v: 1, en: 'Bel bows down. Nebo stoops. Their idols are carried by animals, and on the livestock. The things that you carried around are heavy loads, a burden for the weary.', pt: 'Bel se encurva, Nebo se abaixa; os seus ídolos são postos sobre os animais, sobre as bestas; essas cargas que costumáveis levar são pesadas para as bestas já cansadas.' },
      { v: 2, en: 'They stoop and they bow down together. They could not deliver the burden, but they have gone into captivity.', pt: 'Eles juntamente se abaixam e se encurvam; não podem salvar a carga, mas eles mesmos vão para o cativeiro.' },
      { v: 3, en: '“Listen to me, house of Jacob, and all the remnant of the house of Israel, that have been carried from their birth, that have been carried from the womb.', pt: 'Ouvi-me, ó casa de Jacó, e todo o resto da casa de Israel, vós que por mim tendes sido carregados desde o ventre, que tendes sido levados desde a madre.' },
      { v: 4, en: 'Even to old age I am he, and even to gray hairs I will carry you. I have made, and I will bear. Yes, I will carry, and will deliver.', pt: 'Até a vossa velhice eu sou o mesmo, e ainda até as cãs eu vos carregarei; eu vos criei, e vos levarei; sim, eu vos carregarei e vos livrarei.' },
      { v: 5, en: '“To whom will you compare me, and consider my equal, and compare me, as if we were the same?', pt: 'A quem me assemelhareis, e com quem me igualareis e me comparareis, para que sejamos semelhantes?' },
      { v: 6, en: 'Some pour out gold from the bag, and weigh silver in the balance. They hire a goldsmith, and he makes it a god. They fall down— yes, they worship.', pt: 'Os que prodigalizam o ouro da bolsa, e pesam a prata nas balanças, assalariam o ourives, e ele faz um deus; e diante dele se prostram e adora,' },
      { v: 7, en: 'They bear it on their shoulder. They carry it, and set it in its place, and it stands there. It cannot move from its place. Yes, one may cry to it, yet it can not answer. It cannot save him out of his trouble.', pt: 'Eles o tomam sobre os ombros, o levam, e o colocam no seu lugar, e ali permanece; do seu lugar não se pode mover; e, se recorrem a ele, resposta nenhuma dá, nem livra alguém da sua tribulação.' },
      { v: 8, en: '“Remember this, and show yourselves men. Bring it to mind again, you transgressors.', pt: 'Lembrai-vos, disto, e considerai; trazei-o à memória, ó transgressores.' },
      { v: 9, en: 'Remember the former things of old: for I am God, and there is no other. I am God, and there is none like me.', pt: 'Lembrai-vos das coisas passadas desde a antigüidade; que eu sou Deus, e não há outro; eu sou Deus, e não há outro semelhante a mim;' },
      { v: 10, en: 'I declare the end from the beginning, and from ancient times things that are not yet done. I say: My counsel will stand, and I will do all that I please.', pt: 'que anuncio o fim desde o princípio, e desde a antigüidade as coisas que ainda não sucederam; que digo: O meu conselho subsistirá, e farei toda a minha vontade;' },
      { v: 11, en: 'I call a ravenous bird from the east, the man of my counsel from a far country. Yes, I have spoken. I will also bring it to pass. I have planned. I will also do it.', pt: 'chamando do oriente uma ave de rapina, e dum país remoto o homem do meu conselho; sim, eu o disse, e eu o cumprirei; formei esse propósito, e também o executarei.' },
      { v: 12, en: 'Listen to me, you stubborn-hearted, who are far from righteousness!', pt: 'Ouvi-me, ó duros de coração, os que estais longe da justiça.' },
      { v: 13, en: 'I bring my righteousness near. It is not far off, and my salvation will not wait. I will grant salvation to Zion, my glory to Israel.', pt: 'Faço chegar a minha justiça; e ela não está longe, e a minha salvação não tardará; mas estabelecerei a salvação em Sião, e em Israel a minha glória.' },
    ],
    47: [
      { v: 1, en: '“Come down, and sit in the dust, virgin daughter of Babylon. Sit on the ground without a throne, daughter of the Chaldeans. For you will no longer be called tender and delicate.', pt: 'Desce, e assenta-te no pó, ó virgem filha de Babilônia; assenta-te no chão sem trono, ó filha dos caldeus, porque nunca mais seras chamada a mimosa nem a delicada.' },
      { v: 2, en: 'Take the millstones, and grind flour. Remove your veil, lift up your skirt, uncover your legs, and wade through the rivers.', pt: 'Toma a mó, e mói a farinha; remove o teu véu, suspende a cauda da tua vestidura, descobre as pernas e passa os rios.' },
      { v: 3, en: 'Your nakedness will be uncovered. Yes, your shame will be seen. I will take vengeance, and will spare no one.”', pt: 'A tua nudez será descoberta, e ver-se-á o teu opróbrio; tomarei vingança, e não pouparei a homem algum.' },
      { v: 4, en: 'Our Redeemer, Yahweh of Armies is his name, is the Holy One of Israel.', pt: 'Quanto ao nosso Redentor, o Senhor dos exércitos é o seu nome, o Santo de Israel.' },
      { v: 5, en: '“Sit in silence, and go into darkness, daughter of the Chaldeans. For you shall no longer be called the mistress of kingdoms.', pt: 'Assenta-te calada, e entra nas trevas, ó filha dos caldeus; porque não serás chamada mais a senhora de reinos.' },
      { v: 6, en: 'I was angry with my people. I profaned my inheritance, and gave them into your hand. You showed them no mercy. You laid a very heavy yoke on the aged.', pt: 'Muito me agastei contra o meu povo, profanei a minha herança, e os entreguei na tua mão; não usaste de misericórdia para com eles, e até sobre os velhos fizeste muito pesado o teu jugo.' },
      { v: 7, en: 'You said, ‘I will be a princess forever;’ so that you did not lay these things to your heart, nor did you remember the results.', pt: 'E disseste: Eu serei senhora para sempre; de sorte que até agora não tomaste a peito estas coisas, nem te lembraste do fim delas.' },
      { v: 8, en: '“Now therefore hear this, you who are given to pleasures, who sit securely, who say in your heart, ‘I am, and there is no one else besides me. I shall not sit as a widow, neither shall I know the loss of children.’', pt: 'Agora pois ouve isto, tu que és dada a prazeres, que habitas descuidada, que dizes no teu coração: Eu sou, e fora de mim não há outra; não ficarei viúva, nem conhecerei a perda de filhos.' },
      { v: 9, en: 'But these two things shall come to you in a moment in one day, the loss of children and widowhood. They will come on you in their full measure, in the multitude of your sorceries, and the great abundance of your enchantments.', pt: 'Mas ambas estas coisas virão sobre ti num momento, no mesmo dia, perda de filhos e viuvez; em toda a sua plenitude virão sobre ti, apesar da multidão das tuas feitiçarias, e da grande abundância dos teus encantamentos.' },
      { v: 10, en: 'For you have trusted in your wickedness. You have said, ‘No one sees me.’ Your wisdom and your knowledge has perverted you. You have said in your heart, ‘I am, and there is no one else besides me.’', pt: 'Porque confiaste na tua maldade e disseste: Ninguém me vê; a tua sabedoria e o teu conhecimento, essas coisas te perverteram; e disseste no teu coração: Eu sou, e fora de mim não há outra.' },
      { v: 11, en: 'Therefore disaster will come on you. You won’t know when it dawns. Mischief will fall on you. You won’t be able to put it away. Desolation will come on you suddenly, which you don’t understand.', pt: 'Pelo que sobre ti virá o mal de que por encantamentos não saberás livrar-te; e tal destruição cairá sobre ti, que não a poderás afastar; e virá sobre ti de repente tão tempestuosa desolação, que não a poderás conhecer.' },
      { v: 12, en: '“Stand now with your enchantments, and with the multitude of your sorceries, in which you have labored from your youth; as if you might profit; as if you might prevail.', pt: 'Deixa-te estar com os teus encantamentos, e com a multidão das tuas feitiçarias em que te hás fatigado desde a tua mocidade, a ver se podes tirar proveito, ou se porventura podes inspirar terror.' },
      { v: 13, en: 'You are wearied in the multitude of your counsels. Now let the astrologers, the stargazers, and the monthly prognosticators, stand up and save you from the things that will come on you.', pt: 'Cansaste-te na multidão dos teus conselhos; levantem-se pois agora e te salvem os astrólogos, que contemplam os astros, e os que nas luas novas prognosticam o que há de vir sobre ti.' },
      { v: 14, en: 'Behold, they are like stubble. The fire will burn them. They won’t deliver themselves from the power of the flame. It won’t be a coal to warm at or a fire to sit by.', pt: 'Eis que são como restolho; o logo os queimará; não poderão livrar-se do poder das chamas; pois não é um braseiro com que se aquentar, nem fogo para se sentar junto dele.' },
      { v: 15, en: 'The things that you labored in will be like this: those who have trafficked with you from your youth will each wander in his own way. There will be no one to save you.', pt: 'Assim serão para contigo aqueles com quem te hás fatigado, os que tiveram negócios contigo desde a tua mocidade; andarão vagueando, cada um pelo seu caminho; não haverá quem te salve.' },
    ],
    48: [
      { v: 1, en: '“Hear this, house of Jacob, you who are called by the name of Israel, and have come out of the waters of Judah. You swear by Yahweh’s name, and make mention of the God of Israel, but not in truth, nor in righteousness', pt: 'Ouvi isto, casa de Jacó, que vos chamais do nome de Israel, e saístes dos lombos de Judá, que jurais pelo nome do Senhor, e fazeis menção do Deus de Israel, mas não em verdade nem em justiça.' },
      { v: 2, en: '(for they call themselves citizens of the holy city, and rely on the God of Israel; Yahweh of Armies is his name):', pt: 'E até da santa cidade tomam o nome, e se firmam sobre o Deus de Israel; o Senhor dos exércitos é o seu nome.' },
      { v: 3, en: 'I have declared the former things from of old; yes, they went out of my mouth, and I revealed them. I did them suddenly, and they happened.', pt: 'Desde a antigüidade anunciei as coisas que haviam de ser; da minha boca é que saíram, e eu as fiz ouvir; de repente as pus por obra, e elas aconteceram.' },
      { v: 4, en: 'Because I knew that you are obstinate, and your neck is an iron sinew, and your brow brass;', pt: 'Porque eu sabia que és obstinado, que a tua cerviz é um nervo de ferro, e a tua testa de bronze.' },
      { v: 5, en: 'therefore I have declared it to you from of old; before it came to pass I showed it to you; lest you should say, ‘My idol has done them, and my engraved image, and my molten image, has commanded them.’', pt: 'Há muito tas anunciei, e as manifestei antes que acontecessem, para que não dissesses: O meu ídolo fez estas coisas, ou a minha imagem de escultura, ou a minha imagem de fundição as ordenou.' },
      { v: 6, en: 'You have heard it; see all this. And you, won’t you declare it? “I have shown you new things from this time, even hidden things, which you have not known.', pt: 'Já o tens ouvido; olha bem para tudo isto; porventura não o anunciarás? Desde agora te mostro coisas novas e ocultas, que não sabias.' },
      { v: 7, en: 'They are created now, and not from of old; and before today you didn’t hear them; lest you should say, ‘Behold, I knew them.’', pt: 'São criadas agora, e não de há muito, e antes deste dia não as ouviste, para que não digas: Eis que já eu as sabia.' },
      { v: 8, en: 'Yes, you didn’t hear; yes, you didn’t know; yes, from of old your ear was not opened: for I knew that you dealt very treacherously, and were called a transgressor from the womb.', pt: 'Tu nem as ouviste, nem as conheceste, nem tampouco há muito foi aberto o teu ouvido; porque eu sabia que procedeste muito perfidamente, e que eras chamado transgressor desde o ventre.' },
      { v: 9, en: 'For my name’s sake, I will defer my anger, and for my praise I hold it back for you, so that I don’t cut you off.', pt: 'Por amor do meu nome retardo a minha ira, e por causa do meu louvor me contenho para contigo, para que eu não te extermine.' },
      { v: 10, en: 'Behold, I have refined you, but not as silver. I have chosen you in the furnace of affliction.', pt: 'Eis que te purifiquei, mas não como a prata; provei-te na fornalha da aflição,' },
      { v: 11, en: 'For my own sake, for my own sake, I will do it; for how would my name be profaned? I will not give my glory to another.', pt: 'Por amor de mim, por amor de mim o faço; porque como seria profanado o meu nome? A minha glória não a darei a outrem,' },
      { v: 12, en: '“Listen to me, O Jacob, and Israel my called: I am he; I am the first, I am also the last.', pt: 'Escuta-me, ó Jacó, e tu, ó Israel, a quem chamei; eu sou o mesmo, eu o primeiro, eu também o último.' },
      { v: 13, en: 'Yes, my hand has laid the foundation of the earth, and my right hand has spread out the heavens. when I call to them, they stand up together.', pt: 'Também a minha mão fundou a terra, e a minha destra estendeu os céus; quando eu os chamo, eles aparecem juntos.' },
      { v: 14, en: '“Assemble yourselves, all of you, and hear; who among them has declared these things? He whom Yahweh loves will do what he likes to Babylon, and his arm will be against the Chaldeans.', pt: 'Ajuntai-vos todos vós, e ouvi: Quem, dentre eles, tem anunciado estas coisas? Aquele a quem o Senhor amou executará a sua vontade contra Babilônia, e o seu braço será contra os caldeus.' },
      { v: 15, en: 'I, even I, have spoken; yes, I have called him. I have brought him, and he shall make his way prosperous.', pt: 'Eu, eu o tenho dito; também já o chamei; eu o trouxe, e o seu caminho será próspero.' },
      { v: 16, en: '“Come near to me and hear this: “From the beginning I have not spoken in secret; from the time that it happened, I was there.” Now the Lord Yahweh has sent me, with his Spirit.', pt: 'Chegai-vos a mim, ouvi isto: Não falei em segredo desde o princípio; desde o tempo em que aquilo se fez, eu estava ali; e agora o Senhor Deus me enviou juntamente com o seu Espírito.' },
      { v: 17, en: 'Yahweh, your Redeemer, the Holy One of Israel says: “I am Yahweh your God, who teaches you to profit, who leads you by the way that you should go.', pt: 'Assim diz o Senhor, o teu Redentor, o Santo de Israel: Eu sou o Senhor, o teu Deus, que te ensina o que é útil, e te guia pelo caminho em que deves andar.' },
      { v: 18, en: 'Oh that you had listened to my commandments! Then your peace would have been like a river, and your righteousness like the waves of the sea.', pt: 'Ah! se tivesses dado ouvidos aos meus mandamentos! então seria a tua paz como um rio, e a tua justiça como as ondas do mar;' },
      { v: 19, en: 'Your offspring also would have been as the sand, and the descendants of your body like its grains. His name would not be cut off nor destroyed from before me.”', pt: 'também a tua descendência teria sido como a areia, e os que procedem das tuas entranhas como os seus grãos; o seu nome nunca seria cortado nem destruído de diante de mim.' },
      { v: 20, en: 'Leave Babylon! Flee from the Chaldeans! With a voice of singing announce this, tell it even to the end of the earth: say, “Yahweh has redeemed his servant Jacob!”', pt: 'Saí de Babilônia, fugi de entre os caldeus. E anunciai com voz de júbilo, fazei ouvir isto, e levai-o até o fim da terra; dizei: O Senhor remiu a seu servo Jacó;' },
      { v: 21, en: 'They didn’t thirst when he led them through the deserts. He caused the waters to flow out of the rock for them. He split the rock also, and the waters gushed out.', pt: 'e não tinham sede, quando os levava pelos desertos; fez-lhes correr água da rocha; fendeu a rocha, e as águas jorraram.' },
      { v: 22, en: '“There is no peace”, says Yahweh, “for the wicked.”', pt: 'Não há paz para os ímpios, diz o Senhor.' },
    ],
    49: [
      { v: 1, en: 'Listen, islands, to me. Listen, you peoples, from afar: Yahweh has called me from the womb; from the inside of my mother he has mentioned my name.', pt: 'Ouvi-me, ilhas, e escutai vós, povos de longe: O Senhor chamou-me desde o ventre, desde as entranhas de minha mãe fez menção do meu nome' },
      { v: 2, en: 'He has made my mouth like a sharp sword. He has hidden me in the shadow of his hand. He has made me a polished shaft. He has kept me close in his quiver.', pt: 'e fez a minha boca qual espada aguda; na sombra da sua mão me escondeu; fez-me qual uma flecha polida, e me encobriu na sua aljava;' },
      { v: 3, en: 'He said to me, “You are my servant; Israel, in whom I will be glorified.”', pt: 'e me disse: Tu és meu servo; és Israel, por quem hei de ser glorificado.' },
      { v: 4, en: 'But I said, “I have labored in vain. I have spent my strength in vain for nothing; yet surely the justice due to me is with Yahweh, and my reward with my God.”', pt: 'Mas eu disse: Debalde tenho trabalhado, inútil e vãmente gastei as minhas forças; todavia o meu direito está perante o Senhor, e o meu galardão perante o meu Deus.' },
      { v: 5, en: 'Now Yahweh says, he who formed me from the womb to be his servant, to bring Jacob again to him, and to gather Israel to him, for I am honorable in Yahweh’s eyes, and my God has become my strength.', pt: 'E agora diz o Senhor, que me formou desde o ventre para ser o seu servo, para tornar a trazer-lhe Jacó, e para reunir Israel a ele (pois aos olhos do Senhor sou glorificado, e o meu Deus se fez a minha força).' },
      { v: 6, en: 'Indeed, he says, “It is too light a thing that you should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel? I will also give you as a light to the nations, that you may be my salvation to the end of the earth.”', pt: 'Sim, diz ele: Pouco é que sejas o meu servo, para restaurares as tribos de Jacó, e tornares a trazer os preservados de Israel; também te porei para luz das nações, para seres a minha salvação até a extremidade da terra.' },
      { v: 7, en: 'Yahweh, the Redeemer of Israel, and his Holy One, says to him whom man despises, to him whom the nation abhors, to a servant of rulers: “Kings shall see and rise up; princes, and they shall worship; because of Yahweh who is faithful, even the Holy One of Israel, who has chosen you.”', pt: 'Assim diz o Senhor, o Redentor de Israel, e o seu Santo, ao que é desprezado dos homens, ao que é aborrecido das nações, ao servo dos tiranos: Os reis o verão e se levantarão, como também os príncipes, e eles te adorarão, por amor do Senhor, que é fiel, e do Santo de Israel, que te escolheu.' },
      { v: 8, en: 'Yahweh says, “In an acceptable time I have answered you, and in a day of salvation I have helped you. I will preserve you, and give you for a covenant of the people, to raise up the land, to make them inherit the desolate heritage,', pt: 'Assim diz o Senhor: No tempo aceitável te ouvi, e no dia da salvação te ajudei; e te guardarei, e te darei por pacto do povo, para restaurares a terra, e lhe dares em herança as herdades assoladas;' },
      { v: 9, en: 'saying to those who are bound, ‘Come out!’; to those who are in darkness, ‘Show yourselves!’ “They shall feed along the paths, and their pasture shall be on all treeless heights.', pt: 'para dizeres aos presos: Saí; e aos que estão em trevas: Aparecei; eles pastarão nos caminhos, e em todos os altos desnudados haverá o seu pasto.' },
      { v: 10, en: 'They shall not hunger nor thirst; neither shall the heat nor sun strike them: for he who has mercy on them will lead them. He will guide them by springs of water.', pt: 'Nunca terão fome nem sede; não os afligirá nem a calma nem o sol; porque o que se compadece deles os guiará, e os conduzirá mansamente aos mananciais das águas.' },
      { v: 11, en: 'I will make all my mountains a road, and my highways shall be exalted.', pt: 'Farei de todos os meus montes um caminho; e as minhas estradas serão exaltadas.' },
      { v: 12, en: 'Behold, these shall come from afar; and behold, these from the north and from the west; and these from the land of Sinim.”', pt: 'Eis que estes virão de longe, e eis que aqueles do Norte e do Ocidente, e aqueles outros da terra de Sinim.' },
      { v: 13, en: 'Sing, heavens; and be joyful, earth; and break out into singing, mountains: for Yahweh has comforted his people, and will have compassion on his afflicted.', pt: 'Cantai, ó céus, e exulta, ó terra, e vós, montes, estalai de júbilo, porque o Senhor consolou o seu povo, e se compadeceu dos seus aflitos.' },
      { v: 14, en: 'But Zion said, “Yahweh has forsaken me, and the Lord has forgotten me.”', pt: 'Mas Sião diz: O Senhor me desamparou, o meu Senhor se esqueceu de mim.' },
      { v: 15, en: '“Can a woman forget her nursing child, that she should not have compassion on the son of her womb? Yes, these may forget, yet I will not forget you!', pt: 'pode uma mulher esquecer-se de seu filho de peito, de maneira que não se compadeça do filho do seu ventre? Mas ainda que esta se esquecesse, eu, todavia, não me esquecerei de ti.' },
      { v: 16, en: 'Behold, I have engraved you on the palms of my hands. your walls are continually before me.', pt: 'Eis que nas palmas das minhas mãos eu te gravei; os teus muros estão continuamente diante de mim.' },
      { v: 17, en: 'Your children hurry. Your destroyers and those who devastated you will leave you.', pt: 'Os teus filhos pressurosamente virão; mas os teus destruidores e os teus assoladores sairão do meio de ti.' },
      { v: 18, en: 'Lift up your eyes all around, and see: all these gather themselves together, and come to you. As I live,” says Yahweh, “you shall surely clothe yourself with them all as with an ornament, and dress yourself with them, like a bride.', pt: 'Levanta os teus olhos ao redor, e olha; todos estes que se ajuntam vêm ter contigo. Vivo eu, diz o Senhor, que de todos estes te vestirás, como dum ornamento, e te cingirás deles como a noiva.' },
      { v: 19, en: '“For, as for your waste and your desolate places, and your land that has been destroyed, surely now that land will be too small for the inhabitants, and those who swallowed you up will be far away.', pt: 'Pois quanto aos teus desertos, e lugares desolados, e à tua terra destruída, serás agora estreita demais para os moradores, e os que te devoravam se afastarão para longe de ti.' },
      { v: 20, en: 'The children of your bereavement will say in your ears, ‘This place is too small for me. Give me a place to live in.’', pt: 'Os filhos de que foste privada ainda dirão aos teus ouvidos: Muito estreito é para mim este lugar; dá-me espaço em que eu habite.' },
      { v: 21, en: 'Then you will say in your heart, ‘Who has conceived these for me, since I have been bereaved of my children, and am solitary, an exile, and wandering back and forth? Who has brought these up? Behold, I was left alone. Where were these?’”', pt: 'Então no teu coração dirás: Quem me gerou estes, visto que eu era desfilhada e solitária, exilada e errante? quem, pois, me criou estes? Fui deixada sozinha; estes onde estavam?' },
      { v: 22, en: 'Thus says the Lord Yahweh, “Behold, I will lift up my hand to the nations, and lift up my banner to the peoples; and they shall bring your sons in their bosom, and your daughters shall be carried on their shoulders.', pt: 'Assim diz o Senhor Deus: Eis que levantarei a minha mão para as nações, e ante os povos arvorarei a minha bandeira; então eles trarão os teus filhos nos braços, e as tuas filhas serão levadas sobre os ombros.' },
      { v: 23, en: 'Kings shall be your foster fathers, and their queens your nursing mothers. They will bow down to you with their faces to the earth, and lick the dust of your feet; Then you will know that I am Yahweh; and those who wait for me shall not be disappointed.”', pt: 'Reis serão os teus aios, e as suas rainhas as tuas amas; diante de ti se inclinarão com o rosto em terra e lamberão o pó dos teus pés; e saberás que eu sou o Senhor, e que os que por mim esperam não serão confundidos.' },
      { v: 24, en: 'Shall the plunder be taken from the mighty, or the lawful captives be delivered?', pt: 'Acaso tirar-se-ia a presa ao valente? ou serão libertados os cativos de um tirano?' },
      { v: 25, en: 'But Yahweh says, “Even the captives of the mighty shall be taken away, and the plunder retrieved from the fierce; for I will contend with him who contends with you, and I will save your children.', pt: 'Mas assim diz o Senhor: Certamente os cativos serão tirados ao valente, e a presa do tirano será libertada; porque eu contenderei com os que contendem contigo, e os teus filhos eu salvarei.' },
      { v: 26, en: 'I will feed those who oppress you with their own flesh; and they will be drunk on their own blood, as with sweet wine. Then all flesh shall know that I, Yahweh, am your Savior, and your Redeemer, the Mighty One of Jacob.”', pt: 'E sustentarei os teus opressores com a sua propria carne, e com o seu proprio sangue se embriagarão, como com mosto; e toda a carne saberá que eu sou o Senhor, o teu Salvador e o teu Redentor, o Poderoso de Jacó.' },
    ],
    50: [
      { v: 1, en: 'Yahweh says, “Where is the bill of your mother’s divorce, with which I have put her away? or to which of my creditors have I sold you? Behold, you were sold for your iniquities, and your mother was put away for your transgressions.', pt: 'Assim diz o Senhor: Onde está a carta de divórcio de vossa mãe, pela qual eu a repudiei? ou quem é o meu credor, a quem eu vos tenha vendido? Eis que por vossas maldades fostes vendidos, e por vossas transgressões foi repudiada vossa mãe.' },
      { v: 2, en: 'Why, when I came, was there no one? when I called, why was there no one to answer? Is my hand shortened at all, that it can’t redeem? or have I no power to deliver? Behold, at my rebuke I dry up the sea. I make the rivers a wilderness: their fish stink, because there is no water, and die for thirst.', pt: 'Por que razão, quando eu vim, ninguém apareceu? quando chamei, não houve quem respondesse? Acaso tanto se encolheu a minha mão, que já não possa remir? ou não tenho poder para livrar? Eis que com a minha repreensão faço secar o mar, e torno os rios em deserto; cheiram mal os seus peixes, pois não há água, e morrem de sede:' },
      { v: 3, en: 'I clothe the heavens with blackness, and I make sackcloth their covering.”', pt: 'Eu visto os céus de negridão, e lhes ponho cilício por sua cobertura.' },
      { v: 4, en: 'The Lord Yahweh has given me the tongue of those who are taught, that I may know how to sustain with words him who is weary. He wakens morning by morning, he wakens my ear to hear as those who are taught.', pt: 'O Senhor Deus me deu a língua dos instruídos para que eu saiba sustentar com uma palavra o que está cansado; ele desperta-me todas as manhãs; desperta-me o ouvido para que eu ouça como discípulo.' },
      { v: 5, en: 'The Lord Yahweh has opened my ear, and I was not rebellious. I have not turned back.', pt: 'O Senhor Deus abriu-me os ouvidos, e eu não fui rebelde, nem me retirei para trás.' },
      { v: 6, en: 'I gave my back to those who beat me, and my cheeks to those who plucked off the hair. I didn’t hide my face from shame and spitting.', pt: 'Ofereci as minhas costas aos que me feriam, e as minhas faces aos que me arrancavam a barba; não escondi o meu rosto dos que me afrontavam e me cuspiam.' },
      { v: 7, en: 'For the Lord Yahweh will help me. Therefore I have not been confounded. Therefore I have set my face like a flint, and I know that I shall not be disappointed.', pt: 'Pois o Senhor Deus me ajuda; portanto não me sinto confundido; por isso pus o meu rosto como um seixo, e sei que não serei envergonhado.' },
      { v: 8, en: 'He who justifies me is near. Who will bring charges against me? Let us stand up together. Who is my adversary? Let him come near to me.', pt: 'Perto está o que me justifica; quem contenderá comigo? apresentemo-nos juntos; quem é meu adversário? chegue-se para mim.' },
      { v: 9, en: 'Behold, the Lord Yahweh will help me! Who is he who will condemn me? Behold, they will all grow old like a garment. The moths will eat them up.', pt: 'Eis que o Senhor Deus me ajuda; quem há que me condene? Eis que todos eles se envelhecerão como um vestido, e a traça os comerá.' },
      { v: 10, en: 'Who among you fears Yahweh, and obeys the voice of his servant? He who walks in darkness, and has no light, let him trust in Yahweh’s name, and rely on his God.', pt: 'Quem há entre vós que tema ao Senhor? ouça ele a voz do seu servo. Aquele que anda em trevas, e não tem luz, confie no nome do Senhor, e firme-se sobre o seu Deus.' },
      { v: 11, en: 'Behold, all you who kindle a fire, who adorn yourselves with torches around yourselves; walk in the flame of your fire, and among the torches that you have kindled. You will have this from my hand: You will lie down in sorrow.', pt: 'Eia! todos vós, que acendeis fogo, e vos cingis com tições acesos; andai entre as labaredas do vosso fogo, e entre os tições que ateastes! Isto vos sobrevirá da minha mão, e em tormentos jazereis.' },
    ],
    51: [
      { v: 1, en: '“Listen to me, you who follow after righteousness, you who seek Yahweh: look to the rock you were cut from, and to the quarry you were dug from.', pt: 'Ouvi-me vós, os que seguis a justiça, os que buscais ao Senhor; olhai para a rocha donde fostes cortados, e para a caverna do poço donde fostes cavados.' },
      { v: 2, en: 'Look to Abraham your father, and to Sarah who bore you; for when he was but one I called him, and I blessed him, and made him many.', pt: 'Olhai para Abraão, vosso pai, e para Sara, que vos deu à luz; porque ainda quando ele era um só, eu o chamei, e o abençoei e o multipliquei.' },
      { v: 3, en: 'For Yahweh has comforted Zion. He has comforted all her waste places, and has made her wilderness like Eden, and her desert like the garden of Yahweh. Joy and gladness will be found therein, thanksgiving, and the voice of melody.', pt: 'Porque o Senhor consolará a Sião; consolará a todos os seus lugares assolados, e fará o seu deserto como o Edem e a sua solidão como o jardim do Senhor; gozo e alegria se acharão nela, ação de graças, e voz de cântico.' },
      { v: 4, en: '“Listen to me, my people; and hear me, my nation: for a law will go out from me, and I will establish my justice for a light to the peoples.', pt: 'Atendei-me, povo meu, e nação minha, inclinai os ouvidos para mim; porque de mim sairá a lei, e estabelecerei a minha justiça como luz dos povos.' },
      { v: 5, en: 'My righteousness is near. My salvation has gone out, and my arms will judge the peoples. The islands will wait for me, and they will trust my arm.', pt: 'Perto está a minha justiça, vem saindo a minha salvação, e os meus braços governarão os povos; as ilhas me aguardam, e no meu braço esperam.' },
      { v: 6, en: 'Lift up your eyes to the heavens, and look on the earth beneath; for the heavens will vanish away like smoke, and the earth will wear out like a garment; and its inhabitants will die in the same way: but my salvation will be forever, and my righteousness will not be abolished.', pt: 'Levantai os vossos olhos para os céus e olhai para a terra em baixo; porque os céus desaparecerão como a fumaça, e a terra se envelhecerá como um vestido; e os seus moradores morrerão semelhantemente; a minha salvação, porém, durará para sempre, e a minha justiça não será abolida.' },
      { v: 7, en: '“Listen to me, you who know righteousness, the people in whose heart is my law: Don’t fear the reproach of men, and don’t be dismayed at their insults.', pt: 'Ouvi-me, vós que conheceis a justiça, vós, povo, em cujo coração está a minha lei; não temais o opróbrio dos homens, nem vos turbeis pelas suas injúrias.' },
      { v: 8, en: 'For the moth will eat them up like a garment, and the worm will eat them like wool; but my righteousness will be forever, and my salvation to all generations.”', pt: 'Pois a traça os roerá como a um vestido, e o bicho os comerá como à lã; a minha justiça, porém, durará para sempre, e a minha salvação para todas as gerações.' },
      { v: 9, en: 'Awake, awake, put on strength, arm of Yahweh! Awake, as in the days of old, the generations of ancient times. Isn’t it you who cut Rahab in pieces, who pierced the monster?', pt: 'Desperta, desperta, veste-te de força, ó braço do Senhor; desperta como nos dias da antigüidade, como nas gerações antigas. Porventura não és tu aquele que cortou em pedaços a Raabe, e traspassou ao dragão,' },
      { v: 10, en: 'Isn’t it you who dried up the sea, the waters of the great deep; who made the depths of the sea a way for the redeemed to pass over?', pt: 'Não és tu aquele que secou o mar, as águas do grande abismo? o que fez do fundo do mar um caminho, para que por ele passassem os remidos?' },
      { v: 11, en: 'Those ransomed by Yahweh will return, and come with singing to Zion; and everlasting joy shall be on their heads. They will obtain gladness and joy. Sorrow and sighing shall flee away.', pt: 'Assim voltarão os resgatados do Senhor, e virão com júbilo a Sião; e haverá perpétua alegria sobre as suas cabeças; gozo e alegria alcançarão, a tristeza e o gemido fugirão.' },
      { v: 12, en: '“I, even I, am he who comforts you. Who are you, that you are afraid of man who shall die, and of the son of man who will be made as grass?', pt: 'Eu, eu sou aquele que vos consola; quem, pois, és tu, para teres medo dum homem, que é mortal, ou do filho do homem que se tornará como feno;' },
      { v: 13, en: 'Have you forgotten Yahweh your Maker, who stretched out the heavens, and laid the foundations of the earth? Do you live in fear continually all day because of the fury of the oppressor, when he prepares to destroy? Where is the fury of the oppressor?', pt: 'e te esqueces de Senhor, o teu Criador, que estendeu os céus, e fundou a terra, e temes continuamente o dia todo por causa do furor do opressor, quando se prepara para destruir? Onde está o furor do opressor?' },
      { v: 14, en: 'The captive exile will speedily be freed; and he will not die and go down into the pit, and his bread will not fail.', pt: 'O exilado cativo depressa será solto, e não morrerá para ir à sepultura, nem lhe faltará o pão.' },
      { v: 15, en: 'For I am Yahweh your God, who stirs up the sea, so that its waves roar: Yahweh of Armies is his name.', pt: 'Pois eu sou o Senhor teu Deus, que agita o mar, de modo que bramem as suas ondas. O Senhor dos exércitos é o seu nome.' },
      { v: 16, en: 'I have put my words in your mouth, and have covered you in the shadow of my hand, that I may plant the heavens, and lay the foundations of the earth, and tell Zion, ‘You are my people.’”', pt: 'E pus as minhas palavras na tua boca, e te cubro com a sombra da minha mão; para plantar os céus, e para fundar a terra, e para dizer a Sião: Tu és o meu povo.' },
      { v: 17, en: 'Awake, awake! Stand up, Jerusalem, you who have drunk from Yahweh’s hand the cup of his wrath. You have drunken the bowl of the cup of staggering, and drained it.', pt: 'Desperta, desperta, levanta-te, ó Jerusalém, que bebeste da mão do Senhor o cálice do seu furor; que bebeste da taça do atordoamento, e a esgotaste.' },
      { v: 18, en: 'There is no one to guide her among all the sons to whom she has given birth; and there is no one who takes her by the hand among all the sons who she has brought up.', pt: 'De todos os filhos que ela teve, nenhum há que a guie; e de todos os filhos que criou, nenhum há que a tome pela mão.' },
      { v: 19, en: 'These two things have happened to you— who will grieve with you?— desolation and destruction, and famine and the sword. How can I comfort you?', pt: 'Estas duas coisas te aconteceram; quem terá compaixão de ti? a assolação e a ruína, a fome e a espada; quem te consolará?' },
      { v: 20, en: 'Your sons have fainted. They lie at the head of all the streets, like an antelope in a net. They are full of the Yahweh’s wrath, the rebuke of your God.', pt: 'Os teus filhos já desmaiaram, jazem nas esquinas de todas as ruas, como o antílope tomado na rede; cheios estão do furor do Senhor, e da repreensão do teu Deus.' },
      { v: 21, en: 'Therefore now hear this, you afflicted, and drunken, but not with wine:', pt: 'Pelo que agora ouve isto, ó aflita, e embriagada, mas não de vinho.' },
      { v: 22, en: 'Thus says your Lord Yahweh, your God who pleads the cause of his people, “Behold, I have taken out of your hand the cup of staggering, even the bowl of the cup of my wrath. You will not drink it any more:', pt: 'Assim diz o Senhor Deus e o teu Deus, que pleiteia a causa do seu povo: Eis que eu tiro da tua mão a taça de atordoamento e o cálice do meu furor; nunca mais dele beberás;' },
      { v: 23, en: 'and I will put it into the hand of those who afflict you, who have said to your soul, ‘Bow down, that we may walk over you;’ and you have laid your back as the ground, like a street to those who walk over.”', pt: 'mas pô-lo-ei nas mãos dos que te afligem, os quais te diziam: Abaixa-te, para que passemos sobre ti; e tu puseste as tuas costas como o chão, e como a rua para os que passavam.' },
    ],
    52: [
      { v: 1, en: 'Awake, awake! Put on your strength, Zion. Put on your beautiful garments, Jerusalem, the holy city: for from now on the uncircumcised and the unclean will no more come into you.', pt: 'Desperta, desperta, veste-te da tua fortaleza, Sião; veste-te dos teus vestidos formosos, ó Jerusalém, cidade santa; porque nunca mais entrará em ti nem incircunciso nem imundo.' },
      { v: 2, en: 'Shake yourself from the dust! Arise, sit up, Jerusalem! Release yourself from the bonds of your neck, captive daughter of Zion!', pt: 'Sacode-te do pó; levanta-te, e assenta-te, ó Jerusalém; solta-te das ataduras de teu pescoço, ó cativa filha de Sião.' },
      { v: 3, en: 'For Yahweh says, “You were sold for nothing; and you will be redeemed without money.”', pt: 'Porque assim diz o Senhor: Por nada fostes vendidos; e sem dinheiro sereis resgatados.' },
      { v: 4, en: 'For thus says the Lord Yahweh: “My people went down at the first into Egypt to live there: and the Assyrian has oppressed them without cause.', pt: 'Pois assim diz o Senhor Deus: O meu povo desceu no princípio ao Egito, para peregrinar lá, e a Assíria sem razão o oprimiu.' },
      { v: 5, en: '“Now therefore, what do I do here,” says Yahweh, “seeing that my people are taken away for nothing? Those who rule over them mock,” says Yahweh, “and my name is blasphemed continually all day long.', pt: 'E agora, que acho eu aqui? diz o Senhor, pois que o meu povo foi tomado sem nenhuma razão, os seus dominadores dão uivos sobre ele, diz o Senhor; e o meu nome é blasfemado incessantemente o dia todo!' },
      { v: 6, en: 'Therefore my people shall know my name. Therefore they shall know in that day that I am he who speaks. Behold, it is I.”', pt: 'Portanto o meu povo saberá o meu nome; portanto saberá naquele dia que sou eu o que falo; eis-me aqui.' },
      { v: 7, en: 'How beautiful on the mountains are the feet of him who brings good news, who publishes peace, who brings good news, who proclaims salvation, who says to Zion, “Your God reigns!”', pt: 'Quão formosos sobre os montes são os pés do que anuncia as boas-novas, que proclama a paz, que anuncia coisas boas, que proclama a salvação, que diz a Sião: O teu Deus reina!' },
      { v: 8, en: 'Your watchmen lift up their voice, together they sing; for they shall see eye to eye, when Yahweh returns to Zion.', pt: 'Eis a voz dos teus atalaias! eles levantam a voz, juntamente exultam; porque de perto contemplam a volta do Senhor a Sião.' },
      { v: 9, en: 'Break out into joy, sing together, you waste places of Jerusalem; for Yahweh has comforted his people. He has redeemed Jerusalem.', pt: 'Clamai cantando, exultai juntamente, desertos de Jerusalém; porque o Senhor consolou o seu povo, remiu a Jerusalém.' },
      { v: 10, en: 'Yahweh has made bare his holy arm in the eyes of all the nations; and all the ends of the earth have seen the salvation of our God.', pt: 'O Senhor desnudou o seu santo braço à vista de todas as nações; e todos os confins da terra verão a salvação do nosso Deus.' },
      { v: 11, en: 'Depart, depart, go out from there; touch no unclean thing! Go out from among her! Cleanse yourselves, you who carry Yahweh’s vessels.', pt: 'Retirai-vos, retirai-vos, saí daí, não toqueis coisa imunda; saí do meio dela, purificai-vos, os que levais os vasos do Senhor.' },
      { v: 12, en: 'For you shall not go out in haste, neither shall you go by flight: for Yahweh will go before you; and the God of Israel will be your rear guard.', pt: 'Pois não saireis apressadamente, nem ireis em fuga; porque o Senhor irá diante de vós, e o Deus de Israel será a vossa retaguarda.' },
      { v: 13, en: 'Behold, my servant will deal wisely. He will be exalted and lifted up, and will be very high.', pt: 'Eis que o meu servo procederá com prudência; será exaltado, e elevado, e mui sublime.' },
      { v: 14, en: 'Just as many were astonished at you (his appearance was marred more than any man, and his form more than the sons of men),', pt: 'Como pasmaram muitos à vista dele (pois o seu aspecto estava tão desfigurado que não era o de um homem, e a sua figura não era a dos filhos dos homens),' },
      { v: 15, en: 'so he will cleanse many nations. Kings will shut their mouths at him: for they will see that which had not been told them; and they will understand that which they had not heard.', pt: 'assim ele espantará muitas nações; por causa dele reis taparão a boca; pois verão aquilo que não se lhes havia anunciado, e entenderão aquilo que não tinham ouvido.' },
    ],
    53: [
      { v: 1, en: 'Who has believed our message? To whom has the arm of Yahweh been revealed?', pt: 'Quem deu crédito à nossa pregação? e a quem se manifestou o braço do Senhor?' },
      { v: 2, en: 'For he grew up before him as a tender plant, and as a root out of dry ground. He has no good looks or majesty. When we see him, there is no beauty that we should desire him.', pt: 'Pois foi crescendo como renovo perante ele, e como raiz que sai duma terra seca; não tinha formosura nem beleza; e quando olhávamos para ele, nenhuma beleza víamos, para que o desejássemos.' },
      { v: 3, en: 'He was despised, and rejected by men; a man of suffering, and acquainted with disease. He was despised as one from whom men hide their face; and we didn’t respect him.', pt: 'Era desprezado, e rejeitado dos homens; homem de dores, e experimentado nos sofrimentos; e, como um de quem os homens escondiam o rosto, era desprezado, e não fizemos dele caso algum.' },
      { v: 4, en: 'Surely he has borne our sickness, and carried our suffering; yet we considered him plagued, struck by God, and afflicted.', pt: 'Verdadeiramente ele tomou sobre si as nossas enfermidades, e carregou com as nossas dores; e nós o reputávamos por aflito, ferido de Deus, e oprimido.' },
      { v: 5, en: 'But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed.', pt: 'Mas ele foi ferido por causa das nossas transgressões, e esmagado por causa das nossas iniqüidades; o castigo que nos traz a paz estava sobre ele, e pelas suas pisaduras fomos sarados.' },
      { v: 6, en: 'All we like sheep have gone astray. Everyone has turned to his own way; and Yahweh has laid on him the iniquity of us all.', pt: 'Todos nós andávamos desgarrados como ovelhas, cada um se desviava pelo seu caminho; mas o Senhor fez cair sobre ele a iniqüidade de todos nós.' },
      { v: 7, en: 'He was oppressed, yet when he was afflicted he didn’t open his mouth. As a lamb that is led to the slaughter, and as a sheep that before its shearers is silent, so he didn’t open his mouth.', pt: 'Ele foi oprimido e afligido, mas não abriu a boca; como um cordeiro que é levado ao matadouro, e como a ovelha que é muda perante os seus tosquiadores, assim ele não abriu a boca.' },
      { v: 8, en: 'He was taken away by oppression and judgment; and as for his generation, who considered that he was cut off out of the land of the living and stricken for the disobedience of my people?', pt: 'Pela opressão e pelo juízo foi arrebatado; e quem dentre os da sua geração considerou que ele fora cortado da terra dos viventes, ferido por causa da transgressão do meu povo?' },
      { v: 9, en: 'They made his grave with the wicked, and with a rich man in his death; although he had done no violence, nor was any deceit in his mouth.', pt: 'E deram-lhe a sepultura com os ímpios, e com o rico na sua morte, embora nunca tivesse cometido injustiça, nem houvesse engano na sua boca.' },
      { v: 10, en: 'Yet it pleased Yahweh to bruise him. He has caused him to suffer. When you make his soul an offering for sin, he will see his offspring. He will prolong his days, and Yahweh’s pleasure will prosper in his hand.', pt: 'Todavia, foi da vontade do Senhor esmagá-lo, fazendo-o enfermar; quando ele se puser como oferta pelo pecado, verá a sua posteridade, prolongará os seus dias, e a vontade do Senhor prosperará nas suas mãos.' },
      { v: 11, en: 'After the suffering of his soul, he will see the light and be satisfied. My righteous servant will justify many by the knowledge of himself; and he will bear their iniquities.', pt: 'Ele verá o fruto do trabalho da sua alma, e ficará satisfeito; com o seu conhecimento o meu servo justo justificará a muitos, e as iniqüidades deles levará sobre si.' },
      { v: 12, en: 'Therefore will I give him a portion with the great, and he will divide the plunder with the strong; because he poured out his soul to death, and was counted with the transgressors; yet he bore the sin of many, and made intercession for the transgressors.', pt: 'Pelo que lhe darei o seu quinhão com os grandes, e com os poderosos repartirá ele o despojo; porquanto derramou a sua alma até a morte, e foi contado com os transgressores; mas ele levou sobre si o pecado de muitos, e pelos transgressores intercedeu.' },
    ],
    54: [
      { v: 1, en: '“Sing, barren, you who didn’t give birth; break out into singing, and cry aloud, you who did not travail with child: for more are the children of the desolate than the children of the married wife,” says Yahweh.', pt: 'Canta, alegremente, ó estéril, que não deste à luz; exulta de prazer com alegre canto, e exclama, tu que não tiveste dores de parto; porque mais são os filhos da desolada, do que os filhos da casada, diz o Senhor.' },
      { v: 2, en: '“Enlarge the place of your tent, and let them stretch out the curtains of your habitations; don’t spare: lengthen your cords, and strengthen your stakes.', pt: 'Amplia o lugar da tua tenda, e estendam-se as cortinas das tuas habitações; não o impeças; alonga as tuas cordas, e firma bem as tuas estacas.' },
      { v: 3, en: 'For you will spread out on the right hand and on the left; and your offspring will possess the nations, and settle in desolate cities.', pt: 'Porque trasbordarás para a direita e para a esquerda; e a tua posteridade possuirá as nações e fará que sejam habitadas as cidades assoladas.' },
      { v: 4, en: '“Don’t be afraid; for you will not be ashamed. Don’t be confounded; for you will not be disappointed. For you will forget the shame of your youth; and the reproach of your widowhood you shall remember no more.', pt: 'Não temas, porque não serás envergonhada; e não te envergonhes, porque não sofrerás afrontas; antes te esquecerás da vergonha da tua mocidade, e não te lembrarás mais do opróbrio da tua viuvez.' },
      { v: 5, en: 'For your Maker is your husband; Yahweh of Armies is his name. The Holy One of Israel is your Redeemer. He will be called the God of the whole earth.', pt: 'Pois o teu Criador é o teu marido; o Senhor dos exércitos é o seu nome; e o Santo de Israel é o teu Redentor, que é chamado o Deus de toda a terra.' },
      { v: 6, en: 'For Yahweh has called you as a wife forsaken and grieved in spirit, even a wife of youth, when she is cast off,” says your God.', pt: 'Porque o Senhor te chamou como a mulher desamparada e triste de espírito; como a mulher da mocidade, que fora repudiada, diz o teu Deus:' },
      { v: 7, en: '“For a small moment I have forsaken you; but with great mercies will I gather you.', pt: 'Por um breve momento te deixei, mas com grande compaixão te recolherei;' },
      { v: 8, en: 'In overflowing wrath I hid my face from you for a moment; but with everlasting loving kindness I will have mercy on you,” says Yahweh your Redeemer.', pt: 'num ímpeto de indignação escondi de ti por um momento o meu rosto; mas com benignidade eterna me compadecerei de ti, diz o Senhor, o teu Redentor.' },
      { v: 9, en: '“For this is like the waters of Noah to me; for as I have sworn that the waters of Noah will no more go over the earth, so I have sworn that I will not be angry with you, nor rebuke you.', pt: 'Porque isso será para mim como as águas de Noé; como jurei que as águas de Noé não inundariam mais a terra, assim também jurei que não me irarei mais contra ti, nem te repreenderei.' },
      { v: 10, en: 'For the mountains may depart, and the hills be removed; but my loving kindness will not depart from you, and my covenant of peace will not be removed,” says Yahweh who has mercy on you.', pt: 'Pois as montanhas se retirarão, e os outeiros serão removidos; porém a minha benignidade não se apartará de ti, nem será removido ao pacto da minha paz, diz o Senhor, que se compadece de ti.' },
      { v: 11, en: '“You afflicted, tossed with storms, and not comforted, behold, I will set your stones in beautiful colors, and lay your foundations with sapphires.', pt: 'e aflita arrojada com a tormenta e desconsolada eis que eu assentarei as tuas pedras com antimônio, e lançarei os teus alicerces com safiras.' },
      { v: 12, en: 'I will make your pinnacles of rubies, your gates of sparkling jewels, and all your walls of precious stones.', pt: 'Farei os teus baluartes de rubis, e as tuas portas de carbúnculos, e toda a tua muralha de pedras preciosas.' },
      { v: 13, en: 'All your children will be taught by Yahweh; and your children’s peace will be great.', pt: 'E todos os teus filhos serão ensinados do Senhor; e a paz de teus filhos será abundante.' },
      { v: 14, en: 'In righteousness you will be established. You will be far from oppression, for you will not be afraid; and far from terror, for it shall not come near you.', pt: 'Com justiça serás estabelecida; estarás longe da opressão, porque já não temerás; e também do terror, porque a ti não chegará.' },
      { v: 15, en: 'Behold, they may gather together, but not by me. Whoever gathers together against you will fall because of you.', pt: 'Eis que embora se levantem contendas, isso não será por mim; todos os que contenderem contigo, por causa de ti cairão.' },
      { v: 16, en: '“Behold, I have created the blacksmith who fans the coals into flame, and forges a weapon for his work; and I have created the destroyer to destroy.', pt: 'Eis que eu criei o ferreiro, que assopra o fogo de brasas, e que produz a ferramenta para a sua obra; também criei o assolador, para destruir.' },
      { v: 17, en: 'No weapon that is formed against you will prevail; and you will condemn every tongue that rises against you in judgment. This is the heritage of Yahweh’s servants, and their righteousness is of me,” says Yahweh.', pt: 'Não prosperará nenhuma arma forjada contra ti; e toda língua que se levantar contra ti em juízo, tu a condenarás; esta é a herança dos servos do Senhor, e a sua justificação que de mim procede, diz o Senhor.' },
    ],
    55: [
      { v: 1, en: '“Hey! Come, everyone who thirsts, to the waters! Come, he who has no money, buy, and eat! Yes, come, buy wine and milk without money and without price.', pt: 'ç vós, todos os que tendes sede, vinde às águas, e os que não tendes dinheiro, vinde, comprai, e comei; sim, vinde e comprai, sem dinheiro e sem preço, vinho e leite.' },
      { v: 2, en: 'Why do you spend money for that which is not bread, and your labor for that which doesn’t satisfy? Listen diligently to me, and eat that which is good, and let your soul delight itself in richness.', pt: 'Por que gastais o dinheiro naquilo que não é pão! e o produto do vosso trabalho naquilo que não pode satisfazer? ouvi-me atentamente, e comei o que é bom, e deleitai-vos com a gordura.' },
      { v: 3, en: 'Turn your ear, and come to me. Hear, and your soul will live: and I will make an everlasting covenant with you, even the sure mercies of David.', pt: 'Inclinai os vossos ouvidos, e vinde a mim; ouvi, e a vossa alma viverá; porque convosco farei um pacto perpétuo, dando-vos as firmes beneficências prometidas a Davi.' },
      { v: 4, en: 'Behold, I have given him for a witness to the peoples, a leader and commander to the peoples.', pt: 'Eis que eu o dei como testemunha aos povos, como príncipe e governador dos povos.' },
      { v: 5, en: 'Behold, you shall call a nation that you don’t know; and a nation that didn’t know you shall run to you, because of Yahweh your God, and for the Holy One of Israel; for he has glorified you.”', pt: 'Eis que chamarás a uma nação que não conheces, e uma nação que nunca te conheceu a ti correrá, por amor do Senhor teu Deus, e do Santo de Israel; porque ele te glorificou.' },
      { v: 6, en: 'Seek Yahweh while he may be found. Call on him while he is near.', pt: 'Buscai ao Senhor enquanto se pode achar, invocai-o enquanto está perto.' },
      { v: 7, en: 'Let the wicked forsake his way, and the unrighteous man his thoughts. Let him return to Yahweh, and he will have mercy on him; and to our God, for he will freely pardon.', pt: 'Deixe o ímpio o seu caminho, e o homem maligno os seus pensamentos; volte-se ao Senhor, que se compadecerá dele; e para o nosso Deus, porque é generoso em perdoar.' },
      { v: 8, en: '“For my thoughts are not your thoughts, and your ways are not my ways,” says Yahweh.', pt: 'Porque os meus pensamentos não são os vossos pensamentos, nem os vossos caminhos os meus caminhos, diz o Senhor.' },
      { v: 9, en: '“For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.', pt: 'Porque, assim como o céu é mais alto do que a terra, assim são os meus caminhos mais altos do que os vossos caminhos, e os meus pensamentos mais altos do que os vossos pensamentos.' },
      { v: 10, en: 'For as the rain comes down and the snow from the sky, and doesn’t return there, but waters the earth, and makes it grow and bud, and gives seed to the sower and bread to the eater;', pt: 'Porque, assim como a chuva e a neve descem dos céus e para lá não tornam, mas regam a terra, e a fazem produzir e brotar, para que dê semente ao semeador, e pão ao que come,' },
      { v: 11, en: 'so is my word that goes out of my mouth: it will not return to me void, but it will accomplish that which I please, and it will prosper in the thing I sent it to do.', pt: 'assim será a palavra que sair da minha boca: ela não voltará para mim vazia, antes fará o que me apraz, e prosperará naquilo para que a enviei.' },
      { v: 12, en: 'For you shall go out with joy, and be led out with peace. The mountains and the hills will break out before you into singing; and all the trees of the fields will clap their hands.', pt: 'Pois com alegria saireis, e em paz sereis guiados; os montes e os outeiros romperão em cânticos diante de vós, e todas as árvores de campo baterão palmas.' },
      { v: 13, en: 'Instead of the thorn the cypress tree will come up; and instead of the brier the myrtle tree will come up: and it will make a name for Yahweh, for an everlasting sign that will not be cut off.”', pt: 'Em lugar do espinheiro crescerá a faia, e em lugar da sarça crescerá a murta; o que será para o Senhor por nome, por sinal eterno, que nunca se apagará.' },
    ],
    56: [
      { v: 1, en: 'Yahweh says, “Maintain justice, and do what is right; for my salvation is near, and my righteousness will soon be revealed.', pt: 'Assim diz o Senhor: Mantende a retidão, e fazei justiça; porque a minha salvação está prestes a vir, e a minha justiça a manifestar-se.' },
      { v: 2, en: 'Blessed is the man who does this, and the son of man who holds it fast; who keeps the Sabbath without profaning it, and keeps his hand from doing any evil.”', pt: 'Bem-aventurado o homem que fizer isto, e o filho do homem que lançar mão disto: que se abstém de profanar o sábado, e guarda a sua mão de cometer o mal.' },
      { v: 3, en: 'Let no foreigner, who has joined himself to Yahweh, speak, saying, “Yahweh will surely separate me from his people.” Do not let the eunuch say, “Behold, I am a dry tree.”', pt: 'E não fale o estrangeiro, que se houver unido ao Senhor, dizendo: Certamente o Senhor me separará do seu povo; nem tampouco diga o eunuco: Eis que eu sou uma árvore seca.' },
      { v: 4, en: 'For Yahweh says, “To the eunuchs who keep my Sabbaths, and choose the things that please me, and hold fast to my covenant:', pt: 'Pois assim diz o Senhor a respeito dos eunucos que guardam os meus sábados, e escolhem as coisas que me agradam, e abraçam o meu pacto:' },
      { v: 5, en: 'I will give them in my house and within my walls a memorial and a name better than of sons and of daughters. I will give them an everlasting name, that will not be cut off.', pt: 'Dar-lhes-ei na minha casa e dentro dos meus muros um memorial e um nome melhor do que o de filhos e filhas; um nome eterno darei a cada um deles, que nunca se apagará.' },
      { v: 6, en: 'Also the foreigners who join themselves to Yahweh, to serve him, and to love Yahweh’s name, to be his servants, everyone who keeps the Sabbath from profaning it, and holds fast my covenant;', pt: 'E aos estrangeiros, que se unirem ao Senhor, para o servirem, e para amarem o nome do Senhor, sendo deste modo servos seus, todos os que guardarem o sábado, não o profanando, e os que abraçarem o meu pacto,' },
      { v: 7, en: 'I will bring these to my holy mountain, and make them joyful in my house of prayer. Their burnt offerings and their sacrifices will be accepted on my altar; for my house will be called a house of prayer for all peoples.”', pt: 'sim, a esses os levarei ao meu santo monte, e os alegrarei na minha casa de oração; os seus holocaustos e os seus sacrifícios serão aceitos no meu altar; porque a minha casa será chamada casa de oração para todos os povos.' },
      { v: 8, en: 'The Lord Yahweh, who gathers the outcasts of Israel, says, “I will yet gather others to him, besides his own who are gathered.”', pt: 'Assim diz o Senhor Deus, que ajunta os dispersos de Israel: Ainda outros ajuntarei a ele, além dos que já se lhe ajuntaram.' },
      { v: 9, en: 'All you animals of the field, come to devour, all you animals in the forest.', pt: 'Vós, todos os animais do campo, todos os animais do bosque, vinde comer.' },
      { v: 10, en: 'His watchmen are blind. They are all without knowledge. They are all mute dogs. They can’t bark; dreaming, lying down, loving to slumber.', pt: 'Todos os seus atalaias são cegos, nada sabem; todos são cães mudos, não podem ladrar; deitados, sonham e gostam de dormir.' },
      { v: 11, en: 'Yes, the dogs are greedy. They can never have enough. They are shepherds who can’t understand. They have all turned to their own way, each one to his gain, from every quarter.', pt: 'E estes cães são gulosos, nunca se podem fartar; e eles são pastores que nada compreendem; todos eles se tornam para o seu caminho, cada um para a sua ganância, todos sem exceção.' },
      { v: 12, en: '“Come,” say they, “I will get wine, and we will fill ourselves with strong drink; and tomorrow will be as today, great beyond measure.”', pt: 'Vinde, dizem, trarei vinho, e nos encheremos de bebida forte; e o dia de amanhã será como hoje, ou ainda mais festivo.' },
    ],
    57: [
      { v: 1, en: 'The righteous perish, and no one lays it to heart. Merciful men are taken away, and no one considers that the righteous is taken away from the evil.', pt: 'Perece o justo, e não há quem se importe com isso; os homens compassivos são arrebatados, e não há ninguém que entenda. Pois o justo é arrebatado da calamidade,' },
      { v: 2, en: 'He enters into peace. They rest in their beds, each one who walks in his uprightness.', pt: 'entra em paz; descansam nas suas camas todos os que andam na retidão.' },
      { v: 3, en: '“But draw near here, you sons of a sorceress, you offspring of adulterers and prostitutes.', pt: 'Mas chegai-vos aqui, vós os filhos da agoureira, linhagem do adúltero e da prostituta.' },
      { v: 4, en: 'Whom do you mock? Against whom do you make a wide mouth, and stick out your tongue? Aren’t you children of disobedience, and offspring of falsehood,', pt: 'De quem fazeis escárnio? Contra quem escancarais a boca, e deitais para fora a língua? Porventura não sois vós filhos da transgressão, estirpe da falsidade,' },
      { v: 5, en: 'you who inflame yourselves among the oaks, under every green tree; who kill the children in the valleys, under the clefts of the rocks?', pt: 'que vos inflamais junto aos terebintos, debaixo de toda árvore verde, e sacrificais os filhos nos vales, debaixo das fendas dos penhascos?' },
      { v: 6, en: 'Among the smooth stones of the valley is your portion; they, they are your lot. You have even poured a drink offering to them. You have offered an offering. Shall I be appeased for these things?', pt: 'Por entre as pedras lisas do vale está o teu quinhão; estas, estas são a tua sorte; também a estas derramaste a tua libação e lhes ofereceste uma oblação. Contentar-me-ia com estas coisas?' },
      { v: 7, en: 'On a high and lofty mountain you have set your bed. You also went up there to offer sacrifice.', pt: 'sobre um monte alto e levantado puseste a tua cama; e lá subiste para oferecer sacrifícios.' },
      { v: 8, en: 'You have set up your memorial behind the doors and the posts; for you have exposed yourself to someone besides me, and have gone up; you have enlarged your bed, and made you a covenant with them. You loved what you saw on their bed.', pt: 'Detrás das portas e dos umbrais colocaste o teu memorial; pois te descobriste a outro que não a mim, e subiste, e alargaste a tua cama; e fizeste para ti um pacto com eles; amaste a sua cama, onde quer que a viste.' },
      { v: 9, en: 'You went to the king with oil, and increased your perfumes, and sent your ambassadors far off, and degraded yourself even to Sheol.', pt: 'E foste ao rei com óleo, e multiplicaste os teus perfumes, e enviaste os teus embaixadores para longe, e te abateste até o Seol.' },
      { v: 10, en: 'You were wearied with the length of your ways; yet you didn’t say, ‘It is in vain.’ You found a reviving of your strength; therefore you weren’t faint.', pt: 'Na tua comprida viagem te cansaste; contudo não disseste: Não há esperança; achaste com que renovar as tuas forças; por isso não enfraqueceste.' },
      { v: 11, en: '“Whom have you dreaded and feared, so that you lie, and have not remembered me, nor laid it to your heart? Haven’t I held my peace for a long time, and you don’t fear me?', pt: 'Mas de quem tiveste receio ou medo, para que mentisses, e não te lembrasses de mim, nem te importasses? Não é porventura porque eu me calei, e isso há muito tempo, e não me temes?' },
      { v: 12, en: 'I will declare your righteousness; and as for your works, they will not benefit you.', pt: 'Eu publicarei essa justiça tua; e quanto às tuas obras, elas não te aproveitarão.' },
      { v: 13, en: 'When you cry, let those whom you have gathered deliver you; but the wind will take them. a breath will carry them all away: but he who takes refuge in me will possess the land, and will inherit my holy mountain.”', pt: 'Quando clamares, livrem-te os ídolos que ajuntaste; mas o vento a todos levará, e um assopro os arrebatará; mas o que confia em mim possuirá a terra, e herdarão o meu santo monte.' },
      { v: 14, en: 'He will say, “Build up, build up, prepare the way! Remove the stumbling-block out of the way of my people.”', pt: 'E dir-se-á: Aplanai, aplanai, preparai e caminho, tirai os tropeços do caminho do meu povo.' },
      { v: 15, en: 'For thus says the high and lofty One who inhabits eternity, whose name is Holy: “I dwell in the high and holy place, with him also who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.', pt: 'Porque assim diz o Alto e o Excelso, que habita na eternidade e cujo nome é santo: Num alto e santo lugar habito, e também com o contrito e humilde de espírito, para vivificar o espírito dos humildes, e para vivificar o coração dos contritos.' },
      { v: 16, en: 'For I will not contend forever, neither will I be always angry; for the spirit would faint before me, and the souls whom I have made.', pt: 'Pois eu não contenderei para sempre, nem continuamente ficarei irado; porque de mim procede o espírito, bem como o fôlego da vida que eu criei.' },
      { v: 17, en: 'I was angry because of the iniquity of his covetousness, and struck him; I hid myself and was angry; and he went on backsliding in the way of his heart.', pt: 'Por causa da iniqüidade da sua avareza me indignei e o feri; escondi-me, e indignei-me; mas, rebelando-se, ele seguiu o caminho do seu coração.' },
      { v: 18, en: 'I have seen his ways, and will heal him: I will lead him also, and restore comforts to him and to his mourners.', pt: 'Tenho visto os seus caminhos, mas eu o sararei; também o guiarei, e tornarei a dar-lhe consolação, a ele e aos que o pranteiam.' },
      { v: 19, en: 'I create the fruit of the lips: Peace, peace, to him who is far off and to him who is near,” says Yahweh; “and I will heal them.”', pt: 'Eu crio o fruto dos lábios; paz, paz, para o que está longe, e para o que está perto diz o Senhor; e eu o sararei.' },
      { v: 20, en: 'But the wicked are like the troubled sea; for it can’t rest, and its waters cast up mire and mud.', pt: 'Mas os ímpios são como o mar agitado; pois não pode estar quieto, e as suas águas lançam de si lama e lodo.' },
      { v: 21, en: '“There is no peace”, says my God, “for the wicked.”', pt: 'Não há paz para os ímpios, diz o meu Deus.' },
    ],
    58: [
      { v: 1, en: '“Cry aloud, don’t spare. Lift up your voice like a trumpet. Declare to my people their disobedience, and to the house of Jacob their sins.', pt: 'Clama em alta voz, não te detenhas, levanta a tua voz como a trombeta e anuncia ao meu povo a sua transgressão, e à casa de Jacó os seus pecados.' },
      { v: 2, en: 'Yet they seek me daily, and delight to know my ways. As a nation that did righteousness, and didn’t forsake the ordinance of their God, they ask of me righteous judgments. They delight to draw near to God.', pt: 'Todavia me procuram cada dia, tomam prazer em saber os meus caminhos; como se fossem um povo que praticasse a justiça e não tivesse abandonado a ordenança do seu Deus, pedem-me juízos retos, têm prazer em se chegar a Deus!,' },
      { v: 3, en: '‘Why have we fasted,’ say they, ‘and you don’t see? Why have we afflicted our soul, and you don’t notice?’ “Behold, in the day of your fast you find pleasure, and oppress all your laborers.', pt: 'Por que temos nós jejuado, dizem eles, e tu não atentas para isso? por que temos afligido as nossas almas, e tu não o sabes? Eis que no dia em que jejuais, prosseguis nas vossas empresas, e exigis que se façam todos os vossos trabalhos.' },
      { v: 4, en: 'Behold, you fast for strife and contention, and to strike with the fist of wickedness. You don’t fast today so as to make your voice to be heard on high.', pt: 'Eis que para contendas e rixas jejuais, e para ferirdes com punho iníquo! Jejuando vós assim como hoje, a vossa voz não se fara ouvir no alto.' },
      { v: 5, en: 'Is this the fast that I have chosen? A day for a man to humble his soul? Is it to bow down his head like a reed, and to spread sackcloth and ashes under himself? Will you call this a fast, and an acceptable day to Yahweh?', pt: 'Seria esse o jejum que eu escolhi? o dia em que o homem aflija a sua alma? Consiste porventura, em inclinar o homem a cabeça como junco e em estender debaixo de si saco e cinza? chamarias tu a isso jejum e dia aceitável ao Senhor?' },
      { v: 6, en: '“Isn’t this the fast that I have chosen: to release the bonds of wickedness, to undo the straps of the yoke, to let the oppressed go free, and that you break every yoke?', pt: 'Acaso não é este o jejum que escolhi? que soltes as ligaduras da impiedade, que desfaças as ataduras do jugo? e que deixes ir livres os oprimidos, e despedaces todo jugo?' },
      { v: 7, en: 'Isn’t it to distribute your bread to the hungry, and that you bring the poor who are cast out to your house? When you see the naked, that you cover him; and that you not hide yourself from your own flesh?', pt: 'Porventura não é também que repartas o teu pão com o faminto, e recolhas em casa os pobres desamparados? que vendo o nu, o cubras, e não te escondas da tua carne?' },
      { v: 8, en: 'Then your light will break out as the morning, and your healing will appear quickly; then your righteousness shall go before you; and Yahweh’s glory will be your rear guard.', pt: 'Então romperá a tua luz como a alva, e a tua cura apressadamente brotará. e a tua justiça irá adiante de ti; e a glória do Senhor será a tua retaguarda.' },
      { v: 9, en: 'Then you will call, and Yahweh will answer; you will cry for help, and he will say, ‘Here I am.’ “If you take away from among you the yoke, finger pointing, and speaking wickedly;', pt: 'Então clamarás, e o Senhor te responderá; gritarás, e ele dirá: Eis-me aqui. Se tirares do meio de ti o jugo, o estender do dedo, e o falar iniquamente;' },
      { v: 10, en: 'and if you pour out your soul to the hungry, and satisfy the afflicted soul: then your light will rise in darkness, and your obscurity will be as the noonday;', pt: 'e se abrires a tua alma ao faminto, e fartares o aflito; então a tua luz nascerá nas trevas, e a tua escuridão será como o meio dia.' },
      { v: 11, en: 'and Yahweh will guide you continually, and satisfy your soul in dry places, and make your bones strong; and you shall be like a watered garden, and like a spring of water, whose waters don’t fail.', pt: 'O Senhor te guiará continuamente, e te fartará até em lugares áridos, e fortificará os teus ossos; serás como um jardim regado, e como um manancial, cujas águas nunca falham.' },
      { v: 12, en: 'Those who shall be of you shall build the old waste places; you shall raise up the foundations of many generations; and you shall be called Repairer of the Breach, Restorer of Paths with Dwellings.', pt: 'E os que de ti procederem edificarão as ruínas antigas; e tu levantarás os fundamentos de muitas gerações; e serás chamado reparador da brecha, e restaurador de veredas para morar.' },
      { v: 13, en: '“If you turn away your foot from the Sabbath, from doing your pleasure on my holy day; and call the Sabbath a delight, and the holy of Yahweh honorable; and shall honor it, not doing your own ways, nor finding your own pleasure, nor speaking your own words:', pt: 'Se desviares do sábado o teu pé, e deixares de prosseguir nas tuas empresas no meu santo dia; se ao sábado chamares deleitoso, ao santo dia do Senhor, digno de honra; se o honrares, não seguindo os teus caminhos, nem te ocupando nas tuas empresas, nem falando palavras vãs;' },
      { v: 14, en: 'then you shall delight yourself in Yahweh; and I will make you to ride on the high places of the earth; and I will feed you with the heritage of Jacob your father:” for Yahweh’s mouth has spoken it.', pt: 'então te deleitarás no Senhor, e eu te farei cavalgar sobre as alturas da terra, e te sustentarei com a herança de teu pai Jacó; porque a boca do Senhor o disse.' },
    ],
    59: [
      { v: 1, en: 'Behold, Yahweh’s hand is not shortened, that it can’t save; nor his ear dull, that it can’t hear.', pt: 'Eis que a mão do Senhor não está encolhida, para que não possa salvar; nem surdo o seu ouvido, para que não possa ouvir;' },
      { v: 2, en: 'But your iniquities have separated you and your God, and your sins have hidden his face from you, so that he will not hear.', pt: 'mas as vossas iniqüidades fazem separação entre vós e o vosso Deus; e os vossos pecados esconderam o seu rosto de vós, de modo que não vos ouça.' },
      { v: 3, en: 'For your hands are defiled with blood, and your fingers with iniquity. Your lips have spoken lies. Your tongue mutters wickedness.', pt: 'Porque as vossas mãos estão contaminadas de sangue, e os vossos dedos de iniqüidade; os vossos lábios falam a mentira, a vossa língua pronuncia perversidade.' },
      { v: 4, en: 'No one sues in righteousness, and no one pleads in truth. They trust in vanity, and speak lies. They conceive mischief, and give birth to iniquity.', pt: 'Ninguém há que invoque a justiça com retidão, nem há quem pleiteie com verdade; confiam na vaidade, e falam mentiras; concebem o mal, e dão à luz a iniqüidade.' },
      { v: 5, en: 'They hatch adders’ eggs, and weave the spider’s web. He who eats of their eggs dies; and that which is crushed breaks out into a viper.', pt: 'Chocam ovos de basiliscos, e tecem teias de aranha; o que comer dos ovos deles, morrerá; e do ovo que for pisado sairá uma víbora.' },
      { v: 6, en: 'Their webs won’t become garments. They won’t cover themselves with their works. Their works are works of iniquity, and acts of violence are in their hands.', pt: 'As suas teias não prestam para vestidos; nem se poderão cobrir com o que fazem; as suas obras são obras de iniqüidade, e atos de violência há nas suas mãos.' },
      { v: 7, en: 'Their feet run to evil, and they hurry to shed innocent blood. Their thoughts are thoughts of iniquity. desolation and destruction are in their paths.', pt: 'Os seus pés correm para o mal, e se apressam para derramarem o sangue inocente; os seus pensamentos são pensamentos de iniqüidade; a desolação e a destruiçao acham-se nas suas estradas.' },
      { v: 8, en: 'They don’t know the way of peace; and there is no justice in their ways. They have made crooked paths for themselves; whoever goes in them doesn’t know peace.', pt: 'O caminho da paz eles não o conhecem, nem há justiça nos seus passos; fizeram para si veredas tortas; todo aquele que anda por elas não tem conhecimento da paz.' },
      { v: 9, en: 'Therefore is justice far from us, and righteousness doesn’t overtake us. We look for light, but see darkness; for brightness, but we walk in obscurity.', pt: 'Pelo que a justiça está longe de nós, e a retidão não nos alcança; esperamos pela luz, e eis que só há trevas; pelo resplendor, mas andamos em escuridão.' },
      { v: 10, en: 'We grope for the wall like the blind. Yes, we grope as those who have no eyes. We stumble at noon as if it were twilight. Among those who are strong, we are like dead men.', pt: 'Apalpamos as paredes como cegos; sim, como os que não têm olhos andamos apalpando; tropeçamos ao meio-dia como no crepúsculo, e entre os vivos somos como mortos.' },
      { v: 11, en: 'We all roar like bears, and moan bitterly like doves. We look for justice, but there is none; for salvation, but it is far off from us.', pt: 'Todos nós bramamos como ursos, e andamos gemendo como pombas; esperamos a justiça, e ela não aparece; a salvação, e ela está longe de nós.' },
      { v: 12, en: 'For our transgressions are multiplied before you, and our sins testify against us; for our transgressions are with us, and as for our iniquities, we know them:', pt: 'Porque as nossas transgressões se multiplicaram perante ti, e os nossos pecados testificam contra nós; pois as nossas transgressões estão conosco, e conhecemos as nossas iniqüidades.' },
      { v: 13, en: 'transgressing and denying Yahweh, and turning away from following our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.', pt: 'transgredimos, e negamos o Senhor, e nos desviamos de seguir após o nosso Deus; falamos a opressão e a rebelião, concebemos e proferimos do coração palavras de falsidade.' },
      { v: 14, en: 'Justice is turned away backward, and righteousness stands far away; for truth has fallen in the street, and uprightness can’t enter.', pt: 'Pelo que o direito se tornou atrás, e a justiça se pôs longe; porque a verdade anda tropeçando pelas ruas, e a eqüidade não pode entrar.' },
      { v: 15, en: 'Yes, truth is lacking; and he who departs from evil makes himself a prey. Yahweh saw it, and it displeased him that there was no justice.', pt: 'Sim, a verdade desfalece; e quem se desvia do mal arrisca-se a ser despojado; e o Senhor o viu, e desagradou-lhe o não haver justiça.' },
      { v: 16, en: 'He saw that there was no man, and wondered that there was no intercessor. Therefore his own arm brought salvation to him; and his righteousness sustained him.', pt: 'E viu que ninguém havia, e maravilhou-se de que não houvesse um intercessor; pelo que o seu próprio braço lhe trouxe a salvação, e a sua própria justiça o susteve;' },
      { v: 17, en: 'He put on righteousness as a breastplate, and a helmet of salvation on his head. He put on garments of vengeance for clothing, and was clad with zeal as a mantle.', pt: 'vestiu-se de justiça, como de uma couraça, e pôs na cabeça o capacete da salvação; e por vestidura pôs sobre si vestes de vingança, e cobriu-se de zelo, como de um manto.' },
      { v: 18, en: 'According to their deeds, he will repay as appropriate, wrath to his adversaries, recompense to his enemies; he will repay the islands their due.', pt: 'Conforme forem as obras deles, assim será a sua retribuição, furor aos seus adversários, e recompensa aos seus inimigos; às ilhas dará ele a sua recompensa.' },
      { v: 19, en: 'So shall they fear Yahweh’s name from the west, and his glory from the rising of the sun; for he will come as a rushing stream, which Yahweh’s breath drives.', pt: 'Então temerão o nome do Senhor desde o poente, e a sua glória desde o nascente do sol; porque ele virá tal uma corrente impetuosa, que o assopro do Senhor impele.' },
      { v: 20, en: '“A Redeemer will come to Zion, and to those who turn from disobedience in Jacob,” says Yahweh.', pt: 'E virá um Redentor a Sião e aos que em Jacó se desviarem da transgressão, diz o Senhor.' },
      { v: 21, en: '“As for me, this is my covenant with them,” says Yahweh. “My Spirit who is on you, and my words which I have put in your mouth, shall not depart out of your mouth, nor out of the mouth of your offspring, nor out of the mouth of your offspring’s offspring,” says Yahweh, “from henceforth and forever.”', pt: 'Quanto a mim, este é o meu pacto com eles, diz o Senhor: o meu Espírito, que está sobre ti, e as minhas palavras, que pus na tua boca, não se desviarão da tua boca, nem da boca dos teus filhos, nem da boca dos filhos dos teus filhos, diz o Senhor, desde agora e para todo o sempre.' },
    ],
    60: [
      { v: 1, en: '“Arise, shine; for your light has come, and Yahweh’s glory has risen on you.', pt: 'Levanta-te, resplandece, porque é chegada a tua luz, e é nascida sobre ti a glória do Senhor.' },
      { v: 2, en: 'For, behold, darkness will cover the earth, and thick darkness the peoples; but Yahweh will arise on you, and his glory shall be seen on you.', pt: 'Pois eis que as trevas cobrirão a terra, e a escuridão os povos; mas sobre ti o Senhor virá surgindo, e a sua glória se verá sobre ti.' },
      { v: 3, en: 'Nations will come to your light, and kings to the brightness of your rising.', pt: 'E nações caminharão para a tua luz, e reis para o resplendor da tua aurora.' },
      { v: 4, en: '“Lift up your eyes all around, and see: they all gather themselves together. They come to you. Your sons will come from far away, and your daughters will be carried in arms.', pt: 'Levanta em redor os teus olhos, e vê; todos estes se ajuntam, e vêm ter contigo; teus filhos vêm de longe, e tuas filhas se criarão a teu lado.' },
      { v: 5, en: 'Then you shall see and be radiant, and your heart will thrill and be enlarged; because the abundance of the sea will be turned to you. The wealth of the nations will come to you.', pt: 'Então o verás, e estarás radiante, e o teu coração estremecerá e se alegrará; porque a abundância do mar se tornará a ti, e as riquezas das nações a ti virão.' },
      { v: 6, en: 'A multitude of camels will cover you, the dromedaries of Midian and Ephah. All from Sheba will come. They will bring gold and frankincense, and will proclaim the praises of Yahweh.', pt: 'A multidão de camelos te cobrirá, os dromedários de Midiã e Efá; todos os de Sabá, virão; trarão ouro e incenso, e publicarão os louvores do Senhor.' },
      { v: 7, en: 'All the flocks of Kedar will be gathered together to you. The rams of Nebaioth will serve you. They will be accepted as offerings on my altar; and I will beautify my glorious house.', pt: 'Todos os rebanhos de Quedar se congregarão em ti, os carneiros de Nebaoite te servirão; com aceitação subirão ao meu altar, e eu glorificarei a casa da minha glória.' },
      { v: 8, en: '“Who are these who fly as a cloud, and as the doves to their windows?', pt: 'Quem são estes que vêm voando como nuvens e como pombas para as suas janelas?' },
      { v: 9, en: 'Surely the islands will wait for me, and the ships of Tarshish first, to bring your sons from far, their silver and their gold with them, for the name of Yahweh your God, and for the Holy One of Israel, because he has glorified you.', pt: 'Certamente as ilhas me aguardarão, e vêm primeiro os navios de Társis, para trazerem teus filhos de longe, e com eles a sua prata e o seu ouro, para o nome do Senhor teu Deus, e para o Santo de Israel, porquanto ele te glorificou.' },
      { v: 10, en: '“Foreigners will build up your walls, and their kings will serve you: for in my wrath I struck you, but in my favor I have had mercy on you.', pt: 'E estrangeiros edificarão os teus muros, e os seus reis te servirão; porque na minha ira te feri, mas na minha benignidade tive misericórdia de ti.' },
      { v: 11, en: 'Your gates also shall be open continually; they shall not be shut day nor night; that men may bring to you the wealth of the nations, and their kings led captive.', pt: 'As tuas portas estarão abertas de contínuo; nem de dia nem de noite se fecharão; para que te sejam trazidas as riquezas das nações, e conduzidos com elas os seus reis.' },
      { v: 12, en: 'For that nation and kingdom that will not serve you shall perish; yes, those nations shall be utterly wasted.', pt: 'Porque a nação e o reino que não te servirem perecerão; sim, essas nações serão de todo assoladas.' },
      { v: 13, en: '“The glory of Lebanon shall come to you, the cypress tree, the pine, and the box tree together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.', pt: 'A glória do Líbano virá a ti; a faia, o olmeiro, e o buxo conjuntamente, para ornarem o lugar do meu santuário; e farei glorioso o lugar em que assentam os meus pés.' },
      { v: 14, en: 'The sons of those who afflicted you will come bowing to you; and all those who despised you will bow themselves down at the soles of your feet. They will call you Yahweh’s City, The Zion of the Holy One of Israel.', pt: 'Também virão a ti, inclinando-se, os filhos dos que te oprimiram; e prostrar-se-ão junto às plantas dos teus pés todos os que te desprezaram; e chamar-te-ão a cidade do Senhor, a Sião do Santo de Israel.' },
      { v: 15, en: '“Whereas you have been forsaken and hated, so that no one passed through you, I will make you an eternal excellency, a joy of many generations.', pt: 'Ao invés de seres abandonada e odiada como eras, de sorte que ninguém por ti passava, far-te-ei uma excelência perpétua, uma alegria de geração em geração.' },
      { v: 16, en: 'You will also drink the milk of the nations, and will nurse from royal breasts. Then you will know that I, Yahweh, am your Savior, your Redeemer, the Mighty One of Jacob.', pt: 'E mamarás o leite das nações, e te alimentarás ao peito dos reis; assim saberás que eu sou o Senhor, o teu Salvador, e o teu Redentor, o Poderoso de Jacó.' },
      { v: 17, en: 'For brass I will bring gold; for iron I will bring silver; for wood, brass, and for stones, iron. I will also make peace your governor, and righteousness your ruler.', pt: 'Por bronze trarei ouro, por ferro trarei prata, por madeira bronze, e por pedras ferro; farei pacíficos os teus oficiais e justos os teus exatores.' },
      { v: 18, en: 'Violence shall no more be heard in your land, nor desolation or destruction within your borders; but you will call your walls Salvation, and your gates Praise.', pt: 'Não se ouvirá mais de violência na tua terra, de desolação ou destruição nos teus termos; mas aos teus muros chamarás Salvação, e às tuas portas Louvor.' },
      { v: 19, en: 'The sun will be no more your light by day; nor will the brightness of the moon give light to you, but Yahweh will be your everlasting light, and your God will be your glory.', pt: 'Não te servirá mais o sol para luz do dia, nem com o seu resplendor a lua te alumiará; mas o Senhor será a tua luz perpétua, e o teu Deus a tua glória.' },
      { v: 20, en: 'Your sun will not go down any more, nor will your moon withdraw itself; for Yahweh will be your everlasting light, and the days of your mourning will end.', pt: 'Nunca mais se porá o teu sol, nem a tua lua minguará; porque o Senhor será a tua luz perpétua, e acabados serão os dias do teu luto.' },
      { v: 21, en: 'Then your people will all be righteous. They will inherit the land forever, the branch of my planting, the work of my hands, that I may be glorified.', pt: 'E todos os do teu povo serão justos; para sempre herdarão a terra; serão renovos por mim plantados, obra das minhas mãos, para que eu seja glorificado.' },
      { v: 22, en: 'The little one will become a thousand, and the small one a strong nation. I, Yahweh, will do this quickly in its time.”', pt: 'O mais pequeno virá a ser mil, e o mínimo uma nação forte; eu, o Senhor, apressarei isso a seu tempo.' },
    ],
    61: [
      { v: 1, en: 'The Lord Yahweh’s Spirit is on me; because Yahweh has anointed me to preach good news to the humble. He has sent me to bind up the broken hearted, to proclaim liberty to the captives, and release to those who are bound;', pt: 'O Espírito do Senhor Deus está sobre mim, porque o Senhor me ungiu para pregar boas-novas aos mansos; enviou-me a restaurar os contritos de coração, a proclamar liberdade aos cativos, e a abertura de prisão aos presos;' },
      { v: 2, en: 'to proclaim the year of Yahweh’s favor, and the day of vengeance of our God; to comfort all who mourn;', pt: 'a apregoar o ano aceitável do Senhor e o dia da vingança do nosso Deus; a consolar todos os tristes;' },
      { v: 3, en: 'to provide for those who mourn in Zion, to give to them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they may be called trees of righteousness, the planting of Yahweh, that he may be glorified.', pt: 'a ordenar acerca dos que choram em Sião que se lhes dê uma grinalda em vez de cinzas, óleo de gozo em vez de pranto, vestidos de louvor em vez de espírito angustiado; a fim de que se chamem árvores de justiça, plantação do Senhor, para que ele seja glorificado.' },
      { v: 4, en: 'They will rebuild the old ruins. They will raise up the places long devastated. They will repair the ruined cities, that have been devastated for many generations.', pt: 'E eles edificarão as antigas ruínas, levantarão as desolações de outrora, e restaurarão as cidades assoladas, as desolações de muitas gerações.' },
      { v: 5, en: 'Strangers will stand and feed your flocks, and foreigners will work your fields and your vineyards.', pt: 'E haverá estrangeiros, que apascentarão os vossos rebanhos; e estranhos serão os vossos lavradores e os vossos vinheiros.' },
      { v: 6, en: 'But you will be called Yahweh’s priests. Men will call you the servants of our God. You will eat the wealth of the nations, and you will boast in their glory.', pt: 'Mas vós sereis chamados sacerdotes do Senhor, e vos chamarão ministros de nosso Deus; comereis as riquezas das nações, e na sua glória vos gloriareis.' },
      { v: 7, en: 'Instead of your shame you will have double. Instead of dishonor, they will rejoice in their portion. Therefore in their land, they will possess double. Everlasting joy will be to them.', pt: 'Em lugar da vossa vergonha, haveis de ter dupla honra; e em lugar de opróbrio exultareis na vossa porção; por isso na sua terra possuirão o dobro, e terão perpétua alegria.' },
      { v: 8, en: '“For I, Yahweh, love justice. I hate robbery and iniquity. I will give them their reward in truth, and I will make an everlasting covenant with them.', pt: 'Pois eu, o Senhor, amo o juízo, aborreço o roubo e toda injustiça; fielmente lhes darei sua recompensa, e farei com eles um pacto eterno.' },
      { v: 9, en: 'Their offspring will be known among the nations, and their offspring among the peoples. All who see them will acknowledge them, that they are the offspring which Yahweh has blessed.”', pt: 'E a sua posteridade será conhecida entre as nações, e os seus descendentes no meio dos povos; todos quantos os virem os reconhecerão como descendência bendita do Senhor.' },
      { v: 10, en: 'I will greatly rejoice in Yahweh! My soul will be joyful in my God; for he has clothed me with the garments of salvation. He has covered me with the robe of righteousness, as a bridegroom decks himself with a garland, and as a bride adorns herself with her jewels.', pt: 'Regozijar-me-ei muito no Senhor, a minha alma se alegrará no meu Deus, porque me vestiu de vestes de salvação, cobriu-me com o manto de justiça, como noivo que se adorna com uma grinalda, e como noiva que se enfeita com as suas jóias.' },
      { v: 11, en: 'For as the earth produces its bud, and as the garden causes the things that are sown in it to spring up; so the Lord Yahweh will cause righteousness and praise to spring up before all the nations.', pt: 'Porque, como a terra produz os seus renovos, e como o horto faz brotar o que nele se semeia, assim o Senhor Deus fará brotar a justiça e o louvor perante todas as nações.' },
    ],
    62: [
      { v: 1, en: 'For Zion’s sake will I not hold my peace, and for Jerusalem’s sake I will not rest, until her righteousness shines out like the dawn, and her salvation like a burning lamp.', pt: 'Por amor de Sião não me calarei, e por amor de Jerusalém não descansarei, até que saia a sua justiça como um resplendor, e a sua salvação como uma tocha acesa.' },
      { v: 2, en: 'The nations will see your righteousness, and all kings your glory, and you will be called by a new name, which Yahweh‘s mouth will name.', pt: 'E as nações verão a tua justiça, e todos os reis a tua glória; e chamar-te-ão por um nome novo, que a boca do Senhor designará.' },
      { v: 3, en: 'You will also be a crown of beauty in Yahweh‘s hand, and a royal diadem in your God‘s hand.', pt: 'Também serás uma coroa de adorno na mão do Senhor, e um diadema real na mão do teu Deus.' },
      { v: 4, en: 'You will not be called Forsaken any more; nor will your land be called Desolate any more: but you will be called Hephzibah, and your land Beulah; for Yahweh delights in you, and your land will be married.', pt: 'Nunca mais te chamarão: Desamparada, nem a tua terra se denominará Desolada; mas chamar-te-ão Hefzibá, e à tua terra Beulá; porque o Senhor se agrada de ti; e a tua terra se casará.' },
      { v: 5, en: 'For as a young man marries a virgin, so your sons will marry you. As a bridegroom rejoices over his bride, so your God will rejoice over you.', pt: 'Pois como o mancebo se casa com a donzela, assim teus filhos se casarão contigo; e, como o noivo se alegra da noiva, assim se alegrará de ti o teu Deus' },
      { v: 6, en: 'I have set watchmen on your walls, Jerusalem. They will never be silent day nor night. You who call on Yahweh, take no rest,', pt: 'e Jerusalém, sobre os teus muros pus atalaias, que não se calarão nem de dia, nem de noite; ó vós, os que fazeis lembrar ao Senhor, não descanseis,' },
      { v: 7, en: 'and give him no rest, until he establishes, and until he makes Jerusalem a praise in the earth.', pt: 'e não lhe deis a ele descanso até que estabeleça Jerusalém e a ponha por objeto de louvor na terra.' },
      { v: 8, en: 'Yahweh has sworn by his right hand, and by the arm of his strength, “Surely I will no more give your grain to be food for your enemies; and foreigners will not drink your new wine, for which you have labored;', pt: 'Jurou o Senhor pela sua mão direita, e pelo braço da sua força: Nunca mais darei de comer o teu trigo aos teus inimigos, nem os estrangeiros beberão o teu mosto, em que trabalhaste.' },
      { v: 9, en: 'but those who have harvested it will eat it, and praise Yahweh; and those who have gathered it will drink it in the courts of my sanctuary.”', pt: 'Mas os que o ajuntarem o comerão, e louvarão ao Senhor; e os que o colherem o beberão nos átrios do meu santuário.' },
      { v: 10, en: 'Go through, go through the gates! Prepare the way of the people! Build up, build up the highway! Gather out the stones! Lift up a banner for the peoples.', pt: 'Passai, passai pelas portas; preparai o caminho ao povo; aplanai, aplanai a estrada, limpai-a das pedras; arvorai a bandeira aos povos.' },
      { v: 11, en: 'Behold, Yahweh has proclaimed to the end of the earth, “Say to the daughter of Zion, ‘Behold, your salvation comes. Behold, his reward is with him, and his recompense before him.’”', pt: 'Eis que o Senhor proclamou até as extremidades da terra: Dizei à filha de Sião: Eis que vem o teu Salvador; eis que com ele vem o seu galardão, e a sua recompensa diante dele.' },
      { v: 12, en: 'They will call them The holy people, Yahweh’s redeemed. You will be called Sought out, A city not forsaken.', pt: 'E chamar-lhes-ão: Povo santo, remidos do Senhor; e tu serás chamada Procurada, cidade não desamparada.' },
    ],
    63: [
      { v: 1, en: 'Who is this who comes from Edom, with dyed garments from Bozrah? Who this who is glorious in his clothing, marching in the greatness of his strength? “It is I who speak in righteousness, mighty to save.”', pt: 'Quem é este, que vem de Edom, de Bozra, com vestiduras tintas de escarlate? este que é glorioso no seu traje, que marcha na plenitude da sua força? Sou eu, que falo em justiça, poderoso para salvar.' },
      { v: 2, en: 'Why is your clothing red, and your garments like him who treads in the wine vat?', pt: 'Por que está vermelha a tua vestidura, e as tuas vestes como as daquele que pisa no lagar?' },
      { v: 3, en: '“I have trodden the wine press alone; and of the peoples, no one was with me: Yes, I trod them in my anger, and trampled them in my wrath. Their lifeblood is sprinkled on my garments, and I have stained all my clothing.', pt: 'Eu sozinho pisei no lagar, e dos povos ninguém houve comigo; eu os pisei na minha ira, e os esmaguei no meu furor, e o seu sangue salpicou as minhas vestes, e manchei toda a minha vestidura.' },
      { v: 4, en: 'For the day of vengeance was in my heart, and the year of my redeemed has come.', pt: 'Porque o dia da vingança estava no meu coração, e o ano dos meus remidos é chegado.' },
      { v: 5, en: 'I looked, and there was no one to help; and I wondered that there was no one to uphold: therefore my own arm brought salvation to me; and my own wrath upheld me.', pt: 'Olhei, mas não havia quem me ajudasse; e admirei-me de não haver quem me sustivesse; pelo que o meu próprio braço me trouxe a vitória; e o meu furor é que me susteve.' },
      { v: 6, en: 'I trod down the peoples in my anger, and made them drunk in my wrath, and I poured out their lifeblood on the earth.”', pt: 'Pisei os povos na minha ira, e os embriaguei no meu furor; e derramei sobre a terra o seu sangue.' },
      { v: 7, en: 'I will tell of the loving kindnesses of Yahweh and the praises of Yahweh, according to all that Yahweh has given to us, and the great goodness toward the house of Israel, which he has given to them according to his mercies, and according to the multitude of his loving kindnesses.', pt: 'Celebrarei as benignidades do Senhor, e os louvores do Senhor, consoante tudo o que o Senhor nos tem concedido, e a grande bondade para com a casa de Israel, bondade que ele lhes tem concedido segundo as suas misericórdias, e segundo a multidão das suas benignidades.' },
      { v: 8, en: 'For he said, “Surely, they are my people, children who will not deal falsely;” so he became their Savior.', pt: 'Porque dizia: Certamente eles são meu povo, filhos que não procederão com falsidade; assim ele se fez o seu Salvador.' },
      { v: 9, en: 'In all their affliction he was afflicted, and the angel of his presence saved them. In his love and in his pity he redeemed them. He bore them, and carried them all the days of old.', pt: 'Em toda a angústia deles foi ele angustiado, e o anjo da sua presença os salvou; no seu amor, e na sua compaixão ele os remiu; e os tomou, e os carregou todos os dias da antigüidade.' },
      { v: 10, en: 'But they rebelled, and grieved his holy Spirit. Therefore he turned and became their enemy, and he himself fought against them.', pt: 'Eles, porém, se rebelaram, e contristaram o seu santo Espírito; pelo que se lhes tornou em inimigo, e ele mesmo pelejou contra eles.' },
      { v: 11, en: 'Then he remembered the days of old, Moses and his people, saying, “Where is he who brought them up out of the sea with the shepherds of his flock? Where is he who put his Holy Spirit among them?”', pt: 'Todavia se lembrou dos dias da antigüidade, de Moisés, e do seu povo, dizendo: Onde está aquele que os fez subir do mar com os pastores do seu rebanho? Onde está o que pôs no meio deles o seu santo Espírito?' },
      { v: 12, en: 'Who caused his glorious arm to be at Moses’ right hand? Who divided the waters before them, to make himself an everlasting name?', pt: 'Aquele que fez o seu braço glorioso andar à mão direita de Moisés? que fendeu as águas diante deles, para fazer para si um nome eterno?' },
      { v: 13, en: 'Who led them through the depths, like a horse in the wilderness, so that they didn’t stumble?', pt: 'Aquele que os guiou pelos abismos, como a um cavalo no deserto, de modo que nunca tropeçaram?' },
      { v: 14, en: 'As the livestock that go down into the valley, Yahweh’s Spirit caused them to rest. So you led your people, to make yourself a glorious name.', pt: 'Como ao gado que desce ao vale, o Espírito do Senhor lhes deu descanso; assim guiaste o teu povo, para te fazeres um nome glorioso.' },
      { v: 15, en: 'Look down from heaven, and see from the habitation of your holiness and of your glory. Where are your zeal and your mighty acts? The yearning of your heart and your compassion is restrained toward me.', pt: 'Atenta lá dos céus e vê, lá da tua santa e gloriosa habitação; onde estão o teu zelo e as tuas obras poderosas? A ternura do teu coração e as tuas misericórdias para comigo estancaram.' },
      { v: 16, en: 'For you are our Father, though Abraham doesn’t know us, and Israel does not acknowledge us. You, Yahweh, are our Father. Our Redeemer from everlasting is your name.', pt: 'Mas tu és nosso Pai, ainda que Abraão não nos conhece, e Israel não nos reconhece; tu, ó Senhor, és nosso Pai; nosso Redentor desde a antigüidade é o teu nome.' },
      { v: 17, en: 'O Yahweh, why do you make us wander from your ways, and harden our heart from your fear? Return for your servants’ sake, the tribes of your inheritance.', pt: 'Por que, ó Senhor, nos fazes errar dos teus caminhos? Por que endureces o nosso coração, para te não temermos? Faze voltar, por amor dos teus servos, as tribos da tua herança.' },
      { v: 18, en: 'Your holy people possessed it but a little while. Our adversaries have trodden down your sanctuary.', pt: 'Só por um pouco de tempo o teu santo povo a possuiu; os nossos adversários pisaram o teu santuário.' },
      { v: 19, en: 'We have become like those over whom you never ruled, like those who were not called by your name.', pt: 'Somos feitos como aqueles sobre quem tu nunca dominaste, e como os que nunca se chamaram pelo teu nome.' },
    ],
    64: [
      { v: 1, en: 'Oh that you would tear the heavens, that you would come down, that the mountains might quake at your presence.', pt: 'Oh! se fendesses os céus, e descesses, e os montes tremessem à tua presença,' },
      { v: 2, en: 'As when fire kindles the brushwood, and the fire causes the water to boil; Make your name known to your adversaries, that the nations may tremble at your presence!', pt: 'como quando o fogo pega em acendalhas, e o fogo faz ferver a água, para fazeres notório o teu nome aos teus adversários, de sorte que à tua presença tremam as nações!' },
      { v: 3, en: 'When you did awesome things which we didn’t look for, you came down, and the mountains quaked at your presence.', pt: 'Quando fazias coisas terríveis, que não esperávamos, descias, e os montes tremiam à tua presença.' },
      { v: 4, en: 'For from of old men have not heard, nor perceived by the ear, nor has the eye seen a God besides you, who works for him who waits for him.', pt: 'Porque desde a antigüidade não se ouviu, nem com ouvidos se percebeu, nem com os olhos se viu um Deus além de ti, que opera a favor daquele que por ele espera.' },
      { v: 5, en: 'You meet him who rejoices and does righteousness, those who remember you in your ways. Behold, you were angry, and we sinned. We have been in sin for a long time. Shall we be saved?', pt: 'Tu sais ao encontro daquele que, com alegria, pratica a justiça, daqueles que se lembram de ti nos teus caminhos. Eis que te iraste, porque pecamos; há muito tempo temos estado em pecados; acaso seremos salvos?' },
      { v: 6, en: 'For we have all become like one who is unclean, and all our righteousness is like a polluted garment. We all fade like a leaf; and our iniquities, like the wind, take us away.', pt: 'Pois todos nós somos como o imundo, e todas as nossas justiças como trapo da imundícia; e todos nós murchamos como a folha, e as nossas iniqüidades, como o vento, nos arrebatam.' },
      { v: 7, en: 'There is no one who calls on your name, who stirs himself up to take hold of you; for you have hidden your face from us, and have consumed us by means of our iniquities.', pt: 'E não há quem invoque o teu nome, que desperte, e te detenha; pois escondeste de nós o teu rosto e nos consumiste, por causa das nossas iniqüidades.' },
      { v: 8, en: 'But now, Yahweh, you are our Father. We are the clay, and you our potter. We all are the work of your hand.', pt: 'Mas agora, ó Senhor, tu és nosso Pai; nós somos o barro, e tu o nosso oleiro; e todos nós obra das tuas mãos.' },
      { v: 9, en: 'Don’t be furious, Yahweh, and don’t remember iniquity forever. Look and see, we beg you, we are all your people.', pt: 'Não te agastes tanto, ó Senhor, nem perpetuamente te lembres da iniqüidade; olha, pois, nós te pedimos, todos nós somos o teu povo.' },
      { v: 10, en: 'Your holy cities have become a wilderness. Zion has become a wilderness, Jerusalem a desolation.', pt: 'As tuas santas cidades se tornaram em deserto, Sião está feita um ermo, Jerusalém uma desolação.' },
      { v: 11, en: 'Our holy and our beautiful house, where our fathers praised you, is burned with fire; and all our pleasant places are laid waste.', pt: 'A nossa santa e gloriosa casa, em que te louvavam nossos pais, foi queimada a fogo; e todos os nossos lugares aprazíveis se tornaram em ruínas.' },
      { v: 12, en: 'Will you hold yourself back for these things, Yahweh? Will you keep silent, and punish us very severely?', pt: 'Acaso conter-te-ás tu ainda sobre estas calamidades, ó Senhor? ficarás calado, e nos afligirás tanto?' },
    ],
    65: [
      { v: 1, en: '“I am inquired of by those who didn’t ask. I am found by those who didn’t seek me. I said, ‘See me, see me,’ to a nation that was not called by my name.', pt: 'Tornei-me acessível aos que não perguntavam por mim; fui achado daqueles que não me buscavam. A uma nação que não se chamava do meu nome eu disse: Eis-me aqui, eis-me aqui.' },
      { v: 2, en: 'I have spread out my hands all day to a rebellious people, who walk in a way that is not good, after their own thoughts;', pt: 'Estendi as minhas mãos o dia todo a um povo rebelde, que anda por um caminho que não é bom, após os seus próprios pensamentos;' },
      { v: 3, en: 'a people who provoke me to my face continually, sacrificing in gardens, and burning incense on bricks;', pt: 'povo que de contínuo me provoca diante da minha face, sacrificando em jardins e queimando incenso sobre tijolos;' },
      { v: 4, en: 'who sit among the graves, and spend nights in secret places; who eat pig’s meat, and broth of abominable things is in their vessels;', pt: 'que se assenta entre as sepulturas, e passa as noites junto aos lugares secretos; que come carne de porco, achando-se caldo de coisas abomináveis nas suas vasilhas;' },
      { v: 5, en: 'who say, ‘Stay by yourself, don’t come near to me, for I am holier than you.’ These are smoke in my nose, a fire that burns all day.', pt: 'e que dizem: Retira-te, e não te chegues a mim, porque sou mais santo do que tu. Estes são fumaça no meu nariz, um fogo que arde o dia todo.' },
      { v: 6, en: '“Behold, it is written before me: I will not keep silence, but will repay, yes, I will repay into their bosom,', pt: 'Eis que está escrito diante de mim: Não me calarei, mas eu pagarei, sim, deitar-lhes-ei a recompensa no seu seio;' },
      { v: 7, en: 'your own iniquities, and the iniquities of your fathers together”, says Yahweh, “who have burned incense on the mountains, and blasphemed me on the hills. Therefore I will first measure their work into their bosom.”', pt: 'as suas iniqüidades, e juntamente as iniqüidades de seus pais, diz o Senhor, os quais queimaram incenso nos montes, e me afrontaram nos outeiros; pelo que lhes tornarei a medir as suas obras antigas no seu seio.' },
      { v: 8, en: 'Yahweh says, “As the new wine is found in the cluster, and one says, ‘Don’t destroy it, for a blessing is in it:’ so will I do for my servants’ sake, that I may not destroy them all.', pt: 'Assim diz o Senhor: Como quando se acha mosto num cacho de uvas, e se diz: Não o desperdices, pois há bênção nele; assim farei por amor de meus servos, para que eu não os destrua a todos.' },
      { v: 9, en: 'I will bring offspring out of Jacob, and out of Judah an inheritor of my mountains. My chosen will inherit it, and my servants will dwell there.', pt: 'E produzirei descendência a Jacó, e a Judá um herdeiro dos meus montes; e os meus escolhidos herdarão a terra e os meus servos nela habitarão.' },
      { v: 10, en: 'Sharon will be a fold of flocks, and the valley of Achor a place for herds to lie down in, for my people who have sought me.', pt: 'E Sarom servirá de pasto de rebanhos, e o vale de Acor de repouso de gado, para o meu povo, que me buscou.' },
      { v: 11, en: '“But you who forsake Yahweh, who forget my holy mountain, who prepare a table for Fortune, and who fill up mixed wine to Destiny;', pt: 'Mas a vós, os que vos apartais do Senhor, os que vos esqueceis do meu santo monte, os que preparais uma mesa para a fortuna, e que misturais vinho para o Destino' },
      { v: 12, en: 'I will destine you to the sword, and you will all bow down to the slaughter; because when I called, you didn’t answer. When I spoke, you didn’t listen; but you did that which was evil in my eyes, and chose that in which I didn’t delight.”', pt: 'também vos destinarei à espada, e todos vos encurvareis à matança; porque quando chamei, não respondestes; quando falei, não ouvistes, mas fizestes o que era mau aos meus olhos, e escolhestes aquilo em que eu não tinha prazer.' },
      { v: 13, en: 'Therefore thus says the Lord Yahweh, “Behold, my servants will eat, but you will be hungry; behold, my servants will drink, but you will be thirsty. Behold, my servants will rejoice, but you will be disappointed;', pt: 'Pelo que assim diz o Senhor Deus: Eis que os meus servos comerão, mas vós padecereis fome; eis que os meus servos beberão, mas vós tereis sede; eis que os meus servos se alegrarão, mas vós vos envergonhareis;' },
      { v: 14, en: 'Behold, my servants will sing for joy of heart, but you will cry for sorrow of heart, and will wail for anguish of spirit.', pt: 'eis que os meus servos cantarão pela alegria de coração, mas vós chorareis pela tristeza de coração, e uivareis pela angústia de espírito.' },
      { v: 15, en: 'You will leave your name for a curse to my chosen; and the Lord Yahweh will kill you. He will call his servants by another name,', pt: 'E deixareis o vosso nome para maldição aos meus escolhidos; e vos matará o Senhor Deus, mas a seus servos chamará por outro nome.' },
      { v: 16, en: 'so that he who blesses himself in the earth will bless himself in the God of truth; and he who swears in the earth will swear by the God of truth; because the former troubles are forgotten, and because they are hidden from my eyes.', pt: 'De sorte que aquele que se bendisser na terra será bendito no Deus da verdade; e aquele que jurar na terra, jurará pelo Deus da verdade; porque já estão esquecidas as angústias passadas, e estão escondidas dos meus olhos.' },
      { v: 17, en: '“For, behold, I create new heavens and a new earth; and the former things will not be remembered, nor come into mind.', pt: 'Pois eis que eu crio novos céus e nova terra; e não haverá lembrança das coisas passadas, nem mais se recordarão:' },
      { v: 18, en: 'But be glad and rejoice forever in that which I create; for, behold, I create Jerusalem to be a delight, and her people a joy.', pt: 'Mas alegrai-vos e regozijai-vos perpetuamente no que eu crio; porque crio para Jerusalém motivo de exultação e para o seu povo motivo de gozo.' },
      { v: 19, en: 'I will rejoice in Jerusalem, and delight in my people; and the voice of weeping and the voice of crying will be heard in her no more.', pt: 'E exultarei em Jerusalém, e folgarei no meu povo; e nunca mais se ouvirá nela voz de choro nem voz de clamor.' },
      { v: 20, en: '“No more will there be an infant who only lives a few days, nor an old man who has not filled his days; for the child will die one hundred years old, and the sinner being one hundred years old will be accursed.', pt: 'Não haverá mais nela criança de poucos dias, nem velho que não tenha cumprido os seus dias; porque o menino morrerá de cem anos; mas o pecador de cem anos será amaldiçoado.' },
      { v: 21, en: 'They will build houses, and inhabit them. They will plant vineyards, and eat their fruit.', pt: 'E eles edificarão casas, e as habitarão; e plantarão vinhas, e comerão o fruto delas.' },
      { v: 22, en: 'They will not build, and another inhabit. They will not plant, and another eat: for the days of my people will be like the days of a tree, and my chosen will long enjoy the work of their hands.', pt: 'Não edificarão para que outros habitem; não plantarão para que outros comam; porque os dias do meu povo serão como os dias da árvore, e os meus escolhidos gozarão por longo tempo das obras das suas mãos:' },
      { v: 23, en: 'They will not labor in vain, nor give birth for calamity; for they are the offspring of Yahweh’s blessed, and their descendants with them.', pt: 'Não trabalharão debalde, nem terão filhos para calamidade; porque serão a descendência dos benditos do Senhor, e os seus descendentes estarão com eles.' },
      { v: 24, en: 'It will happen that, before they call, I will answer; and while they are yet speaking, I will hear.', pt: 'E acontecerá que, antes de clamarem eles, eu responderei; e estando eles ainda falando, eu os ouvirei.' },
      { v: 25, en: 'The wolf and the lamb will feed together, and the lion will eat straw like the ox. Dust will be the serpent’s food. They will not hurt nor destroy in all my holy mountain,” says Yahweh.', pt: 'O lobo e o cordeiro juntos se apascentarão, o leão comerá palha como o boi; e pó será a comida da serpente. Não farão mal nem dano algum em todo o meu santo monte, diz o Senhor.' },
    ],
    66: [
      { v: 1, en: 'Yahweh says, “Heaven is my throne, and the earth is my footstool. What kind of house will you build to me? Where will I rest?', pt: 'Assim diz o Senhor: O céu é o meu trono, e a terra o escabelo dos meus pés. Que casa me edificaríeis vós? e que lugar seria o do meu descanso?' },
      { v: 2, en: 'For my hand has made all these things, and so all these things came to be,” says Yahweh: “but to this man will I look, even to he who is poor and of a contrite spirit, and who trembles at my word.', pt: 'A minha mão fez todas essas coisas, e assim todas elas vieram a existir, diz o Senhor; mas eis para quem olharei: para o humilde e contrito de espírito, que treme da minha palavra.' },
      { v: 3, en: 'He who kills an ox is as he who kills a man; he who sacrifices a lamb, as he who breaks a dog’s neck; he who offers an offering, as he who offers pig’s blood; he who burns frankincense, as he who blesses an idol. Yes, they have chosen their own ways, and their soul delights in their abominations:', pt: 'Quem mata um boi é como o que tira a vida a um homem; quem sacrifica um cordeiro, como o que quebra o pescoço a um cão; quem oferece uma oblação, como o que oferece sangue de porco; quem queima incenso, como o que bendiz a um ídolo. Porquanto eles escolheram os seus próprios caminhos, e tomam prazer nas suas abominações,' },
      { v: 4, en: 'I also will choose their delusions, and will bring their fears on them; because when I called, no one answered; when I spoke, they didn’t listen; but they did that which was evil in my eyes, and chose that in which I didn’t delight.”', pt: 'também eu escolherei as suas aflições, farei vir sobre eles aquilo que temiam; porque quando clamei, ninguém respondeu; quando falei, eles não escutaram, mas fizeram o que era mau aos meus olhos, e escolheram aquilo em que eu não tinha prazer.' },
      { v: 5, en: 'Hear Yahweh’s word, you who tremble at his word: “Your brothers who hate you, who cast you out for my name’s sake, have said, ‘Let Yahweh be glorified, that we may see your joy;’ but it is those who shall be disappointed.', pt: 'Ouvi a palavra do Senhor, os que tremeis da sua palavra: Vossos irmãos, que vos odeiam e que para longe vos lançam por causa do meu nome, disseram: Seja glorificado o Senhor, para que vejamos a vossa alegria; mas eles serão confundidos.' },
      { v: 6, en: 'A voice of tumult from the city, a voice from the temple, a voice of Yahweh that repays his enemies what they deserve.', pt: 'uma voz de grande tumulto vem da cidade, uma voz do templo, ei-la, a voz do Senhor, que dá a recompensa aos seus inimigos.' },
      { v: 7, en: '“Before she travailed, she gave birth. Before her pain came, she delivered a son.', pt: 'Antes que estivesse de parto, deu à luz; antes que lhe viessem as dores, deu à luz um filho.' },
      { v: 8, en: 'Who has heard of such a thing? Who has seen such things? Shall a land be born in one day? Shall a nation be born at once? For as soon as Zion travailed, she gave birth to her children.', pt: 'Quem jamais ouviu tal coisa? quem viu coisas semelhantes? Poder-se-ia fazer nascer uma terra num só dia? nasceria uma nação de uma só vez? Mas logo que Sião esteve de parto, deu à luz seus filhos.' },
      { v: 9, en: 'Shall I bring to the birth, and not cause to be delivered?” says Yahweh. “Shall I who cause to give birth shut the womb?” says your God.', pt: 'Acaso farei eu abrir a madre, e não farei nascer? diz o Senhor. Acaso eu que faço nascer, fecharei a madre? diz o teu Deus.' },
      { v: 10, en: '“Rejoice with Jerusalem, and be glad for her, all you who love her. Rejoice for joy with her, all you who mourn over her;', pt: 'Regozijai-vos com Jerusalém, e alegrai-vos por ela, vós todos os que a amais; enchei-vos por ela de alegria, todos os que por ela pranteastes;' },
      { v: 11, en: 'that you may nurse and be satisfied at the comforting breasts; that you may drink deeply, and be delighted with the abundance of her glory.”', pt: 'para que mameis e vos farteis dos peitos das suas consolações; para que sugueis, e vos deleiteis com a abundância da sua glória.' },
      { v: 12, en: 'For Yahweh says, “Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream; and you will nurse. You will be carried on her side, and will be dandled on her knees.', pt: 'Pois assim diz o Senhor: Eis que estenderei sobre ela a paz como um rio, e a glória das nações como um ribeiro que trasborda; então mamareis, ao colo vos trarão, e sobre os joelhos vos afagarão.' },
      { v: 13, en: 'As one whom his mother comforts, so will I comfort you. You will be comforted in Jerusalem.”', pt: 'Como alguém a quem consola sua mãe, assim eu vos consolarei; e em Jerusalém vós sereis consolados.' },
      { v: 14, en: 'You will see it, and your heart shall rejoice, and your bones will flourish like the tender grass. Yahweh’s hand will be known among his servants; and he will have indignation against his enemies.', pt: 'Isso vereis e alegrar-se-á o vosso coração, e os vossos ossos reverdecerão como a erva tenra; então a mão do Senhor será notória aos seus servos, e ele se indignará contra os seus inimigos.' },
      { v: 15, en: 'For, behold, Yahweh will come with fire, and his chariots will be like the whirlwind; to render his anger with fierceness, and his rebuke with flames of fire.', pt: 'Pois, eis que o Senhor virá com fogo, e os seus carros serão como o torvelinho, para retribuir a sua ira com furor, e a sua repreensão com chamas de fogo.' },
      { v: 16, en: 'For Yahweh will execute judgment by fire and by his sword on all flesh; and those slain by Yahweh will be many.', pt: 'Porque com fogo e com a sua espada entrará o Senhor em juízo com toda a carne; e os que forem mortos pelo Senhor serão muitos.' },
      { v: 17, en: '“Those who sanctify themselves and purify themselves to go to the gardens, behind one in the middle, eating pig’s meat, abominable things, and the mouse, they shall come to an end together,” says Yahweh.', pt: 'Os que se santificam, e se purificam para entrar nos jardins após uma deusa que está no meio, os que comem da carne de porco, e da abominação, e do rato, esses todos serão consumidos, diz o Senhor.' },
      { v: 18, en: '“For I know their works and their thoughts. The time comes that I will gather all nations and languages, and they will come, and will see my glory.', pt: 'Pois eu conheço as suas obras e os seus pensamentos; vem o dia em que ajuntarei todas as nações e línguas; e elas virão, e verão a minha glória.' },
      { v: 19, en: '“I will set a sign among them, and I will send those who escape of them to the nations, to Tarshish, Pul, and Lud, who draw the bow, to Tubal and Javan, to far-away islands, who have not heard my fame, nor have seen my glory; and they shall declare my glory among the nations.', pt: 'Porei entre elas um sinal, e os que dali escaparem, eu os enviarei às nações, a Társis, Pul, e Lude, povos que atiram com o arco, a Tubal e Javã, até as ilhas de mais longe, que não ouviram a minba fama, nem viram a minha glória; e eles anunciarão entre as nações a minha glória.' },
      { v: 20, en: 'They shall bring all your brothers out of all the nations for an offering to Yahweh, on horses, in chariots, in litters, on mules, and on camels, to my holy mountain Jerusalem, says Yahweh, as the children of Israel bring their offering in a clean vessel into Yahweh’s house.', pt: 'E trarão todos os vossos irmãos, dentre todas as nações, como oblação ao Senhor; sobre cavalos, e em carros, e em liteiras, e sobre mulas, e sobre dromedários, os trarão ao meu santo monte, a Jerusalém, diz o Senhor, como os filhos de Israel trazem as suas ofertas em vasos limpos à casa do Senhor.' },
      { v: 21, en: 'Of them I will also select priests and Levites,” says Yahweh.', pt: 'E também deles tomarei alguns para sacerdotes e para levitas, diz o Senhor.' },
      { v: 22, en: '“For as the new heavens and the new earth, which I will make, shall remain before me,” says Yahweh, “so your offspring and your name shall remain.', pt: 'Pois, como os novos céus e a nova terra, que hei de fazer, durarão diante de mim, diz o Senhor, assim durará a vossa posteridade e o vosso nome.' },
      { v: 23, en: 'It shall happen that from one new moon to another, and from one Sabbath to another, all flesh will come to worship before me,” says Yahweh.', pt: 'E acontecerá que desde uma lua nova até a outra, e desde um sábado até o outro, virá toda a carne a adorar perante mim, diz o Senhor.' },
      { v: 24, en: '“They will go out, and look at the dead bodies of the men who have transgressed against me; for their worm will not die, nor will their fire be quenched, and they will be loathsome to all mankind.”', pt: 'E sairão, e verão os cadáveres dos homens que transgrediram contra mim; porque o seu verme nunca morrerá, nem o seu fogo se apagará; e eles serão um horror para toda a carne.' },
    ],
  },
};

export default book;
